export interface Wine {
  id: string;
  name: string;
  description: string;
  targetAudience: string;
  specialFeatures: string;
  image: string; // base64 string
}

export enum AppScreen {
  LIST = 'LIST',
  CREATE = 'CREATE',
  EDIT = 'EDIT',
  GENERATE = 'GENERATE'
}

export enum ImageType {
  BODEGON = 'Bodegón',
  EN_USO = 'En uso',
  MOMENTO_SOCIAL = 'Momento social'
}

export type AspectRatio = '1:1' | '3:4' | '4:3' | '9:16' | '16:9';

export interface GenerationConfig {
  wine: Wine;
  ratio: AspectRatio;
  type: ImageType;
  context?: string;
}

import { GoogleGenAI } from "@google/genai";
import { GenerationConfig, ImageType } from "../types";

export const generateWineImage = async (config: GenerationConfig): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

  // Map our UI types to descriptive prompts for the model
  const typePrompts = {
    [ImageType.BODEGON]: "A professional studio product shot (still life / bodegón) of this wine bottle. Elegant lighting, dark sophisticated background, minimalist setting.",
    [ImageType.EN_USO]: "A lifestyle shot of this wine bottle being used. A hand pouring the wine into a glass, or the bottle open on a table with a glass half full.",
    [ImageType.MOMENTO_SOCIAL]: "A social gathering scene featuring this wine bottle. People talking in the blurred background, warm atmosphere, celebration vibes, bottle in focus."
  };

  const base64Data = config.wine.image.split(',')[1];
  const mimeType = config.wine.image.split(';')[0].split(':')[1];

  const prompt = `
    Generate a new high-quality marketing image for this specific wine.

    PRODUCT DETAILS:
    - Name: ${config.wine.name}
    - Description: ${config.wine.description}
    - Special Features: ${config.wine.specialFeatures}

    SCENE REQUIREMENTS:
    - Context: ${typePrompts[config.type]}
    ${config.context ? `- Additional User Intent: ${config.context}` : ''}

    CRITICAL INSTRUCTION: 
    Maintain the EXACT bottle shape and label design from the reference image provided. 
    The label must be clearly readable and the brand identity preserved.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          {
            inlineData: {
              data: base64Data,
              mimeType: mimeType,
            },
          },
          {
            text: prompt,
          },
        ],
      },
      config: {
        imageConfig: {
          aspectRatio: config.ratio
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }

    return null;
  } catch (error) {
    console.error("Error generating image:", error);
    throw error;
  }
};

