import React, { useState } from 'react';
import { Wine, ImageType, AspectRatio, GenerationConfig } from '../types';
import { generateWineImage } from '../services/geminiService';

interface ImageGeneratorProps {
  wine: Wine;
}

const ImageGenerator: React.FC<ImageGeneratorProps> = ({ wine }) => {
  const [ratio, setRatio] = useState<AspectRatio>('1:1');
  const [type, setType] = useState<ImageType>(ImageType.BODEGON);
  const [context, setContext] = useState('');
  const [loading, setLoading] = useState(false);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);

  const handleGenerate = async () => {
    setLoading(true);
    try {
      const config: GenerationConfig = { wine, ratio, type, context };
      const result = await generateWineImage(config);
      setGeneratedImage(result);
    } catch (error) {
      alert("Error al generar la imagen. Verifica tu conexión o API Key.");
    } finally {
      setLoading(false);
    }
  };

  const ratios: AspectRatio[] = ['1:1', '3:4', '4:3', '9:16', '16:9'];
  const types = Object.values(ImageType);

  return (
    <div className="space-y-8">
      <div className="bg-stone-50 p-4 rounded-xl flex items-center gap-4">
        <img src={wine.image} alt={wine.name} className="w-12 h-12 object-contain" />
        <div>
          <h3 className="font-bold text-stone-900">{wine.name}</h3>
          <p className="text-xs text-stone-500">Configurando imagen publicitaria</p>
        </div>
      </div>

      {!generatedImage ? (
        <div className="space-y-8">
          <div className="space-y-3">
            <label className="block text-sm font-semibold text-stone-700">Formato de imagen</label>
            <div className="grid grid-cols-3 gap-2">
              {ratios.map(r => (
                <button
                  key={r}
                  onClick={() => setRatio(r)}
                  className={`py-2 rounded-lg border text-sm font-medium transition-all ${
                    ratio === r 
                    ? 'bg-red-900 text-white border-red-900 shadow-md' 
                    : 'bg-white text-stone-600 border-stone-200 hover:border-stone-400'
                  }`}
                >
                  {r}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-3">
            <label className="block text-sm font-semibold text-stone-700">Tipo de imagen</label>
            <div className="grid grid-cols-1 gap-2">
              {types.map(t => (
                <button
                  key={t}
                  onClick={() => setType(t)}
                  className={`py-4 rounded-xl border text-left px-4 font-semibold transition-all ${
                    type === t 
                    ? 'bg-red-900 text-white border-red-900 shadow-md' 
                    : 'bg-white text-stone-600 border-stone-200 hover:border-stone-400'
                  }`}
                >
                  {t}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-2">
            <label className="block text-sm font-semibold text-stone-700">Idea o contexto (opcional)</label>
            <textarea
              value={context}
              onChange={(e) => setContext(e.target.value)}
              className="w-full px-4 py-3 rounded-lg border border-stone-200 focus:ring-2 focus:ring-red-900 outline-none bg-white transition-all"
              placeholder="Ej: Atardecer en la Toscana, mesa de madera rústica..."
            />
          </div>

          <button
            onClick={handleGenerate}
            disabled={loading}
            className={`w-full py-5 rounded-2xl font-bold text-white shadow-xl flex items-center justify-center gap-3 transition-all ${
              loading ? 'bg-stone-400' : 'bg-red-900 shadow-red-900/20 active:scale-[0.98]'
            }`}
          >
            {loading ? (
              <>
                <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                Generando arte...
              </>
            ) : (
              <>
                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m12 3-1.912 5.813a2 2 0 0 1-1.275 1.275L3 12l5.813 1.912a2 2 0 0 1 1.275 1.275L12 21l1.912-5.813a2 2 0 0 1 1.275-1.275L21 12l-5.813-1.912a2 2 0 0 1-1.275-1.275L12 3Z"/></svg>
                Generar imagen
              </>
            )}
          </button>
        </div>
      ) : (
        <div className="space-y-6">
          <div className="relative group overflow-hidden rounded-2xl border border-stone-200 shadow-2xl bg-white">
            <img src={generatedImage} alt="Generated" className="w-full h-auto" />
          </div>
          <div className="flex gap-4">
            <button
              onClick={() => setGeneratedImage(null)}
              className="flex-1 bg-stone-100 text-stone-700 py-4 rounded-xl font-bold hover:bg-stone-200 transition-all"
            >
              Nueva configuración
            </button>
            <a
              href={generatedImage}
              download={`kinglab-${wine.name}-${Date.now()}.png`}
              className="flex-1 bg-red-900 text-white py-4 rounded-xl font-bold text-center shadow-lg shadow-red-900/20 hover:bg-red-950 transition-all"
            >
              Descargar
            </a>
          </div>
        </div>
      )}
    </div>
  );
};

export default ImageGenerator;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import WineList from './components/WineList';
import WineForm from './components/WineForm';
import ImageGenerator from './components/ImageGenerator';
import { Wine, AppScreen } from './types';

const App: React.FC = () => {
  const [screen, setScreen] = useState<AppScreen>(AppScreen.LIST);
  const [wines, setWines] = useState<Wine[]>(() => {
    const saved = localStorage.getItem('kinglab_wines');
    return saved ? JSON.parse(saved) : [];
  });
  const [selectedWine, setSelectedWine] = useState<Wine | null>(null);

  useEffect(() => {
    localStorage.setItem('kinglab_wines', JSON.stringify(wines));
  }, [wines]);

  const handleSaveWine = (wine: Wine) => {
    setWines(prev => {
      const exists = prev.find(w => w.id === wine.id);
      if (exists) {
        return prev.map(w => w.id === wine.id ? wine : w);
      }
      return [wine, ...prev];
    });
    setScreen(AppScreen.LIST);
    setSelectedWine(null);
  };

  const navigateToEdit = (wine: Wine) => {
    setSelectedWine(wine);
    setScreen(AppScreen.EDIT);
  };

  const navigateToUse = (wine: Wine) => {
    setSelectedWine(wine);
    setScreen(AppScreen.GENERATE);
  };

  const getTitle = () => {
    switch (screen) {
      case AppScreen.LIST: return 'Kinglab Bodegas 202';
      case AppScreen.CREATE: return 'Dar de alta un vino';
      case AppScreen.EDIT: return 'Editar vino';
      case AppScreen.GENERATE: return 'Crear imagen';
      default: return 'Bodegas 202';
    }
  };

  const handleBack = screen !== AppScreen.LIST ? () => {
    setScreen(AppScreen.LIST);
    setSelectedWine(null);
  } : undefined;

  return (
    <Layout title={getTitle()} onBack={handleBack}>
      {screen === AppScreen.LIST && (
        <WineList 
          wines={wines} 
          onEdit={navigateToEdit} 
          onUse={navigateToUse} 
          onAdd={() => setScreen(AppScreen.CREATE)} 
        />
      )}

      {(screen === AppScreen.CREATE || screen === AppScreen.EDIT) && (
        <WineForm 
          initialWine={selectedWine || undefined} 
          onSave={handleSaveWine} 
        />
      )}

      {screen === AppScreen.GENERATE && selectedWine && (
        <ImageGenerator wine={selectedWine} />
      )}
    </Layout>
  );
};

export default App;

