import React, { useState, useRef } from 'react';
import { Wine } from '../types';

interface WineFormProps {
  initialWine?: Wine;
  onSave: (wine: Wine) => void;
}

const WineForm: React.FC<WineFormProps> = ({ initialWine, onSave }) => {
  // Using simple local state but ensuring no side effects outside this component while typing.
  // The system behavior requirement asks for "dead screen" logic.
  const [formData, setFormData] = useState<Partial<Wine>>(initialWine || {
    name: '',
    description: '',
    targetAudience: '',
    specialFeatures: '',
    image: ''
  });

  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const handleImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setFormData(prev => ({ ...prev, image: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (formData.name && formData.image) {
      onSave({
        ...formData,
        id: initialWine?.id || Date.now().toString(),
      } as Wine);
    } else {
      alert("Por favor, completa el nombre y sube una imagen.");
    }
  };

  const inputClasses = "w-full px-4 py-3 rounded-lg border border-stone-200 focus:ring-2 focus:ring-black focus:border-transparent outline-none bg-white text-black placeholder-stone-500 transition-all";

  return (
    <form onSubmit={handleSubmit} className="space-y-6">
      <div className="space-y-2">
        <label className="block text-sm font-semibold text-stone-700">Nombre del vino</label>
        <input
          type="text"
          name="name"
          value={formData.name}
          onChange={handleChange}
          className={inputClasses}
          placeholder="Ej: Reserva de la Familia"
        />
      </div>

      <div className="space-y-2">
        <label className="block text-sm font-semibold text-stone-700">Descripción del vino</label>
        <textarea
          name="description"
          rows={3}
          value={formData.description}
          onChange={handleChange}
          className={inputClasses}
          placeholder="Describe el cuerpo, aroma y notas..."
        />
      </div>

      <div className="space-y-2">
        <label className="block text-sm font-semibold text-stone-700">¿Para quién es este vino?</label>
        <textarea
          name="targetAudience"
          rows={2}
          value={formData.targetAudience}
          onChange={handleChange}
          className={inputClasses}
          placeholder="Público objetivo..."
        />
      </div>

      <div className="space-y-2">
        <label className="block text-sm font-semibold text-stone-700">¿Qué lo hace especial?</label>
        <textarea
          name="specialFeatures"
          rows={2}
          value={formData.specialFeatures}
          onChange={handleChange}
          className={inputClasses}
          placeholder="Detalles únicos, premios, origen..."
        />
      </div>

      <div className="space-y-2">
        <label className="block text-sm font-semibold text-stone-700">Imagen del producto</label>
        <div className="flex flex-col items-center gap-4">
          {formData.image && (
            <img 
              src={formData.image} 
              alt="Preview" 
              className="w-full h-48 object-contain rounded-lg border border-stone-200 bg-stone-50" 
            />
          )}
          <input
            type="file"
            accept="image/*"
            ref={fileInputRef}
            onChange={handleImageChange}
            className="hidden"
          />
          <button
            type="button"
            onClick={() => fileInputRef.current?.click()}
            className="w-full py-4 border-2 border-dashed border-stone-300 rounded-lg text-stone-500 hover:border-black hover:text-black transition-all flex items-center justify-center gap-2"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 12v7a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V5a2 2 0 0 1 2-2h7"/><line x1="16" x2="22" y1="5" y2="5"/><line x1="19" x2="19" y1="2" y2="8"/><circle cx="9" cy="9" r="2"/><path d="m21 15-3.086-3.086a2 2 0 0 0-2.828 0L6 21"/></svg>
            {formData.image ? "Cambiar imagen" : "Subir imagen"}
          </button>
        </div>
      </div>

      <button
        type="submit"
        className="w-full bg-black text-white py-4 rounded-xl font-bold shadow-lg shadow-black/20 active:scale-[0.98] transition-all"
      >
        Guardar vino
      </button>
    </form>
  );
};

export default WineForm;

