import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import WineList from './components/WineList';
import WineForm from './components/WineForm';
import ImageGenerator from './components/ImageGenerator';
import { Wine, AppScreen } from './types';

const App: React.FC = () => {
  const [screen, setScreen] = useState<AppScreen>(AppScreen.HOME);
  const [wines, setWines] = useState<Wine[]>(() => {
    const saved = localStorage.getItem('kinglab_wines_v2');
    return saved ? JSON.parse(saved) : [];
  });
  const [selectedWineForEdit, setSelectedWineForEdit] = useState<Wine | null>(null);

  useEffect(() => {
    localStorage.setItem('kinglab_wines_v2', JSON.stringify(wines));
  }, [wines]);

  const handleSaveWine = (wine: Wine) => {
    setWines(prev => {
      const exists = prev.find(w => w.id === wine.id);
      if (exists) {
        return prev.map(w => w.id === wine.id ? wine : w);
      }
      return [wine, ...prev];
    });
    // After saving, go back to management if that's where we came from, or home if it's the first one.
    setScreen(wines.length === 0 ? AppScreen.HOME : AppScreen.MANAGE);
    setSelectedWineForEdit(null);
  };

  const navigateToEdit = (wine: Wine) => {
    setSelectedWineForEdit(wine);
    setScreen(AppScreen.FORM);
  };

  const getTitle = () => {
    switch (screen) {
      case AppScreen.HOME: return 'Kinglab Bodegas 202';
      case AppScreen.MANAGE: return 'Gestionar Vinos';
      case AppScreen.FORM: return selectedWineForEdit ? 'Editar vino' : 'Dar de alta un vino';
      default: return 'Kinglab';
    }
  };

  const handleBack = () => {
    if (screen === AppScreen.FORM) {
      setScreen(wines.length === 0 ? AppScreen.HOME : AppScreen.MANAGE);
    } else if (screen === AppScreen.MANAGE) {
      setScreen(AppScreen.HOME);
    }
    setSelectedWineForEdit(null);
  };

  const showGear = wines.length > 0 && screen === AppScreen.HOME;

  return (
    <Layout 
      title={getTitle()} 
      onBack={screen !== AppScreen.HOME ? handleBack : undefined}
      onGear={() => setScreen(AppScreen.MANAGE)}
      showGear={showGear}
    >
      {screen === AppScreen.HOME && (
        wines.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full space-y-8 py-20 animate-in fade-in duration-700">
            <div className="text-center space-y-2">
              <h2 className="text-3xl font-serif font-bold text-stone-900">Bienvenidos</h2>
              <p className="text-stone-500 max-w-xs mx-auto">Comienza registrando tu primer vino para generar imágenes publicitarias.</p>
            </div>
            <button
              onClick={() => setScreen(AppScreen.FORM)}
              className="bg-black text-white px-10 py-5 rounded-full font-bold shadow-2xl shadow-black/20 flex items-center gap-2 active:scale-95 transition-all"
            >
              👉 “Dar de alta un vino”
            </button>
          </div>
        ) : (
          <ImageGenerator wines={wines} />
        )
      )}

      {screen === AppScreen.MANAGE && (
        <WineList 
          wines={wines} 
          onEdit={navigateToEdit} 
          onAdd={() => {
            setSelectedWineForEdit(null);
            setScreen(AppScreen.FORM);
          }} 
        />
      )}

      {screen === AppScreen.FORM && (
        <WineForm 
          initialWine={selectedWineForEdit || undefined} 
          onSave={handleSaveWine} 
        />
      )}
    </Layout>
  );
};

export default App;

export interface Wine {
  id: string;
  name: string;
  description: string;
  image: string; // base64 string
  targetAudience: string;
  priceLevel: string;
  specialFeatures: string[];
}

export enum AppScreen {
  HOME = 'HOME',
  MANAGE = 'MANAGE',
  FORM = 'FORM',
  FUNNEL = 'FUNNEL'
}

export enum ImageType {
  BODEGON = 'Bodegón',
  EN_USO = 'En uso',
  MOMENTO_SOCIAL = 'Momento social'
}

export type AspectRatio = '1:1' | '4:5' | '9:16' | '16:9';

export interface FunnelState {
  type: ImageType | null;
  step: number;
  selections: Record<string, any>;
  contextText: string;
  concepts: string[];
  selectedConceptIndex: number | null;
}

import { GoogleGenAI, Type } from "@google/genai";
import { Wine, ImageType, FunnelState } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const generateVisualConcepts = async (wine: Wine, state: FunnelState): Promise<string[]> => {
  const prompt = `
    Eres un Director Creativo experto en fotografía de vinos para Kinglab Bodegas 202.
    Analiza la siguiente información y genera 3 conceptos visuales distintos, creativos y profesionales en ESPAÑOL.

    PRODUCTO:
    - Nombre: ${wine.name}
    - Perfil: ${wine.description}
    - Público: ${wine.targetAudience}
    - Nivel: ${wine.priceLevel}
    - Especial: ${wine.specialFeatures.join(', ')}

    TIPO DE IMAGEN: ${state.type}
    DETALLES ELEGIDOS: ${JSON.stringify(state.selections)}
    CONTEXTO ADICIONAL: ${state.contextText || 'Ninguno'}

    REGLAS:
    - Los conceptos deben ser cortos (un párrafo de 30-40 palabras cada uno).
    - Lenguaje editorial, elegante y descriptivo.
    - Cada concepto debe ser único en su enfoque visual.
    - Idioma: Español.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            concepts: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Tres párrafos descriptivos de conceptos visuales."
            }
          },
          required: ["concepts"]
        }
      }
    });

    const data = JSON.parse(response.text);
    return data.concepts;
  } catch (error) {
    console.error("Error generating concepts:", error);
    return [
      "Una toma elegante resaltando la etiqueta con luz lateral suave.",
      "Un ambiente cálido y sofisticado que invita a la degustación.",
      "Composición minimalista centrada en la silueta de la botella."
    ];
  }
};

export const generateFinalImage = async (wine: Wine, concept: string, ratio: string): Promise<string | null> => {
  const base64Data = wine.image.split(',')[1];
  const mimeType = wine.image.split(';')[0].split(':')[1];

  const prompt = `
    Genera una imagen publicitaria de alta calidad basada ESTRICTAMENTE en este concepto creativo:
    "${concept}"

    DETALLES TÉCNICOS:
    - Producto: ${wine.name}
    - Objetivo: Mantener la forma exacta de la botella y la legibilidad de la etiqueta de la imagen de referencia.
    - Estilo: Fotografía publicitaria profesional de alta gama.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType } },
          { text: prompt }
        ]
      },
      config: {
        imageConfig: {
          aspectRatio: ratio as any
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Error generating final image:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { Wine, ImageType, FunnelState, AspectRatio } from '../types';
import { generateVisualConcepts, generateFinalImage } from '../services/geminiService';

interface CreativeFunnelProps {
  wines: Wine[];
  onFinish: () => void;
}

const CreativeFunnel: React.FC<CreativeFunnelProps> = ({ wines, onFinish }) => {
  const [selectedWine, setSelectedWine] = useState<Wine>(wines[0]);
  const [state, setState] = useState<FunnelState>({
    type: null,
    step: 1,
    selections: {},
    contextText: '',
    concepts: [],
    selectedConceptIndex: null
  });
  const [ratio, setRatio] = useState<AspectRatio>('1:1');
  const [loading, setLoading] = useState(false);
  const [finalImage, setFinalImage] = useState<string | null>(null);

  const setType = (type: ImageType) => {
    setState(prev => ({ ...prev, type, step: 2, selections: {} }));
  };

  const handleSelection = (key: string, value: string) => {
    setState(prev => ({
      ...prev,
      selections: { ...prev.selections, [key]: value }
    }));
  };

  const nextStep = () => {
    setState(prev => ({ ...prev, step: prev.step + 1 }));
  };

  const startConceptGeneration = async () => {
    setLoading(true);
    const concepts = await generateVisualConcepts(selectedWine, state);
    setState(prev => ({ ...prev, concepts, step: 4 }));
    setLoading(false);
  };

  const selectAndGenerate = async (index: number) => {
    setState(prev => ({ ...prev, selectedConceptIndex: index }));
    setLoading(true);
    try {
      const img = await generateFinalImage(selectedWine, state.concepts[index], ratio);
      setFinalImage(img);
      setState(prev => ({ ...prev, step: 5 }));
    } catch (e) {
      alert("Error al generar la imagen final.");
    } finally {
      setLoading(false);
    }
  };

  const renderStep1 = () => (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4">
      <div className="space-y-2">
        <label className="block text-sm font-semibold text-stone-700">Seleccionar vino</label>
        <select 
          className="w-full px-4 py-3 rounded-lg border border-stone-200 bg-white text-black outline-none"
          value={selectedWine.id}
          onChange={(e) => setSelectedWine(wines.find(w => w.id === e.target.value)!)}
        >
          {wines.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
        </select>
      </div>
      <h2 className="text-xl font-bold text-black font-serif">¿Qué tipo de imagen quieres crear?</h2>
      <div className="grid gap-3">
        {Object.values(ImageType).map(t => (
          <button 
            key={t}
            onClick={() => setType(t)}
            className="w-full py-5 rounded-xl border border-stone-200 bg-white text-black font-semibold text-left px-6 hover:border-black transition-all shadow-sm"
          >
            {t}
          </button>
        ))}
      </div>
    </div>
  );

  const renderStep2 = () => {
    const questions: Record<ImageType, any[]> = {
      [ImageType.BODEGON]: [
        { label: "Tipo de superficie", key: "superficie", options: ["Madera", "Piedra", "Mármol", "Minimalista"] },
