                >
                  {opt}
                </button>
              ))}
            </div>
          </div>
        ))}
        <button 
          onClick={nextStep}
          className="w-full py-4 bg-black text-white rounded-xl font-bold mt-4"
        >
          Continuar
        </button>
      </div>
    );
  };

  const renderStep3 = () => (
    <div className="space-y-8 animate-in fade-in slide-in-from-right-4">
      <h2 className="text-xl font-bold text-black font-serif">Contexto y Atmósfera</h2>
      <div className="space-y-6">
        <div className="space-y-3">
          <label className="text-sm font-semibold text-stone-600">Formato</label>
          <div className="grid grid-cols-4 gap-2">
            {['1:1', '4:5', '9:16', '16:9'].map(r => (
              <button 
                key={r} 
                onClick={() => setRatio(r as AspectRatio)}
                className={`py-2 rounded-lg border text-xs font-bold ${ratio === r ? 'bg-black text-white border-black' : 'bg-white text-stone-600 border-stone-200'}`}
              >
                {r}
              </button>
            ))}
