                  disabled={loading}
                  onClick={() => selectAndGenerate(idx)}
                  className="bg-black text-white px-6 py-2 rounded-full text-xs font-bold flex items-center gap-2"
                >
                  {loading && state.selectedConceptIndex === idx ? <div className="w-3 h-3 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : 'Elegir concepto'}
                </button>
              </div>
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  const renderStep5 = () => (
    <div className="space-y-8 animate-in zoom-in-95">
      {finalImage && (
        <>
          <div className="rounded-2xl overflow-hidden border border-stone-200 shadow-2xl bg-white">
            <img src={finalImage} alt="Resultado final" className="w-full h-auto" />
          </div>
          <div className="bg-stone-50 p-4 rounded-xl border border-stone-100 italic text-sm text-stone-600">
            "{state.concepts[state.selectedConceptIndex!]}"
          </div>
          <div className="flex gap-4">
            <button onClick={onFinish} className="flex-1 py-4 bg-stone-100 text-stone-700 font-bold rounded-xl">Nueva imagen</button>
            <a href={finalImage} download="kinglab.png" className="flex-1 py-4 bg-black text-white text-center font-bold rounded-xl">Descargar</a>
          </div>
          <div className="space-y-4 pt-4 border-t border-stone-100">
            <p className="text-sm font-bold text-stone-800">¿Qué cambiarías de esta imagen?</p>
            <div className="flex flex-wrap gap-2">
              {["Más luz lateral", "Etiqueta más brillante", "Fondo más oscuro"].map(s => (
                <button key={s} className="px-3 py-2 rounded-full border border-stone-200 text-xs text-stone-600 hover:border-black">{s}</button>
              ))}
            </div>
          </div>
        </>
      )}
    </div>
  );

  return (
    <div className="max-w-xl mx-auto">
      {state.step === 1 && renderStep1()}
      {state.step === 2 && renderStep2()}
      {state.step === 3 && renderStep3()}
      {state.step === 4 && renderStep4()}
      {state.step === 5 && renderStep5()}
    </div>
  );
};

