import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import WineList from './components/WineList';
import WineForm from './components/WineForm';
import CreativeFunnel from './components/CreativeFunnel';
import { Wine, AppScreen } from './types';

const App: React.FC = () => {
  const [screen, setScreen] = useState<AppScreen>(AppScreen.HOME);
  const [wines, setWines] = useState<Wine[]>(() => {
    const saved = localStorage.getItem('kinglab_wines_v2');
    return saved ? JSON.parse(saved) : [];
  });
  const [selectedWineForEdit, setSelectedWineForEdit] = useState<Wine | null>(null);

  useEffect(() => {
    localStorage.setItem('kinglab_wines_v2', JSON.stringify(wines));
  }, [wines]);

  const handleSaveWine = (wine: Wine) => {
    setWines(prev => {
      const exists = prev.find(w => w.id === wine.id);
      if (exists) {
        return prev.map(w => w.id === wine.id ? wine : w);
      }
      return [wine, ...prev];
    });
    setScreen(AppScreen.HOME);
    setSelectedWineForEdit(null);
  };

  const navigateToEdit = (wine: Wine) => {
    setSelectedWineForEdit(wine);
    setScreen(AppScreen.FORM);
  };

  const getTitle = () => {
    switch (screen) {
      case AppScreen.HOME: return 'Kinglab Bodegas 202';
      case AppScreen.MANAGE: return 'Gestionar Vinos';
      case AppScreen.FORM: return selectedWineForEdit ? 'Editar vino' : 'Dar de alta un vino';
      case AppScreen.FUNNEL: return 'Director Creativo';
      default: return 'Kinglab';
    }
  };

  const handleBack = () => {
    if (screen === AppScreen.FORM) {
      setScreen(wines.length === 0 ? AppScreen.HOME : AppScreen.MANAGE);
    } else if (screen === AppScreen.MANAGE || screen === AppScreen.FUNNEL) {
      setScreen(AppScreen.HOME);
    }
    setSelectedWineForEdit(null);
  };

  const showGear = wines.length > 0 && screen === AppScreen.HOME;

  return (
    <Layout 
      title={getTitle()} 
      onBack={screen !== AppScreen.HOME ? handleBack : undefined}
      onGear={() => setScreen(AppScreen.MANAGE)}
      showGear={showGear}
    >
      {screen === AppScreen.HOME && (
        wines.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full space-y-8 py-20 animate-in fade-in duration-700">
            <div className="text-center space-y-2">
              <h2 className="text-3xl font-serif font-bold text-stone-900">Bienvenidos</h2>
              <p className="text-stone-500 max-w-xs mx-auto">Comienza registrando tu primer vino para generar imágenes publicitarias.</p>
            </div>
            <button
              onClick={() => setScreen(AppScreen.FORM)}
              className="bg-black text-white px-10 py-5 rounded-full font-bold shadow-2xl shadow-black/20 flex items-center gap-2 active:scale-95 transition-all"
            >
              👉 “Dar de alta un vino”
            </button>
          </div>
        ) : (
          <div className="space-y-12">
            <div className="bg-stone-50 p-8 rounded-3xl border border-stone-100 text-center space-y-4">
              <h3 className="text-xl font-serif font-bold text-black">Asistente de Dirección Creativa</h3>
              <p className="text-sm text-stone-500">Diseñamos el concepto visual antes de capturar la imagen perfecta.</p>
              <button 
                onClick={() => setScreen(AppScreen.FUNNEL)}
                className="bg-black text-white px-8 py-4 rounded-xl font-bold shadow-xl shadow-black/10 hover:scale-105 transition-transform"
              >
                Comenzar proceso creativo
              </button>
            </div>
            {/* Quick list preview could go here if needed, but home is for the funnel start now */}
          </div>
        )
      )}

      {screen === AppScreen.FUNNEL && wines.length > 0 && (
        <CreativeFunnel wines={wines} onFinish={() => setScreen(AppScreen.HOME)} />
      )}

      {screen === AppScreen.MANAGE && (
        <WineList 
          wines={wines} 
          onEdit={navigateToEdit} 
          onAdd={() => {
            setSelectedWineForEdit(null);
            setScreen(AppScreen.FORM);
          }} 
        />
      )}

      {screen === AppScreen.FORM && (
        <WineForm 
          initialWine={selectedWineForEdit || undefined} 
          onSave={handleSaveWine} 
        />
      )}
    </Layout>
  );
};

export default App;

