  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            concepts: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Tres párrafos descriptivos de conceptos visuales."
            }
          },
          required: ["concepts"]
        }
      }
    });

    const data = JSON.parse(response.text);
    return data.concepts;
  } catch (error) {
    console.error("Error generating concepts:", error);
    return [
      "Una toma elegante resaltando la etiqueta con luz lateral suave.",
      "Un ambiente cálido y sofisticado que invita a la degustación.",
      "Composición minimalista centrada en la silueta de la botella."
    ];
  }
};

export const generateFinalImage = async (
  wine: Wine, 
  concept: string, 
  ratio: string, 
  adjustment?: string
): Promise<string | null> => {
  const base64Data = wine.image.split(',')[1];
  const mimeType = wine.image.split(';')[0].split(':')[1];

  let prompt = `
    Genera una imagen publicitaria de alta calidad basada ESTRICTAMENTE en este concepto creativo:
    "${concept}"

    DETALLES TÉCNICOS:
    - Producto: ${wine.name}
    - Objetivo: Mantener la forma exacta de la botella y la legibilidad de la etiqueta de la imagen de referencia.
    - Estilo: Fotografía publicitaria profesional de alta gama.
  `;

  if (adjustment) {
    prompt += `\n\nAPLICA ESTE AJUSTE ESPECÍFICO: "${adjustment}" manteniendo el resto de la composición.`;
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType } },
          { text: prompt }
        ]
      },
      config: {
        imageConfig: {
          aspectRatio: ratio as any
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Error generating final image:", error);
    throw error;
  }
};

import React, { useState } from 'react';
import { Wine, ImageType, FunnelState, AspectRatio } from '../types';
import { generateVisualConcepts, generateFinalImage } from '../services/geminiService';

interface CreativeFunnelProps {
  wines: Wine[];
  onFinish: () => void;
}

const CreativeFunnel: React.FC<CreativeFunnelProps> = ({ wines, onFinish }) => {
  const [selectedWine, setSelectedWine] = useState<Wine>(wines[0]);
  const [state, setState] = useState<FunnelState>({
    type: null,
    step: 1,
    selections: {},
    contextText: '',
    concepts: [],
    selectedConceptIndex: null,
    editingConceptIndex: null,
    imageHistory: []
  });
  const [ratio, setRatio] = useState<AspectRatio>('1:1');
  const [loading, setLoading] = useState(false);
  const [editValue, setEditValue] = useState('');
  const [customAdjustment, setCustomAdjustment] = useState('');

  const setType = (type: ImageType) => {
    setState(prev => ({ ...prev, type, step: 2, selections: {} }));
  };

  const handleSelection = (key: string, value: string) => {
    setState(prev => ({
      ...prev,
      selections: { ...prev.selections, [key]: value }
    }));
  };

  const nextStep = () => setState(prev => ({ ...prev, step: prev.step + 1 }));
  const prevStep = () => setState(prev => ({ ...prev, step: Math.max(1, prev.step - 1) }));

  const startConceptGeneration = async () => {
    setLoading(true);
    const concepts = await generateVisualConcepts(selectedWine, state);
    setState(prev => ({ ...prev, concepts, step: 4 }));
    setLoading(false);
  };

  const selectAndGenerate = async (index: number, adjustment?: string) => {
    setState(prev => ({ ...prev, selectedConceptIndex: index }));
    setLoading(true);
    try {
      const img = await generateFinalImage(selectedWine, state.concepts[index], ratio, adjustment);
      if (img) {
        setState(prev => ({ 
          ...prev, 
          imageHistory: [img, ...prev.imageHistory],
          step: 5 
        }));
      }
    } catch (e) {
      alert("Error al generar la imagen final.");
    } finally {
      setLoading(false);
    }
  };

  const handleSaveEdit = () => {
    if (state.editingConceptIndex !== null) {
      const newConcepts = [...state.concepts];
      newConcepts[state.editingConceptIndex] = editValue;
      setState(prev => ({ ...prev, concepts: newConcepts, editingConceptIndex: null }));
    }
  };

  const handleAdjustment = (adj: string) => {
    if (state.selectedConceptIndex !== null) {
      selectAndGenerate(state.selectedConceptIndex, adj);
    }
  };

  const renderStep1 = () => (
    <div className="space-y-6 animate-in fade-in slide-in-from-bottom-4">
      <div className="space-y-2">
        <label className="block text-sm font-semibold text-stone-700">Seleccionar vino</label>
        <select 
          className="w-full px-4 py-3 rounded-lg border border-stone-200 bg-white text-black outline-none"
          value={selectedWine.id}
          onChange={(e) => setSelectedWine(wines.find(w => w.id === e.target.value)!)}
        >
          {wines.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
        </select>
      </div>
      <h2 className="text-xl font-bold text-black font-serif">¿Qué tipo de imagen quieres crear?</h2>
      <div className="grid gap-3">
        {Object.values(ImageType).map(t => (
          <button 
            key={t}
            onClick={() => setType(t)}
            className="w-full py-5 rounded-xl border border-stone-200 bg-white text-black font-semibold text-left px-6 hover:border-black transition-all shadow-sm"
          >
            {t}
          </button>
        ))}
      </div>
    </div>
  );

  const renderStep2 = () => {
    const questions: Record<ImageType, any[]> = {
      [ImageType.BODEGON]: [
        { label: "Tipo de superficie", key: "superficie", options: ["Madera", "Piedra", "Mármol", "Minimalista"] },
        { label: "Nivel de limpieza visual", key: "limpieza", options: ["Muy minimal", "Con elementos"] },
        { label: "Elementos de apoyo", key: "apoyo", options: ["Ninguno", "Copas", "Uvas", "Corchos"] },
        { label: "Fondo", key: "fondo", options: ["Neutro", "Con contexto"] }
      ],
      [ImageType.EN_USO]: [
        { label: "Sujeción", key: "mano", options: ["Mano sola", "Persona parcial"] },
        { label: "Acción", key: "accion", options: ["Servir", "Sostener", "Brindar"] },
        { label: "Cercanía al producto", key: "cercania", options: ["Primer plano", "Plano medio"] },
        { label: "Protagonismo humano", key: "protagonismo", options: ["Bajo", "Moderado"] }
      ],
      [ImageType.MOMENTO_SOCIAL]: [
        { label: "Número de personas", key: "personas", options: ["2 personas", "3 personas", "Grupo"] },
        { label: "Tipo de situación", key: "situacion", options: ["Íntima", "Celebración", "Informal"] },
        { label: "Nivel de ruido visual", key: "ruido", options: ["Limpio", "Dinámico"] },
        { label: "Foco principal", key: "foco", options: ["El vino", "La escena"] }
      ]
    };

    const currentQuestions = questions[state.type!];

    return (
      <div className="space-y-8 animate-in fade-in slide-in-from-right-4">
        <div className="flex items-center gap-2">
            <button onClick={prevStep} className="text-stone-400 hover:text-black">
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
            </button>
            <h2 className="text-xl font-bold text-black font-serif">Detalles de {state.type}</h2>
        </div>
        {currentQuestions.map(q => (
          <div key={q.key} className="space-y-3">
            <label className="text-sm font-semibold text-stone-600">{q.label}</label>
            <div className="grid grid-cols-2 gap-2">
              {q.options.map((opt: string) => (
                <button
                  key={opt}
                  onClick={() => handleSelection(q.key, opt)}
                  className={`py-3 rounded-lg border text-sm font-medium transition-all ${
                    state.selections[q.key] === opt ? 'bg-black text-white border-black' : 'bg-white text-stone-600 border-stone-200'
                  }`}
                >
                  {opt}
                </button>
              ))}
            </div>
          </div>
        ))}
        <button 
          onClick={nextStep}
          className="w-full py-4 bg-black text-white rounded-xl font-bold mt-4 shadow-lg active:scale-95 transition-all"
        >
          Continuar
        </button>
      </div>
    );
  };

  const renderStep3 = () => (
    <div className="space-y-8 animate-in fade-in slide-in-from-right-4">
      <div className="flex items-center gap-2">
            <button onClick={prevStep} className="text-stone-400 hover:text-black">
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
            </button>
            <h2 className="text-xl font-bold text-black font-serif">Contexto y Atmósfera</h2>
      </div>
      <div className="space-y-6">
        <div className="space-y-3">
          <label className="text-sm font-semibold text-stone-600">Formato</label>
          <div className="grid grid-cols-4 gap-2">
            {['1:1', '4:5', '9:16', '16:9'].map(r => (
              <button 
                key={r} 
                onClick={() => setRatio(r as AspectRatio)}
                className={`py-2 rounded-lg border text-xs font-bold ${ratio === r ? 'bg-black text-white border-black' : 'bg-white text-stone-600 border-stone-200'}`}
              >
                {r}
              </button>
            ))}
          </div>
        </div>
        <div className="space-y-3">
          <label className="text-sm font-semibold text-stone-600">¿Dónde ocurre?</label>
          <div className="grid grid-cols-2 gap-2">
            {["Exterior", "Bodega", "Restaurante", "Casa"].map(opt => (
              <button key={opt} onClick={() => handleSelection('donde', opt)} className={`py-3 rounded-lg border text-sm ${state.selections['donde'] === opt ? 'bg-black text-white border-black' : 'bg-white border-stone-200'}`}>{opt}</button>
            ))}
          </div>
        </div>
        <div className="space-y-2">
          <label className="text-sm font-semibold text-stone-600">Matices o detalles adicionales</label>
          <textarea 
            value={state.contextText}
            onChange={(e) => setState(prev => ({ ...prev, contextText: e.target.value }))}
            className="w-full px-4 py-3 rounded-lg border border-stone-200 bg-white text-black placeholder-stone-400 outline-none h-24"
            placeholder="Ej: Luz de atardecer filtrada por una ventana..."
          />
        </div>
      </div>
      <button 
        disabled={loading}
        onClick={startConceptGeneration}
        className="w-full py-5 bg-black text-white rounded-xl font-bold flex items-center justify-center gap-2 shadow-xl shadow-black/10 active:scale-95 transition-all"
      >
        {loading && <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />}
        Definir conceptos visuales
      </button>
    </div>
  );

  const renderStep4 = () => (
    <div className="space-y-8 animate-in fade-in scale-95 duration-500">
      <div className="flex items-center gap-2">
            <button onClick={prevStep} className="text-stone-400 hover:text-black">
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m15 18-6-6 6-6"/></svg>
            </button>
            <h2 className="text-2xl font-serif font-bold text-black">Propuestas Creativas</h2>
      </div>
      <p className="text-stone-500 text-sm text-center">Selecciona el concepto que mejor encaja con tu visión.</p>

      <div className="space-y-4">
        {state.concepts.map((concept, idx) => (
          <div key={idx} className="relative group">
            <div className={`bg-white border p-6 rounded-2xl shadow-sm transition-all ${state.editingConceptIndex === idx ? 'border-black ring-1 ring-black' : 'border-stone-200 hover:border-black'}`}>
              {state.editingConceptIndex === idx ? (
                <div className="space-y-3">
                  <textarea 
                    autoFocus
                    value={editValue}
                    onChange={(e) => setEditValue(e.target.value)}
                    className="w-full px-3 py-2 border border-stone-200 rounded-lg text-sm bg-stone-50 text-black outline-none focus:ring-1 focus:ring-black h-32"
                  />
                  <div className="flex gap-2 justify-end">
                    <button onClick={() => setState(prev => ({ ...prev, editingConceptIndex: null }))} className="text-xs font-bold text-stone-400 px-3 py-1">Cancelar</button>
                    <button onClick={handleSaveEdit} className="bg-black text-white text-xs font-bold px-4 py-1.5 rounded-lg">Guardar cambios</button>
                  </div>
                </div>
              ) : (
                <>
                  <p className="text-stone-800 text-sm leading-relaxed italic">"{concept}"</p>
                  <div className="mt-4 flex justify-between items-center">
                    <button 
                      onClick={() => {
                        setEditValue(concept);
                        setState(prev => ({ ...prev, editingConceptIndex: idx }));
                      }}
                      className="p-2 hover:bg-stone-100 rounded-lg transition-colors text-stone-400 hover:text-black flex items-center gap-1 text-xs"
                    >
                      <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.85 2.83 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5Z"/><path d="m15 5 4 4"/></svg>
                      Editar concepto
                    </button>
                    <button 
                      disabled={loading || state.editingConceptIndex !== null}
                      onClick={() => selectAndGenerate(idx)}
                      className="bg-black text-white px-6 py-2 rounded-full text-xs font-bold flex items-center gap-2 shadow-sm active:scale-95 transition-all"
                    >
                      {loading && state.selectedConceptIndex === idx ? <div className="w-3 h-3 border-2 border-white/30 border-t-white rounded-full animate-spin" /> : 'Elegir concepto'}
                    </button>
                  </div>
                </>
              )}
            </div>
          </div>
        ))}
      </div>
    </div>
  );

  const renderStep5 = () => (
    <div className="space-y-8 animate-in zoom-in-95">
      {state.imageHistory.length > 0 && (
        <>
          <div className="relative group">
            <div className="rounded-2xl overflow-hidden border border-stone-200 shadow-2xl bg-white">
                <img src={state.imageHistory[0]} alt="Resultado final" className="w-full h-auto" />
            </div>
            {state.imageHistory.length > 1 && (
                <div className="absolute bottom-4 left-1/2 -translate-x-1/2 bg-black/60 backdrop-blur px-3 py-1 rounded-full text-[10px] text-white">
                    Historial: {state.imageHistory.length} versiones
