            <p>"{state.concepts[state.selectedConceptIndex!]}"</p>
          </div>

          <div className="grid grid-cols-3 gap-3">
             <button 
                disabled={loading}
                onClick={() => selectAndGenerate(state.selectedConceptIndex!)} 
                className="flex flex-col items-center justify-center gap-1 py-3 bg-stone-100 text-stone-700 font-bold rounded-xl text-xs hover:bg-stone-200"
            >
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 12a9 9 0 0 0-9-9 9.75 9.75 0 0 0-6.74 2.74L3 8"/><path d="M3 3v5h5"/><path d="M3 12a9 9 0 0 0 9 9 9.75 9.75 0 0 0 6.74-2.74L21 16"/><path d="M16 16h5v5"/></svg>
                Regenerar
            </button>
            <button 
                onClick={prevStep}
                className="flex flex-col items-center justify-center gap-1 py-3 bg-stone-100 text-stone-700 font-bold rounded-xl text-xs hover:bg-stone-200"
            >
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m12 19-7-7 7-7"/><path d="M19 12H5"/></svg>
                Conceptos
            </button>
            <a 
                href={state.imageHistory[0]} 
                download="kinglab.png" 
                className="flex flex-col items-center justify-center gap-1 py-3 bg-black text-white font-bold rounded-xl text-xs"
            >
                <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" x2="12" y1="15" y2="3"/></svg>
                Descargar
            </a>
          </div>

          <div className="space-y-4 pt-4 border-t border-stone-100">
            <p className="text-sm font-bold text-stone-800">Ajustar esta imagen</p>
            <div className="flex flex-wrap gap-2">
              {["Más luz lateral", "Etiqueta más brillante", "Fondo más oscuro", "Aclarar colores"].map(s => (
                <button 
                    key={s} 
                    disabled={loading}
                    onClick={() => handleAdjustment(s)}
                    className="px-3 py-2 rounded-full border border-stone-200 text-xs text-stone-600 hover:border-black active:scale-95 transition-all bg-white"
                >
                    {s}
                </button>
              ))}
            </div>
            <div className="flex gap-2">
                <input 
                    type="text" 
                    value={customAdjustment}
                    onChange={(e) => setCustomAdjustment(e.target.value)}
                    placeholder="Otro ajuste..."
                    className="flex-1 px-3 py-2 border border-stone-200 rounded-lg text-xs bg-white text-black outline-none focus:ring-1 focus:ring-black"
                />
                <button 
                    disabled={loading || !customAdjustment.trim()}
                    onClick={() => {
                        handleAdjustment(customAdjustment);
                        setCustomAdjustment('');
                    }}
                    className="bg-black text-white px-4 py-2 rounded-lg text-xs font-bold"
                >
                    Aplicar
                </button>
            </div>
          </div>

          {loading && (
            <div className="flex items-center justify-center gap-3 py-4 bg-stone-50 rounded-xl animate-pulse">
                <div className="w-4 h-4 border-2 border-stone-300 border-t-black rounded-full animate-spin" />
                <span className="text-xs font-bold text-stone-600">Procesando ajuste...</span>
            </div>
          )}
        </>
      )}
    </div>
  );

  return (
    <div className="max-w-xl mx-auto pb-12">
      {state.step === 1 && renderStep1()}
      {state.step === 2 && renderStep2()}
      {state.step === 3 && renderStep3()}
      {state.step === 4 && renderStep4()}
      {state.step === 5 && renderStep5()}
    </div>
  );
};

