import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import WineList from './components/WineList';
import WineForm from './components/WineForm';
import CreativeFunnel from './components/CreativeFunnel';
import Gallery from './components/Gallery';
import { Wine, AppScreen, GalleryImage } from './types';

const App: React.FC = () => {
  const [screen, setScreen] = useState<AppScreen>(AppScreen.HOME);
  const [wines, setWines] = useState<Wine[]>(() => {
    const saved = localStorage.getItem('kinglab_wines_v2');
    return saved ? JSON.parse(saved) : [];
  });
  const [gallery, setGallery] = useState<GalleryImage[]>(() => {
    const saved = localStorage.getItem('kinglab_gallery_v3');
    return saved ? JSON.parse(saved) : [];
  });
  const [selectedWineForEdit, setSelectedWineForEdit] = useState<Wine | null>(null);
  const [funnelConfig, setFunnelConfig] = useState<{
    wine: Wine;
    concept: string;
    isAdjustment?: boolean;
  } | undefined>(undefined);

  useEffect(() => { localStorage.setItem('kinglab_wines_v2', JSON.stringify(wines)); }, [wines]);
  useEffect(() => { localStorage.setItem('kinglab_gallery_v3', JSON.stringify(gallery)); }, [gallery]);

  const handleSaveWine = (wine: Wine) => {
    setWines(prev => {
      const exists = prev.find(w => w.id === wine.id);
      if (exists) return prev.map(w => w.id === wine.id ? wine : w);
      return [wine, ...prev];
    });
    setScreen(AppScreen.HOME);
    setSelectedWineForEdit(null);
  };

  const handleRegenerateFromGallery = (img: GalleryImage) => {
    const wine = wines.find(w => w.name === img.wineName);
    if (wine) {
      setFunnelConfig({ wine, concept: img.concept, isAdjustment: false });
      setScreen(AppScreen.FUNNEL);
    }
  };

  const handleAdjustFromGallery = (img: GalleryImage) => {
    const wine = wines.find(w => w.name === img.wineName);
    if (wine) {
      setFunnelConfig({ wine, concept: img.concept, isAdjustment: true });
      setScreen(AppScreen.FUNNEL);
    }
  };

  const getTitle = () => {
    switch (screen) {
      case AppScreen.HOME: return 'Kinglab Bodegas 202';
      case AppScreen.MANAGE: return 'Archivo de Vinos';
      case AppScreen.FORM: return selectedWineForEdit ? 'Editar Vino' : 'Registrar Vino';
      case AppScreen.FUNNEL: return 'Dirección Creativa';
      case AppScreen.GALLERY: return 'Galería de Arte';
      default: return 'Kinglab';
    }
  };

  const handleBack = () => {
    if (screen === AppScreen.FORM) setScreen(wines.length === 0 ? AppScreen.HOME : AppScreen.MANAGE);
    else setScreen(AppScreen.HOME);
    setSelectedWineForEdit(null);
    setFunnelConfig(undefined);
  };

  return (
    <Layout 
      title={getTitle()} 
      onBack={screen !== AppScreen.HOME ? handleBack : undefined}
      onGear={() => setScreen(AppScreen.MANAGE)}
      onGallery={() => setScreen(AppScreen.GALLERY)}
      showGear={wines.length > 0}
      showGallery={gallery.length > 0}
    >
      {screen === AppScreen.HOME && (
        wines.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full space-y-10 py-24 animate-in fade-in duration-700">
            <div className="text-center space-y-3 px-8">
              <h2 className="text-5xl font-serif font-bold text-black">Kinglab</h2>
              <p className="text-stone-400 font-medium max-w-sm mx-auto leading-relaxed italic text-lg">Dirección de arte profesional para la industria del vino.</p>
            </div>
            <button onClick={() => setScreen(AppScreen.FORM)} className="bg-black text-white px-12 py-6 rounded-full font-bold shadow-2xl shadow-black/20 flex items-center gap-4 active:scale-90 transition-all text-xl">
              <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M12 5v14M5 12h14"/></svg>
              Dar de alta un vino
            </button>
          </div>
        ) : (
          <div className="space-y-12 py-10">
            <div className="bg-white p-12 rounded-[2.5rem] border-2 border-stone-100 text-center space-y-8 shadow-sm">
              <div className="w-20 h-20 bg-stone-50 rounded-full flex items-center justify-center mx-auto text-black border border-stone-100 shadow-inner">
                <svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2v20"/><path d="M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/></svg>
              </div>
              <div className="space-y-3">
                <h3 className="text-3xl font-serif font-bold text-black">Mesa de Trabajo</h3>
                <p className="text-stone-400 font-medium text-lg leading-snug">Inicia una nueva sesión de dirección creativa para tus productos.</p>
              </div>
              <button onClick={() => { setFunnelConfig(undefined); setScreen(AppScreen.FUNNEL); }} className="w-full bg-black text-white px-8 py-6 rounded-3xl font-bold shadow-2xl shadow-black/10 active:scale-95 transition-all text-xl">
                Comenzar proceso
              </button>
            </div>

            {gallery.length > 0 && (
              <div className="space-y-6">
                <div className="flex justify-between items-end px-4">
                  <h4 className="font-serif font-bold text-2xl text-black">Recientes</h4>
                  <button onClick={() => setScreen(AppScreen.GALLERY)} className="text-black font-black text-[10px] uppercase tracking-widest border-b-2 border-black pb-1 active:opacity-50">Explorar todo</button>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  {gallery.slice(0, 4).map(img => (
                    <div key={img.id} onClick={() => setScreen(AppScreen.GALLERY)} className="aspect-square rounded-3xl overflow-hidden border border-stone-100 shadow-sm cursor-pointer active:scale-95 transition-all">
                      <img src={img.url} alt={img.wineName} className="w-full h-full object-cover" />
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )
      )}

      {screen === AppScreen.FUNNEL && wines.length > 0 && (
        <CreativeFunnel wines={wines} onFinish={() => setScreen(AppScreen.HOME)} onSaveToGallery={(img) => setGallery(prev => [img, ...prev])} initialData={funnelConfig} />
      )}

      {screen === AppScreen.GALLERY && (
        <Gallery images={gallery} onBack={() => setScreen(AppScreen.HOME)} onRegenerate={handleRegenerateFromGallery} onAdjust={handleAdjustFromGallery} />
      )}

      {screen === AppScreen.MANAGE && (
        <WineList wines={wines} onEdit={(w) => { setSelectedWineForEdit(w); setScreen(AppScreen.FORM); }} onAdd={() => { setSelectedWineForEdit(null); setScreen(AppScreen.FORM); }} />
      )}

      {screen === AppScreen.FORM && (
        <WineForm initialWine={selectedWineForEdit || undefined} onSave={handleSaveWine} />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Wine, ImageType, FunnelState, AspectRatio, GalleryImage } from '../types';
import { generateVisualConcepts, generateFinalImage } from '../services/geminiService';

interface CreativeFunnelProps {
  wines: Wine[];
  onFinish: () => void;
  onSaveToGallery: (img: GalleryImage) => void;
  initialData?: {
    wine: Wine;
    concept: string;
    isAdjustment?: boolean;
  };
}

const CreativeFunnel: React.FC<CreativeFunnelProps> = ({ wines, onFinish, onSaveToGallery, initialData }) => {
  const [selectedWine, setSelectedWine] = useState<Wine>(initialData?.wine || wines[0]);
  const [state, setState] = useState<FunnelState>({
    type: null,
    step: initialData ? 5 : 1,
    selections: {},
    contextText: '',
    concepts: initialData ? [initialData.concept] : [],
    selectedConceptIndex: initialData ? 0 : null,
    editingConceptIndex: null,
    imageHistory: [] // Discard previous on entry
  });
  const [ratio, setRatio] = useState<AspectRatio>('1:1');
  const [loading, setLoading] = useState(false);
  const [editValue, setEditValue] = useState('');
  const [customAdjustment, setCustomAdjustment] = useState('');

  useEffect(() => {
    if (initialData && state.step === 5 && state.imageHistory.length === 0) {
      if (!initialData.isAdjustment) {
        selectAndGenerate(0);
      }
    }
  }, []);

  const setType = (type: ImageType) => setState(prev => ({ ...prev, type, step: 2, selections: {} }));
  const handleSelection = (key: string, value: string) => setState(prev => ({ ...prev, selections: { ...prev.selections, [key]: value } }));
  const nextStep = () => setState(prev => ({ ...prev, step: prev.step + 1 }));
  const prevStep = () => setState(prev => ({ ...prev, step: prev.step === 5 ? 4 : Math.max(1, prev.step - 1) }));

  const startConceptGeneration = async () => {
    setLoading(true);
    // STATE RESET: Clear previous results when generating new concepts
    setState(prev => ({ ...prev, concepts: [], selectedConceptIndex: null, imageHistory: [] }));
    const concepts = await generateVisualConcepts(selectedWine, state);
    setState(prev => ({ ...prev, concepts, step: 4 }));
    setLoading(false);
  };

  const selectAndGenerate = async (index: number, adjustment?: string) => {
    // STATE RESET: Discard previous results for a new generation attempt
    setState(prev => ({ ...prev, selectedConceptIndex: index, imageHistory: [] }));
    setLoading(true);
    try {
      const img = await generateFinalImage(selectedWine, state.concepts[index], ratio, adjustment);
      if (img) {
        const galleryItem: GalleryImage = {
          id: Date.now().toString(),
          url: img,
          concept: state.concepts[index],
          wineName: selectedWine.name,
          timestamp: Date.now()
        };
        onSaveToGallery(galleryItem);
        setState(prev => ({ ...prev, imageHistory: [img], step: 5 }));
      }
    } catch (e) {
      alert("Error al generar la imagen final.");
    } finally {
      setLoading(false);
    }
  };

  // Fix: Added handleAdjustment to resolve 'Cannot find name handleAdjustment' errors
  const handleAdjustment = (adjustment: string) => {
    if (state.selectedConceptIndex !== null) {
      selectAndGenerate(state.selectedConceptIndex, adjustment);
    }
  };

  const handleSaveEdit = () => {
    if (state.editingConceptIndex !== null) {
      const newConcepts = [...state.concepts];
      newConcepts[state.editingConceptIndex] = editValue;
      setState(prev => ({ ...prev, concepts: newConcepts, editingConceptIndex: null }));
    }
  };

  const handleDownload = (imgUrl: string) => {
    const conceptSlug = state.concepts[state.selectedConceptIndex || 0].substring(0, 20).toLowerCase().replace(/[^a-z0-9]/g, '_');
    const wineSlug = selectedWine.name.toLowerCase().replace(/[^a-z0-9]/g, '_');
    const filename = `${wineSlug}_${conceptSlug}_${Date.now()}.png`;

    const link = document.createElement('a');
    link.href = imgUrl;
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const btnSecondary = "py-4 rounded-xl border border-stone-300 bg-white text-stone-900 font-bold hover:border-black active:bg-stone-50 transition-all text-center px-4";
  const btnPrimary = "w-full py-5 bg-black text-white rounded-2xl font-bold shadow-xl shadow-black/10 active:scale-95 transition-all text-lg flex items-center justify-center gap-3";

  const renderStep1 = () => (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4">
      <div className="space-y-3">
        <label className="text-sm font-bold text-stone-800 uppercase tracking-wide">Seleccionar vino</label>
        <select 
          className="w-full px-4 py-4 rounded-xl border-2 border-stone-100 bg-white text-black outline-none font-bold text-lg"
          value={selectedWine.id}
          onChange={(e) => setSelectedWine(wines.find(w => w.id === e.target.value)!)}
        >
          {wines.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
        </select>
      </div>
      <div className="space-y-4">
        <h2 className="text-2xl font-bold text-black font-serif">¿Qué tipo de imagen quieres crear?</h2>
        <div className="grid gap-3">
          {Object.values(ImageType).map(t => (
            <button key={t} onClick={() => setType(t)} className="w-full py-6 rounded-2xl border-2 border-stone-100 bg-white text-stone-900 font-bold text-left px-8 hover:border-black transition-all shadow-sm active:bg-stone-50 flex justify-between items-center group">
              {t}
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className="opacity-0 group-hover:opacity-100 transition-opacity"><path d="m9 18 6-6-6-6"/></svg>
            </button>
          ))}
        </div>
      </div>
    </div>
  );

  const renderStep2 = () => {
    const questions: Record<ImageType, any[]> = {
      [ImageType.BODEGON]: [
        { label: "Tipo de superficie", key: "superficie", options: ["Madera", "Piedra", "Mármol", "Minimalista"] },
        { label: "Nivel de limpieza", key: "limpieza", options: ["Muy minimal", "Con elementos"] },
        { label: "Apoyo", key: "apoyo", options: ["Ninguno", "Copas", "Uvas", "Corchos"] },
        { label: "Fondo", key: "fondo", options: ["Neutro", "Con contexto"] }
      ],
      [ImageType.EN_USO]: [
        { label: "Sujeción", key: "mano", options: ["Mano sola", "Persona parcial"] },
        { label: "Acción", key: "accion", options: ["Servir", "Sostener", "Brindar"] },
        { label: "Cercanía", key: "cercania", options: ["Primer plano", "Plano medio"] },
        { label: "Humano", key: "protagonismo", options: ["Bajo", "Moderado"] }
      ],
      [ImageType.MOMENTO_SOCIAL]: [
        { label: "Personas", key: "personas", options: ["2 personas", "3 personas", "Grupo"] },
        { label: "Situación", key: "situacion", options: ["Íntima", "Celebración", "Informal"] },
        { label: "Ruido", key: "ruido", options: ["Limpio", "Dinámico"] },
        { label: "Foco", key: "foco", options: ["El vino", "La escena"] }
      ]
    };
    return (
      <div className="space-y-8 animate-in fade-in slide-in-from-right-4">
        <h2 className="text-2xl font-bold text-black font-serif">Detalles de {state.type}</h2>
        <div className="space-y-6">
          {questions[state.type!].map(q => (
            <div key={q.key} className="space-y-3">
              <label className="text-xs font-black text-stone-400 uppercase tracking-widest">{q.label}</label>
              <div className="grid grid-cols-2 gap-3">
                {q.options.map((opt: string) => (
                  <button key={opt} onClick={() => handleSelection(q.key, opt)} className={`py-4 rounded-xl border-2 font-bold transition-all ${state.selections[q.key] === opt ? 'bg-black text-white border-black' : 'bg-white text-stone-900 border-stone-100 hover:border-stone-300'}`}>
                    {opt}
                  </button>
                ))}
              </div>
            </div>
          ))}
        </div>
        <button onClick={nextStep} className={btnPrimary}>Continuar</button>
      </div>
    );
  };

  const renderStep3 = () => (
    <div className="space-y-8 animate-in fade-in slide-in-from-right-4">
      <h2 className="text-2xl font-bold text-black font-serif">Atmósfera</h2>
      <div className="space-y-6">
        <div className="space-y-3">
          <label className="text-xs font-black text-stone-400 uppercase tracking-widest">Formato</label>
          <div className="grid grid-cols-4 gap-2">
            {['1:1', '4:5', '9:16', '16:9'].map(r => (
              <button key={r} onClick={() => setRatio(r as AspectRatio)} className={`py-4 rounded-xl border-2 font-black text-xs ${ratio === r ? 'bg-black text-white border-black' : 'bg-white text-stone-900 border-stone-100'}`}>{r}</button>
            ))}
          </div>
        </div>
        <div className="space-y-3">
          <label className="text-xs font-black text-stone-400 uppercase tracking-widest">¿Dónde ocurre?</label>
          <div className="grid grid-cols-2 gap-3">
            {["Exterior", "Bodega", "Restaurante", "Casa"].map(opt => (
              <button key={opt} onClick={() => handleSelection('donde', opt)} className={`py-4 rounded-xl border-2 font-bold ${state.selections['donde'] === opt ? 'bg-black text-white border-black' : 'bg-white text-stone-900 border-stone-100'}`}>{opt}</button>
            ))}
          </div>
        </div>
        <div className="space-y-3">
          <label className="text-xs font-black text-stone-400 uppercase tracking-widest">Detalles adicionales</label>
          <textarea value={state.contextText} onChange={(e) => setState(prev => ({ ...prev, contextText: e.target.value }))} className="w-full px-5 py-4 rounded-2xl border-2 border-stone-100 bg-white text-black placeholder-stone-300 outline-none h-32 font-medium focus:border-stone-300 transition-all" placeholder="Ej: Luz de tarde filtrada..." />
        </div>
      </div>
      <button disabled={loading} onClick={startConceptGeneration} className={btnPrimary}>
        {loading && <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />}
        Crear propuestas
      </button>
    </div>
  );

  const renderStep4 = () => (
    <div className="space-y-8 animate-in fade-in scale-95 duration-500">
      <h2 className="text-2xl font-serif font-bold text-black text-center">Propuestas Creativas</h2>
      <div className="space-y-4">
        {state.concepts.map((concept, idx) => (
          <div key={idx} className={`bg-white border-2 p-6 rounded-3xl shadow-sm transition-all ${state.editingConceptIndex === idx ? 'border-black ring-2 ring-black/5' : 'border-stone-100 hover:border-black'}`}>
            {state.editingConceptIndex === idx ? (
              <div className="space-y-4">
                <textarea autoFocus value={editValue} onChange={(e) => setEditValue(e.target.value)} className="w-full px-4 py-3 border-2 border-stone-100 rounded-xl text-stone-900 bg-stone-50 outline-none h-32 font-medium" />
                <div className="flex gap-2 justify-end">
                  <button onClick={() => setState(prev => ({ ...prev, editingConceptIndex: null }))} className="px-5 py-2 text-sm font-bold text-stone-500">Cancelar</button>
                  <button onClick={handleSaveEdit} className="bg-black text-white px-6 py-2 rounded-xl text-sm font-bold shadow-lg">Guardar</button>
                </div>
              </div>
            ) : (
              <div className="space-y-4">
                <p className="text-stone-900 font-medium italic text-lg leading-relaxed">"{concept}"</p>
                <div className="flex justify-between items-center pt-2">
                  <button onClick={() => { setEditValue(concept); setState(prev => ({ ...prev, editingConceptIndex: idx })); }} className="flex items-center gap-2 text-stone-400 hover:text-black transition-colors font-bold text-xs uppercase tracking-widest">
                    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.85 2.83 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5Z"/><path d="m15 5 4 4"/></svg>
                    Editar
                  </button>
                  <button disabled={loading} onClick={() => selectAndGenerate(idx)} className="bg-black text-white px-8 py-3 rounded-xl font-bold active:scale-95 transition-all text-sm shadow-xl shadow-black/5">Elegir concepto</button>
                </div>
              </div>
            )}
          </div>
        ))}
        <button disabled={loading} onClick={startConceptGeneration} className="w-full py-5 border-2 border-dashed border-stone-300 text-stone-500 rounded-3xl font-bold flex items-center justify-center gap-2 hover:border-black hover:text-black transition-all mt-4">
          <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M2 12s3-7 10-7 10 7 10 7-3 7-10 7-10-7-10-7Z"/><circle cx="12" cy="12" r="3"/></svg>
          Proponer otros conceptos
        </button>
      </div>
    </div>
  );

  const renderStep5 = () => (
    <div className="space-y-8 animate-in zoom-in-95">
      {loading ? (
        <div className="flex flex-col items-center justify-center py-20 space-y-6">
          <div className="w-16 h-16 border-4 border-stone-100 border-t-black rounded-full animate-spin" />
          <div className="text-center">
            <h3 className="text-xl font-bold text-black font-serif">Capturando la escena...</h3>
            <p className="text-stone-400 font-medium">Esto tomará unos segundos.</p>
          </div>
        </div>
      ) : state.imageHistory[0] && (
        <div className="space-y-8 animate-in fade-in duration-1000">
          <div className="rounded-3xl overflow-hidden border border-stone-100 shadow-2xl bg-white aspect-square">
            <img src={state.imageHistory[0]} alt="Final" className="w-full h-full object-cover" />
          </div>
          <div className="bg-stone-50 p-6 rounded-2xl border border-stone-100 italic text-stone-700 font-medium text-center">
            "{state.concepts[state.selectedConceptIndex!]}"
          </div>
          <div className="grid grid-cols-3 gap-3">
            <button onClick={() => selectAndGenerate(state.selectedConceptIndex!)} className={btnSecondary} title="Regenerar">
               <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="mx-auto"><path d="M21 12a9 9 0 0 0-9-9 9.75 9.75 0 0 0-6.74 2.74L3 8"/><path d="M3 3v5h5"/><path d="M3 12a9 9 0 0 0 9 9 9.75 9.75 0 0 0 6.74-2.74L21 16"/><path d="M16 16h5v5"/></svg>
               <span className="block mt-1 text-[10px] uppercase">Regenerar</span>
            </button>
            <button onClick={() => setState(p => ({ ...p, step: 4 }))} className={btnSecondary} title="Volver a conceptos">
               <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="mx-auto"><path d="m12 19-7-7 7-7"/><path d="M19 12H5"/></svg>
               <span className="block mt-1 text-[10px] uppercase">Conceptos</span>
            </button>
            <button onClick={() => handleDownload(state.imageHistory[0])} className="py-4 rounded-xl bg-black text-white font-bold active:scale-95 transition-all text-center px-4" title="Descargar">
               <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="mx-auto"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" x2="12" y1="15" y2="3"/></svg>
               <span className="block mt-1 text-[10px] uppercase">Descargar</span>
            </button>
          </div>
          <div className="pt-6 border-t border-stone-100 space-y-4">
            <h4 className="text-sm font-black text-stone-900 uppercase tracking-widest">Ajustar esta imagen</h4>
            <div className="flex flex-wrap gap-2">
              {["Más luz lateral", "Etiqueta más brillante", "Fondo más oscuro", "Aclarar colores"].map(s => (
                <button key={s} onClick={() => handleAdjustment(s)} className="px-4 py-2 rounded-full border border-stone-300 text-xs font-bold text-stone-900 hover:border-black transition-all bg-white">{s}</button>
              ))}
            </div>
            <div className="flex gap-2">
              <input type="text" value={customAdjustment} onChange={(e) => setCustomAdjustment(e.target.value)} placeholder="Otro ajuste..." className="flex-1 px-4 py-3 border border-stone-200 rounded-xl text-sm outline-none focus:border-stone-400" />
              <button disabled={!customAdjustment.trim()} onClick={() => { handleAdjustment(customAdjustment); setCustomAdjustment(''); }} className="bg-black text-white px-6 py-3 rounded-xl text-sm font-bold active:scale-95 transition-all">Aplicar</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );

  return (
    <div className="max-w-xl mx-auto pb-20">
      {state.step === 1 && renderStep1()}
      {state.step === 2 && renderStep2()}
      {state.step === 3 && renderStep3()}
      {state.step === 4 && renderStep4()}
      {state.step === 5 && renderStep5()}
    </div>
  );
};

export default CreativeFunnel;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import WineList from './components/WineList';
import WineForm from './components/WineForm';
import CreativeFunnel from './components/CreativeFunnel';
import Gallery from './components/Gallery';
import { Wine, AppScreen, GalleryImage } from './types';

const App: React.FC = () => {
  const [screen, setScreen] = useState<AppScreen>(AppScreen.HOME);
  const [funnelKey, setFunnelKey] = useState(0);
  const [wines, setWines] = useState<Wine[]>(() => {
    const saved = localStorage.getItem('kinglab_wines_v2');
    return saved ? JSON.parse(saved) : [];
  });
  const [gallery, setGallery] = useState<GalleryImage[]>(() => {
    const saved = localStorage.getItem('kinglab_gallery_v3');
    return saved ? JSON.parse(saved) : [];
  });
  const [selectedWineForEdit, setSelectedWineForEdit] = useState<Wine | null>(null);
  const [funnelConfig, setFunnelConfig] = useState<{
    wine: Wine;
    concept: string;
    isAdjustment?: boolean;
  } | undefined>(undefined);

  useEffect(() => { localStorage.setItem('kinglab_wines_v2', JSON.stringify(wines)); }, [wines]);
  useEffect(() => { localStorage.setItem('kinglab_gallery_v3', JSON.stringify(gallery)); }, [gallery]);

  const handleSaveWine = (wine: Wine) => {
    setWines(prev => {
      const exists = prev.find(w => w.id === wine.id);
      if (exists) return prev.map(w => w.id === wine.id ? wine : w);
      return [wine, ...prev];
    });
    setScreen(AppScreen.HOME);
    setSelectedWineForEdit(null);
  };

  const handleRegenerateFromGallery = (img: GalleryImage) => {
    const wine = wines.find(w => w.name === img.wineName);
    if (wine) {
      setFunnelConfig({ wine, concept: img.concept, isAdjustment: false });
      setFunnelKey(prev => prev + 1);
      setScreen(AppScreen.FUNNEL);
    }
  };

  const handleAdjustFromGallery = (img: GalleryImage) => {
    const wine = wines.find(w => w.name === img.wineName);
    if (wine) {
      setFunnelConfig({ wine, concept: img.concept, isAdjustment: true });
      setFunnelKey(prev => prev + 1);
      setScreen(AppScreen.FUNNEL);
    }
  };

  const startNewFunnel = () => {
    setFunnelConfig(undefined);
    setFunnelKey(prev => prev + 1);
    setScreen(AppScreen.FUNNEL);
  };

  const getTitle = () => {
    switch (screen) {
      case AppScreen.HOME: return 'Kinglab Bodegas 202';
      case AppScreen.MANAGE: return 'Archivo de Vinos';
      case AppScreen.FORM: return selectedWineForEdit ? 'Editar Vino' : 'Registrar Vino';
      case AppScreen.FUNNEL: return 'Dirección Creativa';
      case AppScreen.GALLERY: return 'Galería de Arte';
      default: return 'Kinglab';
    }
  };

  const handleBack = () => {
    if (screen === AppScreen.FORM) setScreen(wines.length === 0 ? AppScreen.HOME : AppScreen.MANAGE);
    else setScreen(AppScreen.HOME);
    setSelectedWineForEdit(null);
    setFunnelConfig(undefined);
  };

  return (
    <Layout 
      title={getTitle()} 
      onBack={screen !== AppScreen.HOME ? handleBack : undefined}
      onGear={() => setScreen(AppScreen.MANAGE)}
      onGallery={() => setScreen(AppScreen.GALLERY)}
      showGear={wines.length > 0}
      showGallery={gallery.length > 0}
    >
      {screen === AppScreen.HOME && (
        wines.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full space-y-10 py-24 animate-in fade-in duration-700">
            <div className="text-center space-y-3 px-8">
              <h2 className="text-5xl font-serif font-bold text-black">Kinglab</h2>
              <p className="text-stone-400 font-medium max-w-sm mx-auto leading-relaxed italic text-lg">Dirección de arte profesional para la industria del vino.</p>
            </div>
            <button onClick={() => setScreen(AppScreen.FORM)} className="bg-black text-white px-12 py-6 rounded-full font-bold shadow-2xl shadow-black/20 flex items-center gap-4 active:scale-90 transition-all text-xl">
              <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M12 5v14M5 12h14"/></svg>
              Dar de alta un vino
            </button>
          </div>
        ) : (
          <div className="space-y-12 py-10">
            <div className="bg-white p-12 rounded-[2.5rem] border-2 border-stone-100 text-center space-y-8 shadow-sm">
              <div className="w-20 h-20 bg-stone-50 rounded-full flex items-center justify-center mx-auto text-black border border-stone-100 shadow-inner">
                <svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2v20"/><path d="M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/></svg>
              </div>
              <div className="space-y-3">
                <h3 className="text-3xl font-serif font-bold text-black">Mesa de Trabajo</h3>
                <p className="text-stone-400 font-medium text-lg leading-snug">Inicia una nueva sesión de dirección creativa para tus productos.</p>
              </div>
              <button onClick={startNewFunnel} className="w-full bg-black text-white px-8 py-6 rounded-3xl font-bold shadow-2xl shadow-black/10 active:scale-95 transition-all text-xl">
                Comenzar proceso
              </button>
            </div>

            {gallery.length > 0 && (
              <div className="space-y-6">
                <div className="flex justify-between items-end px-4">
                  <h4 className="font-serif font-bold text-2xl text-black">Recientes</h4>
                  <button onClick={() => setScreen(AppScreen.GALLERY)} className="text-black font-black text-[10px] uppercase tracking-widest border-b-2 border-black pb-1 active:opacity-50">Explorar todo</button>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  {gallery.slice(0, 4).map(img => (
                    <div key={img.id} onClick={() => setScreen(AppScreen.GALLERY)} className="aspect-square rounded-3xl overflow-hidden border border-stone-100 shadow-sm cursor-pointer active:scale-95 transition-all">
                      <img src={img.url} alt={img.wineName} className="w-full h-full object-cover" />
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )
      )}

      {screen === AppScreen.FUNNEL && wines.length > 0 && (
        <CreativeFunnel 
          key={funnelKey}
          wines={wines} 
          onFinish={() => setScreen(AppScreen.HOME)} 
          onSaveToGallery={(img) => setGallery(prev => [img, ...prev])} 
          initialData={funnelConfig} 
        />
      )}

      {screen === AppScreen.GALLERY && (
        <Gallery images={gallery} onBack={() => setScreen(AppScreen.HOME)} onRegenerate={handleRegenerateFromGallery} onAdjust={handleAdjustFromGallery} />
      )}

      {screen === AppScreen.MANAGE && (
        <WineList wines={wines} onEdit={(w) => { setSelectedWineForEdit(w); setScreen(AppScreen.FORM); }} onAdd={() => { setSelectedWineForEdit(null); setScreen(AppScreen.FORM); }} />
      )}

      {screen === AppScreen.FORM && (
        <WineForm initialWine={selectedWineForEdit || undefined} onSave={handleSaveWine} />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Wine, ImageType, FunnelState, AspectRatio, GalleryImage } from '../types';
import { generateVisualConcepts, generateFinalImage } from '../services/geminiService';

interface CreativeFunnelProps {
  wines: Wine[];
  onFinish: () => void;
  onSaveToGallery: (img: GalleryImage) => void;
  initialData?: {
    wine: Wine;
    concept: string;
    isAdjustment?: boolean;
  };
}

const CreativeFunnel: React.FC<CreativeFunnelProps> = ({ wines, onFinish, onSaveToGallery, initialData }) => {
  const [selectedWine, setSelectedWine] = useState<Wine>(initialData?.wine || wines[0]);
  const [state, setState] = useState<FunnelState>({
    type: null,
    step: initialData ? 5 : 1,
    selections: {},
    contextText: '',
    concepts: initialData ? [initialData.concept] : [],
    selectedConceptIndex: initialData ? 0 : null,
    editingConceptIndex: null,
    imageHistory: []
  });
  const [ratio, setRatio] = useState<AspectRatio>('1:1');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [editValue, setEditValue] = useState('');
  const [customAdjustment, setCustomAdjustment] = useState('');

  useEffect(() => {
    if (initialData && state.step === 5 && state.imageHistory.length === 0) {
      if (!initialData.isAdjustment) {
        selectAndGenerate(0);
      }
    }
  }, []);

  const setType = (type: ImageType) => setState(prev => ({ ...prev, type, step: 2, selections: {} }));
  const handleSelection = (key: string, value: string) => setState(prev => ({ ...prev, selections: { ...prev.selections, [key]: value } }));
  const nextStep = () => setState(prev => ({ ...prev, step: prev.step + 1 }));
  const prevStep = () => setState(prev => ({ ...prev, step: prev.step === 5 ? 4 : Math.max(1, prev.step - 1) }));

  const startConceptGeneration = async () => {
    setLoading(true);
    setError(null);
    // STATE RESET: Clear concepts and history before new request
    setState(prev => ({ ...prev, concepts: [], selectedConceptIndex: null, imageHistory: [] }));

    try {
      const concepts = await generateVisualConcepts(selectedWine, state);
      setState(prev => ({ ...prev, concepts, step: 4 }));
    } catch (e) {
      setError("No se pudieron generar conceptos creativos.");
    } finally {
      setLoading(false);
    }
  };

  const selectAndGenerate = async (index: number, adjustment?: string) => {
    // STATE RESET: Discard results and set step 5 before request
    setLoading(true);
    setError(null);
    setState(prev => ({ ...prev, selectedConceptIndex: index, imageHistory: [], step: 5 }));

    try {
      const img = await generateFinalImage(selectedWine, state.concepts[index], ratio, adjustment);
      if (img) {
        const galleryItem: GalleryImage = {
          id: Date.now().toString(),
          url: img,
          concept: state.concepts[index],
          wineName: selectedWine.name,
          timestamp: Date.now()
        };
        onSaveToGallery(galleryItem);
        setState(prev => ({ ...prev, imageHistory: [img] }));
      } else {
        setError("La generación no devolvió ninguna imagen.");
      }
    } catch (e) {
      setError("Error crítico durante la generación de la imagen.");
    } finally {
      setLoading(false);
    }
  };

  const handleAdjustment = (adjustment: string) => {
    if (state.selectedConceptIndex !== null) {
      selectAndGenerate(state.selectedConceptIndex, adjustment);
    }
  };

  const handleSaveEdit = () => {
    if (state.editingConceptIndex !== null) {
      const newConcepts = [...state.concepts];
      newConcepts[state.editingConceptIndex] = editValue;
      setState(prev => ({ ...prev, concepts: newConcepts, editingConceptIndex: null }));
    }
  };

  const handleDownload = (imgUrl: string) => {
    const conceptSlug = state.concepts[state.selectedConceptIndex || 0].substring(0, 20).toLowerCase().replace(/[^a-z0-9]/g, '_');
    const wineSlug = selectedWine.name.toLowerCase().replace(/[^a-z0-9]/g, '_');
    const filename = `${wineSlug}_${conceptSlug}_${Date.now()}.png`;

    const link = document.createElement('a');
    link.href = imgUrl;
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const btnSecondary = "py-4 rounded-xl border border-stone-300 bg-white text-stone-900 font-bold hover:border-black active:bg-stone-50 transition-all text-center px-4";
  const btnPrimary = "w-full py-5 bg-black text-white rounded-2xl font-bold shadow-xl shadow-black/10 active:scale-95 transition-all text-lg flex items-center justify-center gap-3";

  const renderStep1 = () => (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4">
      <div className="space-y-3">
        <label className="text-sm font-bold text-stone-800 uppercase tracking-wide">Seleccionar vino</label>
        <select 
          className="w-full px-4 py-4 rounded-xl border-2 border-stone-100 bg-white text-black outline-none font-bold text-lg"
          value={selectedWine.id}
          onChange={(e) => setSelectedWine(wines.find(w => w.id === e.target.value)!)}
        >
          {wines.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
        </select>
      </div>
      <div className="space-y-4">
        <h2 className="text-2xl font-bold text-black font-serif">¿Qué tipo de imagen quieres crear?</h2>
        <div className="grid gap-3">
          {Object.values(ImageType).map(t => (
            <button key={t} onClick={() => setType(t)} className="w-full py-6 rounded-2xl border-2 border-stone-100 bg-white text-stone-900 font-bold text-left px-8 hover:border-black transition-all shadow-sm active:bg-stone-50 flex justify-between items-center group">
              {t}
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className="opacity-0 group-hover:opacity-100 transition-opacity"><path d="m9 18 6-6-6-6"/></svg>
            </button>
          ))}
        </div>
      </div>
    </div>
  );

  const renderStep2 = () => {
    const questions: Record<ImageType, any[]> = {
      [ImageType.BODEGON]: [
        { label: "Tipo de superficie", key: "superficie", options: ["Madera", "Piedra", "Mármol", "Minimalista"] },
        { label: "Nivel de limpieza", key: "limpieza", options: ["Muy minimal", "Con elementos"] },
        { label: "Apoyo", key: "apoyo", options: ["Ninguno", "Copas", "Uvas", "Corchos"] },
        { label: "Fondo", key: "fondo", options: ["Neutro", "Con contexto"] }
      ],
      [ImageType.EN_USO]: [
        { label: "Sujeción", key: "mano", options: ["Mano sola", "Persona parcial"] },
        { label: "Acción", key: "accion", options: ["Servir", "Sostener", "Brindar"] },
        { label: "Cercanía", key: "cercania", options: ["Primer plano", "Plano medio"] },
        { label: "Humano", key: "protagonismo", options: ["Bajo", "Moderado"] }
      ],
      [ImageType.MOMENTO_SOCIAL]: [
        { label: "Personas", key: "personas", options: ["2 personas", "3 personas", "Grupo"] },
        { label: "Situación", key: "situacion", options: ["Íntima", "Celebración", "Informal"] },
        { label: "Ruido", key: "ruido", options: ["Limpio", "Dinámico"] },
        { label: "Foco", key: "foco", options: ["El vino", "La escena"] }
      ]
    };
    return (
      <div className="space-y-8 animate-in fade-in slide-in-from-right-4">
        <h2 className="text-2xl font-bold text-black font-serif">Detalles de {state.type}</h2>
        <div className="space-y-6">
          {questions[state.type!].map(q => (
            <div key={q.key} className="space-y-3">
              <label className="text-xs font-black text-stone-400 uppercase tracking-widest">{q.label}</label>
              <div className="grid grid-cols-2 gap-3">
                {q.options.map((opt: string) => (
                  <button key={opt} onClick={() => handleSelection(q.key, opt)} className={`py-4 rounded-xl border-2 font-bold transition-all ${state.selections[q.key] === opt ? 'bg-black text-white border-black' : 'bg-white text-stone-900 border-stone-100 hover:border-stone-300'}`}>
                    {opt}
                  </button>
                ))}
              </div>
            </div>
          ))}
        </div>
        <button onClick={nextStep} className={btnPrimary}>Continuar</button>
      </div>
    );
  };

  const renderStep3 = () => (
    <div className="space-y-8 animate-in fade-in slide-in-from-right-4">
      <h2 className="text-2xl font-bold text-black font-serif">Atmósfera</h2>
      <div className="space-y-6">
        <div className="space-y-3">
          <label className="text-xs font-black text-stone-400 uppercase tracking-widest">Formato</label>
          <div className="grid grid-cols-4 gap-2">
            {['1:1', '4:5', '9:16', '16:9'].map(r => (
              <button key={r} onClick={() => setRatio(r as AspectRatio)} className={`py-4 rounded-xl border-2 font-black text-xs ${ratio === r ? 'bg-black text-white border-black' : 'bg-white text-stone-900 border-stone-100'}`}>{r}</button>
            ))}
          </div>
        </div>
        <div className="space-y-3">
          <label className="text-xs font-black text-stone-400 uppercase tracking-widest">¿Dónde ocurre?</label>
          <div className="grid grid-cols-2 gap-3">
            {["Exterior", "Bodega", "Restaurante", "Casa"].map(opt => (
              <button key={opt} onClick={() => handleSelection('donde', opt)} className={`py-4 rounded-xl border-2 font-bold ${state.selections['donde'] === opt ? 'bg-black text-white border-black' : 'bg-white text-stone-900 border-stone-100'}`}>{opt}</button>
            ))}
          </div>
        </div>
        <div className="space-y-3">
          <label className="text-xs font-black text-stone-400 uppercase tracking-widest">Detalles adicionales</label>
          <textarea value={state.contextText} onChange={(e) => setState(prev => ({ ...prev, contextText: e.target.value }))} className="w-full px-5 py-4 rounded-2xl border-2 border-stone-100 bg-white text-black placeholder-stone-300 outline-none h-32 font-medium focus:border-stone-300 transition-all" placeholder="Ej: Luz de tarde filtrada..." />
        </div>
      </div>
      <button disabled={loading} onClick={startConceptGeneration} className={btnPrimary}>
        {loading && <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />}
        Crear propuestas
      </button>
    </div>
  );

  const renderStep4 = () => (
    <div className="space-y-8 animate-in fade-in scale-95 duration-500">
      <h2 className="text-2xl font-serif font-bold text-black text-center">Propuestas Creativas</h2>
      <div className="space-y-4">
        {state.concepts.map((concept, idx) => (
          <div key={idx} className={`bg-white border-2 p-6 rounded-3xl shadow-sm transition-all ${state.editingConceptIndex === idx ? 'border-black ring-2 ring-black/5' : 'border-stone-100 hover:border-black'}`}>
            {state.editingConceptIndex === idx ? (
              <div className="space-y-4">
                <textarea autoFocus value={editValue} onChange={(e) => setEditValue(e.target.value)} className="w-full px-4 py-3 border-2 border-stone-100 rounded-xl text-stone-900 bg-stone-50 outline-none h-32 font-medium" />
                <div className="flex gap-2 justify-end">
                  <button onClick={() => setState(prev => ({ ...prev, editingConceptIndex: null }))} className="px-5 py-2 text-sm font-bold text-stone-500">Cancelar</button>
                  <button onClick={handleSaveEdit} className="bg-black text-white px-6 py-2 rounded-xl text-sm font-bold shadow-lg">Guardar</button>
                </div>
              </div>
            ) : (
              <div className="space-y-4">
                <p className="text-stone-900 font-medium italic text-lg leading-relaxed">"{concept}"</p>
                <div className="flex justify-between items-center pt-2">
                  <button onClick={() => { setEditValue(concept); setState(prev => ({ ...prev, editingConceptIndex: idx })); }} className="flex items-center gap-2 text-stone-400 hover:text-black transition-colors font-bold text-xs uppercase tracking-widest">
                    <svg xmlns="http://www.w3.org/2000/svg" width="16" height="16" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M17 3a2.85 2.83 0 1 1 4 4L7.5 20.5 2 22l1.5-5.5Z"/><path d="m15 5 4 4"/></svg>
                    Editar
                  </button>
                  <button disabled={loading} onClick={() => selectAndGenerate(idx)} className="bg-black text-white px-8 py-3 rounded-xl font-bold active:scale-95 transition-all text-sm shadow-xl shadow-black/5">Elegir concepto</button>
                </div>
              </div>
            )}
          </div>
        ))}
        <button disabled={loading} onClick={startConceptGeneration} className="w-full py-5 border-2 border-dashed border-stone-300 text-stone-500 rounded-3xl font-bold flex items-center justify-center gap-2 hover:border-black hover:text-black transition-all mt-4">
          <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M2 12s3-7 10-7 10 7 10 7-3 7-10 7-10-7-10-7Z"/><circle cx="12" cy="12" r="3"/></svg>
          Proponer otros conceptos
        </button>
      </div>
    </div>
  );

  const renderStep5 = () => (
    <div className="space-y-8 animate-in zoom-in-95">
      {loading ? (
        <div className="flex flex-col items-center justify-center py-24 space-y-8">
          <div className="w-20 h-20 border-4 border-stone-100 border-t-black rounded-full animate-spin" />
          <div className="text-center space-y-2">
            <h3 className="text-2xl font-bold text-black font-serif">Capturando la escena...</h3>
            <p className="text-stone-400 font-medium">Procesando arte en alta resolución.</p>
          </div>
        </div>
      ) : error ? (
        <div className="py-24 text-center space-y-6 animate-in fade-in">
          <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mx-auto">
            <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" x2="12" y1="8" y2="12"/><line x1="12" x2="12.01" y1="16" y2="16"/></svg>
          </div>
          <div className="space-y-2">
            <h3 className="text-xl font-bold text-black">{error}</h3>
            <p className="text-stone-500">Hubo un problema al procesar tu solicitud.</p>
          </div>
          <button onClick={() => setState(p => ({ ...p, step: 4 }))} className="bg-black text-white px-8 py-3 rounded-xl font-bold active:scale-95 transition-all">Volver a intentar</button>
        </div>
      ) : state.imageHistory[0] ? (
        <div className="space-y-8 animate-in fade-in duration-1000">
          <div className="rounded-3xl overflow-hidden border border-stone-100 shadow-2xl bg-white aspect-square relative">
            <img src={state.imageHistory[0]} alt="Final" className="w-full h-full object-cover" />
          </div>
          <div className="bg-stone-50 p-6 rounded-2xl border border-stone-100 italic text-stone-700 font-medium text-center">
            "{state.concepts[state.selectedConceptIndex!]}"
          </div>
          <div className="grid grid-cols-3 gap-3">
            <button onClick={() => selectAndGenerate(state.selectedConceptIndex!)} className={btnSecondary} title="Regenerar">
               <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="mx-auto"><path d="M21 12a9 9 0 0 0-9-9 9.75 9.75 0 0 0-6.74 2.74L3 8"/><path d="M3 3v5h5"/><path d="M3 12a9 9 0 0 0 9 9 9.75 9.75 0 0 0 6.74-2.74L21 16"/><path d="M16 16h5v5"/></svg>
               <span className="block mt-1 text-[10px] uppercase">Regenerar</span>
            </button>
            <button onClick={() => setState(p => ({ ...p, step: 4 }))} className={btnSecondary} title="Volver a conceptos">
               <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="mx-auto"><path d="m12 19-7-7 7-7"/><path d="M19 12H5"/></svg>
               <span className="block mt-1 text-[10px] uppercase">Conceptos</span>
            </button>
            <button onClick={() => handleDownload(state.imageHistory[0])} className="py-4 rounded-xl bg-black text-white font-bold active:scale-95 transition-all text-center px-4" title="Descargar">
               <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="mx-auto"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" x2="12" y1="15" y2="3"/></svg>
               <span className="block mt-1 text-[10px] uppercase">Descargar</span>
            </button>
          </div>
          <div className="pt-6 border-t border-stone-100 space-y-4">
            <h4 className="text-sm font-black text-stone-900 uppercase tracking-widest">Ajustar esta imagen</h4>
            <div className="flex flex-wrap gap-2">
              {["Más luz lateral", "Etiqueta más brillante", "Fondo más oscuro", "Aclarar colores"].map(s => (
                <button key={s} onClick={() => handleAdjustment(s)} className="px-4 py-2 rounded-full border border-stone-300 text-xs font-bold text-stone-900 hover:border-black transition-all bg-white">{s}</button>
              ))}
            </div>
            <div className="flex gap-2">
              <input type="text" value={customAdjustment} onChange={(e) => setCustomAdjustment(e.target.value)} placeholder="Otro ajuste..." className="flex-1 px-4 py-3 border border-stone-200 rounded-xl text-sm outline-none focus:border-stone-400" />
              <button disabled={!customAdjustment.trim()} onClick={() => { handleAdjustment(customAdjustment); setCustomAdjustment(''); }} className="bg-black text-white px-6 py-3 rounded-xl text-sm font-bold active:scale-95 transition-all">Aplicar</button>
            </div>
          </div>
        </div>
      ) : (
        <div className="py-24 text-center space-y-6">
           <p className="text-stone-500 font-bold">No hay ninguna imagen activa.</p>
           <button onClick={() => setState(p => ({ ...p, step: 4 }))} className="text-black font-black uppercase text-xs tracking-widest underline underline-offset-4">Volver a propuestas</button>
        </div>
      )}
    </div>
  );

  return (
    <div className="max-w-xl mx-auto pb-20">
      {state.step === 1 && renderStep1()}
      {state.step === 2 && renderStep2()}
      {state.step === 3 && renderStep3()}
      {state.step === 4 && renderStep4()}
      {state.step === 5 && renderStep5()}
    </div>
  );
};

export default CreativeFunnel;

import { GoogleGenAI, Type } from "@google/genai";
import { Wine, ImageType, FunnelState } from "../types";

export const generateVisualConcepts = async (wine: Wine, state: FunnelState): Promise<string[]> => {
  // Initialize right before call to ensure up-to-date config
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Eres un Director Creativo experto en fotografía de vinos para Kinglab Bodegas 202.
    Analiza la siguiente información y genera 3 conceptos visuales distintos, creativos y profesionales en ESPAÑOL.

    PRODUCTO:
    - Nombre: ${wine.name}
    - Perfil: ${wine.description}
    - Público: ${wine.targetAudience}
    - Nivel: ${wine.priceLevel}
    - Especial: ${wine.specialFeatures.join(', ')}

    TIPO DE IMAGEN: ${state.type}
    DETALLES ELEGIDOS: ${JSON.stringify(state.selections)}
    CONTEXTO ADICIONAL: ${state.contextText || 'Ninguno'}

    REGLAS:
    - Los conceptos deben ser cortos (un párrafo de 30-40 palabras cada uno).
    - Lenguaje editorial, elegante y descriptivo.
    - Cada concepto debe ser único en su enfoque visual.
    - Idioma: Español.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            concepts: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Tres párrafos descriptivos de conceptos visuales."
            }
          },
          required: ["concepts"]
        }
      }
    });

    const data = JSON.parse(response.text || '{}');
    return data.concepts || [];
  } catch (error) {
    console.error("Error generating concepts:", error);
    throw error;
  }
};

export const generateFinalImage = async (
  wine: Wine, 
  concept: string, 
  ratio: string, 
  adjustment?: string
): Promise<string | null> => {
  // Initialize right before call
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const base64Data = wine.image.split(',')[1];
  const mimeType = wine.image.split(';')[0].split(':')[1];

  let prompt = `
    Genera una imagen publicitaria de alta calidad basada ESTRICTAMENTE en este concepto creativo:
    "${concept}"

    DETALLES TÉCNICOS:
    - Producto: ${wine.name}
    - Objetivo: Mantener la forma exacta de la botella y la legibilidad de la etiqueta de la imagen de referencia.
    - Estilo: Fotografía publicitaria profesional de alta gama.
  `;

  if (adjustment) {
    prompt += `\n\nAPLICA ESTE AJUSTE ESPECÍFICO: "${adjustment}" manteniendo el resto de la composición.`;
  }

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: {
        parts: [
          { inlineData: { data: base64Data, mimeType } },
          { text: prompt }
        ]
      },
      config: {
        imageConfig: {
          aspectRatio: ratio as any
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Error generating final image:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { Wine, ImageType, FunnelState, AspectRatio, GalleryImage } from '../types';
import { generateVisualConcepts, generateFinalImage } from '../services/geminiService';

interface CreativeFunnelProps {
  wines: Wine[];
  onFinish: () => void;
  onSaveToGallery: (img: GalleryImage) => void;
  initialData?: {
    wine: Wine;
    concept: string;
    isAdjustment?: boolean;
  };
}

const CreativeFunnel: React.FC<CreativeFunnelProps> = ({ wines, onFinish, onSaveToGallery, initialData }) => {
  const [selectedWine, setSelectedWine] = useState<Wine>(initialData?.wine || wines[0]);
  const [state, setState] = useState<FunnelState>({
    type: null,
    step: initialData ? 5 : 1,
    selections: {},
    contextText: '',
    concepts: initialData ? [initialData.concept] : [],
    selectedConceptIndex: initialData ? 0 : null,
    editingConceptIndex: null,
    imageHistory: []
  });
  const [ratio, setRatio] = useState<AspectRatio>('1:1');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [editValue, setEditValue] = useState('');
  const [customAdjustment, setCustomAdjustment] = useState('');

  // Initial trigger for Gallery regeneration/adjustment
  useEffect(() => {
    if (initialData && state.step === 5 && state.imageHistory.length === 0) {
      if (!initialData.isAdjustment) {
        selectAndGenerate(0);
      }
    }
  }, []);

  const setType = (type: ImageType) => {
    setError(null);
    setState(prev => ({ ...prev, type, step: 2, selections: {} }));
  };

  const handleSelection = (key: string, value: string) => {
    setState(prev => ({ ...prev, selections: { ...prev.selections, [key]: value } }));
  };

  const nextStep = () => {
    setError(null);
    setState(prev => ({ ...prev, step: prev.step + 1 }));
  };

  const prevStep = () => {
    setError(null);
    setState(prev => ({ ...prev, step: prev.step === 5 ? 4 : Math.max(1, prev.step - 1) }));
  };

  const startConceptGeneration = async () => {
    // 1. STATE CLEARING: Discard any previous concepts/results before starting
    setLoading(true);
    setError(null);
    setState(prev => ({ 
      ...prev, 
      concepts: [], 
      selectedConceptIndex: null, 
      imageHistory: [] 
    }));

    try {
      const concepts = await generateVisualConcepts(selectedWine, state);
      if (concepts && concepts.length > 0) {
        setState(prev => ({ ...prev, concepts, step: 4 }));
      } else {
        throw new Error("No concepts returned");
      }
    } catch (e) {
      setError("No se pudieron generar conceptos creativos. Por favor, revisa el contexto e intenta de nuevo.");
    } finally {
      setLoading(false);
    }
  };

  const selectAndGenerate = async (index: number, adjustment?: string) => {
    // 2. STATE CLEARING: Discard current results before new final image generation
    setLoading(true);
    setError(null);
    setState(prev => ({ 
      ...prev, 
      selectedConceptIndex: index, 
      imageHistory: [], 
      step: 5 
    }));

    try {
      const img = await generateFinalImage(selectedWine, state.concepts[index], ratio, adjustment);
      if (img) {
        const galleryItem: GalleryImage = {
          id: Date.now().toString(),
          url: img,
          concept: state.concepts[index],
          wineName: selectedWine.name,
          timestamp: Date.now()
        };
        onSaveToGallery(galleryItem);
        // Explicitly set the new history with ONLY the current result
        setState(prev => ({ ...prev, imageHistory: [img] }));
      } else {
        throw new Error("Empty image result");
      }
    } catch (e) {
      setError("Error crítico durante la generación de la imagen publicitaria.");
    } finally {
      setLoading(false);
    }
  };

  const handleAdjustment = (adjustment: string) => {
    if (state.selectedConceptIndex !== null) {
      selectAndGenerate(state.selectedConceptIndex, adjustment);
    }
  };

  const handleSaveEdit = () => {
    if (state.editingConceptIndex !== null) {
      const newConcepts = [...state.concepts];
      newConcepts[state.editingConceptIndex] = editValue;
      setState(prev => ({ ...prev, concepts: newConcepts, editingConceptIndex: null }));
    }
  };

  const handleDownload = (imgUrl: string) => {
    const conceptSlug = state.concepts[state.selectedConceptIndex || 0].substring(0, 20).toLowerCase().replace(/[^a-z0-9]/g, '_');
    const wineSlug = selectedWine.name.toLowerCase().replace(/[^a-z0-9]/g, '_');
    const filename = `${wineSlug}_${conceptSlug}_${Date.now()}.png`;

    const link = document.createElement('a');
    link.href = imgUrl;
    link.download = filename;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const btnSecondary = "py-4 rounded-xl border border-stone-300 bg-white text-stone-900 font-bold hover:border-black active:bg-stone-50 transition-all text-center px-4";
  const btnPrimary = "w-full py-5 bg-black text-white rounded-2xl font-bold shadow-xl shadow-black/10 active:scale-95 transition-all text-lg flex items-center justify-center gap-3";

  const renderStep1 = () => (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4">
      <div className="space-y-3">
        <label className="text-sm font-bold text-stone-800 uppercase tracking-wide">Seleccionar vino</label>
        <select 
          className="w-full px-4 py-4 rounded-xl border-2 border-stone-100 bg-white text-black outline-none font-bold text-lg focus:border-black transition-colors"
          value={selectedWine.id}
          onChange={(e) => setSelectedWine(wines.find(w => w.id === e.target.value)!)}
        >
          {wines.map(w => <option key={w.id} value={w.id}>{w.name}</option>)}
        </select>
      </div>
      <div className="space-y-4">
        <h2 className="text-2xl font-bold text-black font-serif">¿Qué tipo de imagen quieres crear?</h2>
        <div className="grid gap-3">
          {Object.values(ImageType).map(t => (
            <button key={t} onClick={() => setType(t)} className="w-full py-6 rounded-2xl border-2 border-stone-100 bg-white text-stone-900 font-bold text-left px-8 hover:border-black transition-all shadow-sm active:bg-stone-50 flex justify-between items-center group">
              {t}
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className="opacity-0 group-hover:opacity-100 transition-opacity"><path d="m9 18 6-6-6-6"/></svg>
            </button>
          ))}
        </div>
      </div>
    </div>
  );

  const renderStep2 = () => {
    const questions: Record<ImageType, any[]> = {
      [ImageType.BODEGON]: [
        { label: "Tipo de superficie", key: "superficie", options: ["Madera", "Piedra", "Mármol", "Minimalista"] },
        { label: "Nivel de limpieza", key: "limpieza", options: ["Muy minimal", "Con elementos"] },
        { label: "Apoyo", key: "apoyo", options: ["Ninguno", "Copas", "Uvas", "Corchos"] },
        { label: "Fondo", key: "fondo", options: ["Neutro", "Con contexto"] }
      ],
      [ImageType.EN_USO]: [
        { label: "Sujeción", key: "mano", options: ["Mano sola", "Persona parcial"] },
        { label: "Acción", key: "accion", options: ["Servir", "Sostener", "Brindar"] },
        { label: "Cercanía", key: "cercania", options: ["Primer plano", "Plano medio"] },
        { label: "Humano", key: "protagonismo", options: ["Bajo", "Moderado"] }
      ],
      [ImageType.MOMENTO_SOCIAL]: [
        { label: "Personas", key: "personas", options: ["2 personas", "3 personas", "Grupo"] },
        { label: "Situación", key: "situacion", options: ["Íntima", "Celebración", "Informal"] },
        { label: "Ruido", key: "ruido", options: ["Limpio", "Dinámico"] },
        { label: "Foco", key: "foco", options: ["El vino", "La escena"] }
      ]
    };
    return (
      <div className="space-y-8 animate-in fade-in slide-in-from-right-4">
        <h2 className="text-2xl font-bold text-black font-serif">Detalles de {state.type}</h2>
        <div className="space-y-6">
          {questions[state.type!].map(q => (
            <div key={q.key} className="space-y-3">
              <label className="text-xs font-black text-stone-400 uppercase tracking-widest">{q.label}</label>
              <div className="grid grid-cols-2 gap-3">
                {q.options.map((opt: string) => (
                  <button key={opt} onClick={() => handleSelection(q.key, opt)} className={`py-4 rounded-xl border-2 font-bold transition-all ${state.selections[q.key] === opt ? 'bg-black text-white border-black' : 'bg-white text-stone-900 border-stone-100 hover:border-stone-300'}`}>
                    {opt}
                  </button>
                ))}
              </div>
            </div>
          ))}
        </div>
        <button onClick={nextStep} className={btnPrimary}>Continuar</button>
      </div>
    );
  };

  const renderStep3 = () => (
    <div className="space-y-8 animate-in fade-in slide-in-from-right-4">
      <h2 className="text-2xl font-bold text-black font-serif">Atmósfera</h2>
      <div className="space-y-6">
        <div className="space-y-3">
          <label className="text-xs font-black text-stone-400 uppercase tracking-widest">Formato</label>
          <div className="grid grid-cols-4 gap-2">
            {['1:1', '4:5', '9:16', '16:9'].map(r => (
              <button key={r} onClick={() => setRatio(r as AspectRatio)} className={`py-4 rounded-xl border-2 font-black text-xs ${ratio === r ? 'bg-black text-white border-black' : 'bg-white text-stone-900 border-stone-100'}`}>{r}</button>
            ))}
          </div>
        </div>
        <div className="space-y-3">
          <label className="text-xs font-black text-stone-400 uppercase tracking-widest">¿Dónde ocurre?</label>
          <div className="grid grid-cols-2 gap-3">
            {["Exterior", "Bodega", "Restaurante", "Casa"].map(opt => (
              <button key={opt} onClick={() => handleSelection('donde', opt)} className={`py-4 rounded-xl border-2 font-bold ${state.selections['donde'] === opt ? 'bg-black text-white border-black' : 'bg-white text-stone-900 border-stone-100'}`}>{opt}</button>
            ))}
          </div>
        </div>
        <div className="space-y-3">
          <label className="text-xs font-black text-stone-400 uppercase tracking-widest">Detalles adicionales</label>
          <textarea value={state.contextText} onChange={(e) => setState(prev => ({ ...prev, contextText: e.target.value }))} className="w-full px-5 py-4 rounded-2xl border-2 border-stone-100 bg-white text-black placeholder-stone-300 outline-none h-32 font-medium focus:border-stone-300 transition-all" placeholder="Ej: Luz de tarde filtrada..." />
        </div>
      </div>
      <button disabled={loading} onClick={startConceptGeneration} className={btnPrimary}>
        {loading && <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />}
        Crear propuestas
      </button>
    </div>
  );

  const renderStep4 = () => (
    <div className="space-y-8 animate-in fade-in scale-95 duration-500">
      <h2 className="text-2xl font-serif font-bold text-black text-center">Propuestas Creativas</h2>
      {loading ? (
        <div className="py-24 flex flex-col items-center justify-center space-y-6">
          <div className="w-16 h-16 border-4 border-stone-100 border-t-black rounded-full animate-spin" />
          <p className="text-stone-400 font-bold">Ideando conceptos únicos...</p>
        </div>
      ) : error ? (
        <div className="py-24 text-center space-y-6">
          <p className="text-red-500 font-bold">{error}</p>
          <button onClick={startConceptGeneration} className="bg-black text-white px-8 py-3 rounded-xl font-bold">Reintentar</button>
        </div>
      ) : (
        <div className="space-y-4">
          {state.concepts.map((concept, idx) => (
            <div key={idx} className={`bg-white border-2 p-6 rounded-3xl shadow-sm transition-all ${state.editingConceptIndex === idx ? 'border-black ring-2 ring-black/5' : 'border-stone-100 hover:border-black'}`}>
              {state.editingConceptIndex === idx ? (
                <div className="space-y-4">
                  <textarea autoFocus value={editValue} onChange={(e) => setEditValue(e.target.value)} className="w-full px-4 py-3 border-2 border-stone-100 rounded-xl text-stone-900 bg-stone-50 outline-none h-32 font-medium" />
                  <div className="flex gap-2 justify-end">
                    <button onClick={() => setState(prev => ({ ...prev, editingConceptIndex: null }))} className="px-5 py-2 text-sm font-bold text-stone-500">Cancelar</button>
                    <button onClick={handleSaveEdit} className="bg-black text-white px-6 py-2 rounded-xl text-sm font-bold shadow-lg">Guardar</button>
                  </div>
                </div>
              ) : (
                <div className="space-y-4">
                  <p className="text-stone-900 font-medium italic text-lg leading-relaxed">"{concept}"</p>
                  <div className="flex justify-between items-center pt-2">
