            <h4 className="text-sm font-black text-stone-900 uppercase tracking-widest">Ajustar esta imagen</h4>
            <div className="flex flex-wrap gap-2">
              {["Más luz lateral", "Etiqueta más brillante", "Fondo más oscuro", "Aclarar colores"].map(s => (
                <button key={s} onClick={() => handleAdjustment(s)} className="px-4 py-2 rounded-full border border-stone-300 text-xs font-bold text-stone-900 hover:border-black transition-all bg-white shadow-sm">{s}</button>
              ))}
            </div>
            <div className="flex gap-2">
              <input type="text" value={customAdjustment} onChange={(e) => setCustomAdjustment(e.target.value)} placeholder="Ej: Añade una copa vacía..." className="flex-1 px-4 py-3 border border-stone-200 rounded-xl text-sm outline-none focus:border-stone-400 font-medium" />
              <button disabled={!customAdjustment.trim() || loading} onClick={() => { handleAdjustment(customAdjustment); setCustomAdjustment(''); }} className="bg-black text-white px-6 py-3 rounded-xl text-sm font-bold active:scale-95 transition-all">Aplicar</button>
            </div>
          </div>
        </div>
      ) : (
        <div className="py-24 text-center space-y-6 animate-in fade-in">
           <div className="w-16 h-16 bg-stone-50 rounded-full flex items-center justify-center mx-auto text-stone-300">
             <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect width="18" height="18" x="3" y="3" rx="2" ry="2"/><circle cx="9" cy="9" r="2"/><path d="m21 15-3.086-3.086a2 2 0 0 0-2.828 0L6 21"/></svg>
           </div>
           <p className="text-stone-500 font-bold">No hay ninguna imagen activa.</p>
           <button onClick={() => setState(p => ({ ...p, step: 4 }))} className="text-black font-black uppercase text-xs tracking-widest underline underline-offset-4">Volver a propuestas</button>
        </div>
      )}
    </div>
  );

  return (
    <div className="max-w-xl mx-auto pb-20">
      {state.step === 1 && renderStep1()}
      {state.step === 2 && renderStep2()}
      {state.step === 3 && renderStep3()}
      {state.step === 4 && renderStep4()}
      {state.step === 5 && renderStep5()}
    </div>
  );
};

export default CreativeFunnel;

import React, { useState } from 'react';
import { Wine, ImageType, AspectRatio } from '../types';
import { generateFinalImage } from '../services/geminiService';

interface ImageGeneratorProps {
  wines: Wine[];
  initialSelectedWine?: Wine;
}

const ImageGenerator: React.FC<ImageGeneratorProps> = ({ wines, initialSelectedWine }) => {
  const [selectedWine, setSelectedWine] = useState<Wine | null>(initialSelectedWine || wines[0] || null);
  const [ratio, setRatio] = useState<AspectRatio>('1:1');
  const [type, setType] = useState<ImageType>(ImageType.BODEGON);
  const [context, setContext] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);

  const handleGenerate = async () => {
    if (!selectedWine) return;

    // STATE RESET: Clear previous results/errors before starting a new request
    setLoading(true);
    setError(null);
    setGeneratedImage(null);

    try {
      const concept = context.trim() || `Fotografía publicitaria profesional de ${selectedWine.name}, estilo ${type}.`;
      const result = await generateFinalImage(selectedWine, concept, ratio);
      if (result) {
        setGeneratedImage(result);
      } else {
        setError("La generación no devolvió ninguna imagen.");
      }
    } catch (error) {
      setError("Error al generar la imagen. Verifica tu conexión o intenta con otro contexto.");
    } finally {
      setLoading(false);
    }
  };

  const ratios: AspectRatio[] = ['1:1', '4:5', '9:16', '16:9'];
  const types = Object.values(ImageType);

  const labelClasses = "block text-sm font-semibold text-stone-700 mb-2";

  return (
    <div className="space-y-8 pb-10">
      {loading ? (
        <div className="py-24 flex flex-col items-center justify-center space-y-6">
          <div className="w-20 h-20 border-4 border-stone-100 border-t-black rounded-full animate-spin" />
          <div className="text-center">
             <h3 className="text-xl font-bold font-serif">Creando escena...</h3>
             <p className="text-stone-400 font-medium">Capturando detalles publicitarios.</p>
          </div>
        </div>
      ) : error ? (
        <div className="py-24 text-center space-y-6">
           <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mx-auto">
             <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" x2="12" y1="8" y2="12"/><line x1="12" x2="12.01" y1="16" y2="16"/></svg>
           </div>
           <p className="text-red-600 font-bold">{error}</p>
           <button onClick={() => setError(null)} className="bg-black text-white px-8 py-3 rounded-xl font-bold">Intentar de nuevo</button>
        </div>
      ) : !generatedImage ? (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-300">
          <div>
            <label className={labelClasses}>Seleccionar vino</label>
            <select
              className="w-full px-4 py-3 rounded-lg border border-stone-200 focus:ring-2 focus:ring-black outline-none bg-white text-black font-bold"
              value={selectedWine?.id || ''}
              onChange={(e) => setSelectedWine(wines.find(w => w.id === e.target.value) || null)}
            >
              {wines.map(w => (
                <option key={w.id} value={w.id}>{w.name}</option>
              ))}
            </select>
          </div>

          <div className="space-y-3">
            <label className={labelClasses}>Formato</label>
            <div className="grid grid-cols-4 gap-2">
              {ratios.map(r => (
                <button
                  key={r}
                  onClick={() => setRatio(r)}
                  className={`py-3 rounded-lg border-2 text-sm font-black transition-all ${
                    ratio === r 
                    ? 'bg-black text-white border-black shadow-md' 
                    : 'bg-white text-stone-600 border-stone-100 hover:border-stone-400'
                  }`}
                >
                  {r}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-3">
            <label className={labelClasses}>Tipo de imagen</label>
            <div className="grid grid-cols-1 gap-2">
              {types.map(t => (
                <button
                  key={t}
                  onClick={() => setType(t)}
                  className={`py-4 rounded-xl border-2 text-left px-5 font-bold transition-all ${
                    type === t 
                    ? 'bg-black text-white border-black shadow-md' 
                    : 'bg-white text-stone-600 border-stone-100 hover:border-stone-400'
                  }`}
                >
                  {t}
                </button>
              ))}
            </div>
          </div>

          <div className="space-y-2">
            <label className={labelClasses}>Idea o contexto</label>
            <textarea
              value={context}
              onChange={(e) => setContext(e.target.value)}
              className="w-full px-4 py-3 rounded-xl border border-stone-200 focus:ring-2 focus:ring-black outline-none bg-white text-black placeholder-stone-300 transition-all font-medium h-32"
              placeholder="Ej: Bodega antigua con barricas al fondo..."
            />
          </div>

          <button
            onClick={handleGenerate}
            disabled={loading || !selectedWine}
            className="w-full py-5 rounded-2xl font-bold text-white shadow-xl bg-black shadow-black/10 active:scale-[0.98] transition-all flex items-center justify-center gap-3 text-lg"
          >
            <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m12 3-1.912 5.813a2 2 0 0 1-1.275 1.275L3 12l5.813 1.912a2 2 0 0 1 1.275 1.275L12 21l1.912-5.813a2 2 0 0 1 1.275-1.275L21 12l-5.813-1.912a2 2 0 0 1-1.275-1.275L12 3Z"/></svg>
            Generar imagen
          </button>
        </div>
      ) : (
        <div className="space-y-6 animate-in zoom-in-95 duration-500">
          <div className="relative group overflow-hidden rounded-3xl border border-stone-100 shadow-2xl bg-white aspect-square">
            <img src={generatedImage} alt="Generated result" className="w-full h-full object-cover" />
          </div>
          <div className="grid grid-cols-2 gap-4">
            <button
              onClick={() => setGeneratedImage(null)}
              className="bg-stone-100 text-stone-700 py-4 rounded-xl font-bold hover:bg-stone-200 transition-all active:scale-95"
            >
              Nueva imagen
            </button>
            <button
              onClick={() => {
                const link = document.createElement('a');
                link.href = generatedImage;
                link.download = `vin_${Date.now()}.png`;
                link.click();
              }}
              className="bg-black text-white py-4 rounded-xl font-bold text-center shadow-lg active:scale-95 transition-all"
            >
              Descargar
            </button>
          </div>
        </div>
      )}
    </div>
  );
};

export default ImageGenerator;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import WineList from './components/WineList';
import WineForm from './components/WineForm';
import CreativeFunnel from './components/CreativeFunnel';
import Gallery from './components/Gallery';
import { Wine, AppScreen, GalleryImage } from './types';

const App: React.FC = () => {
  const [screen, setScreen] = useState<AppScreen>(AppScreen.HOME);
  const [funnelKey, setFunnelKey] = useState(0);
  const [wines, setWines] = useState<Wine[]>(() => {
    const saved = localStorage.getItem('kinglab_wines_v2');
    return saved ? JSON.parse(saved) : [];
  });
  const [gallery, setGallery] = useState<GalleryImage[]>(() => {
    const saved = localStorage.getItem('kinglab_gallery_v3');
    return saved ? JSON.parse(saved) : [];
  });
  const [selectedWineForEdit, setSelectedWineForEdit] = useState<Wine | null>(null);
  const [funnelConfig, setFunnelConfig] = useState<{
    wine: Wine;
    concept: string;
    isAdjustment?: boolean;
  } | undefined>(undefined);

  useEffect(() => { localStorage.setItem('kinglab_wines_v2', JSON.stringify(wines)); }, [wines]);
  useEffect(() => { localStorage.setItem('kinglab_gallery_v3', JSON.stringify(gallery)); }, [gallery]);

  const handleSaveWine = (wine: Wine) => {
    setWines(prev => {
      const exists = prev.find(w => w.id === wine.id);
      if (exists) return prev.map(w => w.id === wine.id ? wine : w);
      return [wine, ...prev];
    });
    setScreen(AppScreen.HOME);
    setSelectedWineForEdit(null);
  };

  const handleBack = () => {
    if (screen === AppScreen.FORM) setScreen(wines.length === 0 ? AppScreen.HOME : AppScreen.MANAGE);
    else setScreen(AppScreen.HOME);
    setSelectedWineForEdit(null);
    setFunnelConfig(undefined);
  };

  const startNewCreativeSession = () => {
    setFunnelConfig(undefined);
    setFunnelKey(prev => prev + 1); // Forzar reset total de CreativeFunnel
    setScreen(AppScreen.FUNNEL);
  };

  const startFromGallery = (img: GalleryImage, isAdjustment: boolean) => {
    const wine = wines.find(w => w.name === img.wineName);
    if (wine) {
      setFunnelConfig({ wine, concept: img.concept, isAdjustment });
      setFunnelKey(prev => prev + 1); // Forzar reset total de CreativeFunnel
      setScreen(AppScreen.FUNNEL);
    }
  };

  return (
    <Layout 
      title={screen === AppScreen.HOME ? 'Kinglab Bodegas 202' : screen} 
      onBack={screen !== AppScreen.HOME ? handleBack : undefined}
      onGear={() => setScreen(AppScreen.MANAGE)}
      onGallery={() => setScreen(AppScreen.GALLERY)}
      showGear={wines.length > 0}
      showGallery={gallery.length > 0}
    >
      {screen === AppScreen.HOME && (
        wines.length === 0 ? (
          <div className="flex flex-col items-center justify-center h-full py-24 text-center space-y-10 animate-in fade-in duration-700">
            <div className="space-y-3 px-8">
              <h2 className="text-5xl font-serif font-bold text-black">Kinglab</h2>
              <p className="text-stone-400 font-medium italic text-lg leading-relaxed">Estudio de dirección de arte profesional para el sector vinícola.</p>
            </div>
            <button 
              onClick={() => setScreen(AppScreen.FORM)} 
              className="bg-black text-white px-12 py-6 rounded-full font-bold shadow-2xl active:scale-90 transition-all text-xl hover:bg-stone-900"
            >
              Dar de alta un vino
            </button>
          </div>
        ) : (
          <div className="space-y-12 py-10 animate-in fade-in duration-500">
            <div className="bg-white p-12 rounded-[2.5rem] border-2 border-stone-100 text-center space-y-8 shadow-sm">
              <div className="w-16 h-16 bg-stone-50 rounded-full flex items-center justify-center mx-auto text-black border border-stone-100">
                <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2v20"/><path d="M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/></svg>
              </div>
              <div className="space-y-3">
                <h3 className="text-3xl font-serif font-bold">Mesa de Trabajo</h3>
                <p className="text-stone-400 font-medium">Inicia una sesión de dirección creativa para tus productos.</p>
              </div>
              <button 
                onClick={startNewCreativeSession} 
                className="w-full bg-black text-white px-8 py-6 rounded-3xl font-bold shadow-2xl transition-all text-xl active:scale-95 hover:bg-stone-900"
              >
                Comenzar proceso
              </button>
            </div>
            {gallery.length > 0 && (
              <div className="space-y-4">
                <h4 className="font-serif font-bold text-xl px-4">Recientes</h4>
                <div className="grid grid-cols-2 gap-4">
                  {gallery.slice(0, 4).map(img => (
                    <div 
                      key={img.id} 
                      onClick={() => setScreen(AppScreen.GALLERY)} 
                      className="aspect-square rounded-3xl overflow-hidden shadow-sm cursor-pointer border border-stone-100 active:scale-95 transition-transform"
                    >
                      <img src={img.url} className="w-full h-full object-cover" alt={img.wineName} />
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )
      )}

      {screen === AppScreen.FUNNEL && wines.length > 0 && (
        <CreativeFunnel 
          key={funnelKey}
          wines={wines} 
          onFinish={() => setScreen(AppScreen.HOME)} 
          onSaveToGallery={(img) => setGallery(prev => [img, ...prev])} 
          initialData={funnelConfig} 
        />
      )}

      {screen === AppScreen.GALLERY && (
        <Gallery 
          images={gallery} 
          onBack={() => setScreen(AppScreen.HOME)} 
          onRegenerate={(img) => startFromGallery(img, false)} 
          onAdjust={(img) => startFromGallery(img, true)} 
        />
      )}

      {screen === AppScreen.MANAGE && (
        <WineList wines={wines} onEdit={(w) => { setSelectedWineForEdit(w); setScreen(AppScreen.FORM); }} onAdd={() => { setSelectedWineForEdit(null); setScreen(AppScreen.FORM); }} />
      )}

      {screen === AppScreen.FORM && (
        <WineForm initialWine={selectedWineForEdit || undefined} onSave={handleSaveWine} />
      )}
    </Layout>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Wine, ImageType, FunnelState, AspectRatio, GalleryImage } from '../types';
import { generateVisualConcepts, generateFinalImage } from '../services/geminiService';

interface CreativeFunnelProps {
  wines: Wine[];
  onFinish: () => void;
  onSaveToGallery: (img: GalleryImage) => void;
  initialData?: {
    wine: Wine;
    concept: string;
    isAdjustment?: boolean;
  };
}

const LOCATIONS = ["Bodega / Cava", "Viñedo", "Mesa de Hogar", "Restaurante", "Wine Bar", "Entorno Minimalista"];

const CreativeFunnel: React.FC<CreativeFunnelProps> = ({ wines, onFinish, onSaveToGallery, initialData }) => {
  const [selectedWine, setSelectedWine] = useState<Wine>(initialData?.wine || wines[0]);
  const [state, setState] = useState<FunnelState>({
    type: null,
    location: null,
    step: initialData ? 6 : 1,
    selections: {},
    contextText: '',
    concepts: initialData ? [initialData.concept] : [],
    selectedConceptIndex: initialData ? 0 : null,
    editingConceptIndex: null,
    imageHistory: []
  });
  const [ratio, setRatio] = useState<AspectRatio>('1:1');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [editValue, setEditValue] = useState('');

  useEffect(() => {
    // Si entramos desde galería para regenerar directamente
    if (initialData && state.step === 6 && state.imageHistory.length === 0) {
      if (!initialData.isAdjustment) {
        selectAndGenerate(0);
      }
    }
  }, []);

  const handleSelection = (key: string, value: string) => {
    setState(prev => ({ ...prev, selections: { ...prev.selections, [key]: value } }));
  };

  const nextStep = () => {
    setError(null);
    setState(prev => ({ ...prev, step: prev.step + 1 }));
  };

  const prevStep = () => {
    setError(null);
    setState(prev => ({ ...prev, step: Math.max(1, prev.step - 1) }));
  };

  const startConceptGeneration = async () => {
    // CRITICAL: Reset state before new generation
    setLoading(true);
    setError(null);
    setState(prev => ({ ...prev, concepts: [], selectedConceptIndex: null, imageHistory: [] }));

    try {
      const concepts = await generateVisualConcepts(selectedWine, state);
      if (concepts && concepts.length > 0) {
        setState(prev => ({ ...prev, concepts, step: 5 }));
      } else {
        throw new Error("No concepts returned");
      }
    } catch (e) {
      setError("No se pudieron idear los conceptos creativos. Reintenta por favor.");
    } finally {
      setLoading(false);
    }
  };

  const selectAndGenerate = async (index: number, adjustment?: string) => {
    // CRITICAL: Reset state before final image generation
    setLoading(true);
    setError(null);
    setState(prev => ({ ...prev, selectedConceptIndex: index, step: 6, imageHistory: [] }));

    try {
      const img = await generateFinalImage(selectedWine, state.concepts[index], ratio, adjustment);
      if (img) {
        const galleryItem: GalleryImage = {
          id: Date.now().toString(),
          url: img,
          concept: state.concepts[index],
          wineName: selectedWine.name,
          timestamp: Date.now()
        };
        onSaveToGallery(galleryItem);
        setState(prev => ({ ...prev, imageHistory: [img] }));
      } else {
        throw new Error("Empty image result");
      }
    } catch (e) {
      setError("Error crítico durante la captura de la escena. Reintenta.");
    } finally {
      setLoading(false);
    }
  };

  const handleAdjustment = (adjustment: string) => {
    if (state.selectedConceptIndex !== null) {
      selectAndGenerate(state.selectedConceptIndex, adjustment);
    }
  };

  const handleSaveEdit = () => {
    if (state.editingConceptIndex !== null) {
      const newConcepts = [...state.concepts];
      newConcepts[state.editingConceptIndex] = editValue;
      setState(prev => ({ ...prev, concepts: newConcepts, editingConceptIndex: null }));
    }
  };

  const handleDownload = (imgUrl: string) => {
    const link = document.createElement('a');
    link.href = imgUrl;
    link.download = `kinglab_${selectedWine.name.replace(/\s+/g, '_')}_${Date.now()}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const btnSecondary = "py-4 rounded-xl border border-stone-300 bg-white text-stone-900 font-bold hover:border-black active:bg-stone-50 transition-all text-center px-4";

  const stepIndicator = (current: number) => (
    <div className="flex justify-center gap-2 mb-8">
      {[1, 2, 3, 4, 5].map(i => (
        <div key={i} className={`h-1.5 rounded-full transition-all duration-500 ${i === current ? 'w-10 bg-black' : 'w-2 bg-stone-200'}`} />
      ))}
    </div>
  );

  // Step 1: PRODUCT
  const renderStep1 = () => (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4">
      {stepIndicator(1)}
      <div className="space-y-6">
        <h2 className="text-3xl font-bold text-black font-serif">1. Producto</h2>
        <p className="text-stone-500">Selecciona el vino que deseas trabajar.</p>
        <div className="grid gap-4">
          {wines.map(w => (
            <button 
              key={w.id} 
              onClick={() => { setSelectedWine(w); nextStep(); }}
              className={`w-full py-6 rounded-2xl border-2 text-left px-8 hover:border-black transition-all shadow-sm flex items-center gap-6 group ${selectedWine.id === w.id ? 'border-black bg-stone-50' : 'border-stone-100 bg-white'}`}
            >
              <img src={w.image} className="w-16 h-16 object-contain" alt={w.name} />
              <div className="flex-1">
                <p className="text-lg font-bold">{w.name}</p>
                <p className="text-stone-400 text-sm">{w.description.substring(0, 40)}...</p>
              </div>
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className="opacity-40 group-hover:opacity-100 transition-opacity"><path d="m9 18 6-6-6-6"/></svg>
            </button>
          ))}
        </div>
      </div>
    </div>
  );

  // Step 2: IMAGE TYPE
  const renderStep2 = () => (
    <div className="space-y-8 animate-in fade-in slide-in-from-right-4">
      {stepIndicator(2)}
      <div className="space-y-6">
        <h2 className="text-3xl font-bold text-black font-serif">2. Dirección de Estilo</h2>
        <div className="grid gap-3">
          {Object.values(ImageType).map(t => (
            <button key={t} onClick={() => { setState(prev => ({ ...prev, type: t })); nextStep(); }} className={`w-full py-6 rounded-2xl border-2 bg-white text-stone-900 font-bold text-left px-8 hover:border-black transition-all shadow-sm active:bg-stone-50 flex justify-between items-center group ${state.type === t ? 'border-black' : 'border-stone-100'}`}>
              {t}
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className="opacity-0 group-hover:opacity-100 transition-opacity"><path d="m9 18 6-6-6-6"/></svg>
            </button>
          ))}
        </div>
        <button onClick={prevStep} className="w-full text-stone-400 font-bold py-2 border-t border-stone-100">Volver</button>
      </div>
    </div>
  );

  // Step 3: WHERE (LOCATION)
  const renderStep3 = () => (
    <div className="space-y-8 animate-in fade-in slide-in-from-right-4">
      {stepIndicator(3)}
      <div className="space-y-6">
        <h2 className="text-3xl font-bold text-black font-serif">3. Entorno Visual</h2>
        <p className="text-stone-500 font-medium">¿Dónde se situará la escena?</p>
        <div className="grid grid-cols-2 gap-3">
          {LOCATIONS.map(loc => (
            <button 
              key={loc} 
              onClick={() => { setState(prev => ({ ...prev, location: loc })); nextStep(); }} 
              className={`py-6 rounded-2xl border-2 font-bold transition-all px-4 text-center ${state.location === loc ? 'bg-black text-white border-black shadow-md' : 'bg-white text-stone-900 border-stone-100 hover:border-stone-300'}`}
            >
              {loc}
            </button>
          ))}
        </div>
        <button onClick={prevStep} className="w-full text-stone-400 font-bold py-2 border-t border-stone-100">Volver</button>
      </div>
    </div>
  );

  // Step 4: CONTEXT / STYLE
  const renderStep4 = () => (
    <div className="space-y-8 animate-in fade-in slide-in-from-right-4">
      {stepIndicator(4)}
      <div className="space-y-6">
        <h2 className="text-3xl font-bold text-black font-serif">4. Detalles Finales</h2>
        <div className="space-y-6">
          <div className="space-y-3">
            <label className="text-xs font-black text-stone-400 uppercase tracking-widest">Formato Publicitario</label>
            <div className="grid grid-cols-4 gap-2">
              {['1:1', '4:5', '9:16', '16:9'].map(r => (
                <button key={r} onClick={() => setRatio(r as AspectRatio)} className={`py-4 rounded-xl border-2 font-black text-xs transition-all ${ratio === r ? 'bg-black text-white border-black' : 'bg-white text-stone-900 border-stone-100'}`}>{r}</button>
              ))}
            </div>
          </div>
          <div className="space-y-3">
            <label className="text-xs font-black text-stone-400 uppercase tracking-widest">Matices de Atmósfera</label>
            <textarea value={state.contextText} onChange={(e) => setState(prev => ({ ...prev, contextText: e.target.value }))} className="w-full px-5 py-4 rounded-2xl border-2 border-stone-100 bg-white text-black placeholder-stone-300 outline-none h-32 font-medium focus:border-stone-400 transition-all shadow-sm" placeholder="Ej: Luz lateral cálida, sombras suaves, estilo bodegón clásico con uvas..." />
          </div>
        </div>
        <div className="flex gap-4">
           <button onClick={prevStep} className="flex-1 py-5 rounded-2xl border-2 border-stone-200 font-bold active:scale-95">Atrás</button>
           <button 
            disabled={loading} 
            onClick={startConceptGeneration} 
            className="flex-[2] py-5 bg-black text-white rounded-2xl font-bold shadow-xl active:scale-95 transition-all flex items-center justify-center gap-3 hover:bg-stone-900"
          >
            {loading && <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin" />}
            Idear Conceptos
          </button>
        </div>
      </div>
    </div>
  );

  // Step 5: PROPOSALS
  const renderStep5 = () => (
    <div className="space-y-8 animate-in fade-in scale-95 duration-500">
      {stepIndicator(5)}
      <h2 className="text-2xl font-serif font-bold text-black text-center">Propuestas del Director Creativo</h2>

      {loading ? (
        <div className="py-20 flex flex-col items-center justify-center space-y-6">
          <div className="w-16 h-16 border-4 border-stone-100 border-t-black rounded-full animate-spin" />
          <p className="font-medium text-stone-400">Generando ideas únicas...</p>
        </div>
      ) : error ? (
        <div className="py-20 text-center space-y-4">
          <p className="text-red-500 font-bold">{error}</p>
          <button onClick={startConceptGeneration} className="bg-black text-white px-8 py-3 rounded-xl font-bold">Reintentar</button>
        </div>
      ) : (
        <div className="space-y-4">
          {state.concepts.map((concept, idx) => (
            <div key={idx} className={`bg-white border-2 p-6 rounded-3xl shadow-sm transition-all ${state.editingConceptIndex === idx ? 'border-black ring-2 ring-black/5' : 'border-stone-100 hover:border-black'}`}>
              {state.editingConceptIndex === idx ? (
                <div className="space-y-4">
                  <textarea autoFocus value={editValue} onChange={(e) => setEditValue(e.target.value)} className="w-full px-4 py-3 border-2 border-stone-100 rounded-xl text-stone-900 bg-stone-50 outline-none h-32 font-medium" />
                  <div className="flex gap-2 justify-end">
                    <button onClick={() => setState(prev => ({ ...prev, editingConceptIndex: null }))} className="px-5 py-2 text-sm font-bold text-stone-500">Cancelar</button>
                    <button onClick={handleSaveEdit} className="bg-black text-white px-6 py-2 rounded-xl text-sm font-bold shadow-lg">Guardar</button>
                  </div>
                </div>
              ) : (
                <div className="space-y-4">
                  <p className="text-stone-900 font-medium italic text-lg leading-relaxed">"{concept}"</p>
                  <div className="flex justify-between items-center pt-2">
                    <button onClick={() => { setEditValue(concept); setState(prev => ({ ...prev, editingConceptIndex: idx })); }} className="text-stone-400 hover:text-black font-bold text-xs uppercase tracking-widest border-b border-transparent hover:border-black transition-all">Ajustar</button>
                    <button disabled={loading} onClick={() => selectAndGenerate(idx)} className="bg-black text-white px-8 py-3 rounded-xl font-bold active:scale-95 transition-all text-sm shadow-xl shadow-black/5">Generar Imagen</button>
                  </div>
                </div>
              )}
            </div>
          ))}
          <button onClick={startConceptGeneration} className="w-full py-5 border-2 border-dashed border-stone-200 text-stone-400 rounded-3xl font-bold hover:border-stone-400 hover:text-stone-600 transition-all mt-4">Proponer otros conceptos</button>
        </div>
      )}
      {!loading && <button onClick={prevStep} className="w-full text-stone-400 font-bold py-4">Atrás</button>}
    </div>
  );

  // Step 6: RESULT
  const renderStep6 = () => (
    <div className="space-y-8 animate-in zoom-in-95 duration-500">
      {loading ? (
        <div className="flex flex-col items-center justify-center py-32 space-y-8">
          <div className="w-20 h-20 border-4 border-stone-100 border-t-black rounded-full animate-spin" />
          <div className="text-center space-y-2">
            <h3 className="text-2xl font-bold text-black font-serif">Capturando Escena...</h3>
            <p className="text-stone-400 font-medium animate-pulse">Procesando iluminación y detalles del producto.</p>
          </div>
        </div>
      ) : error ? (
        <div className="py-24 text-center space-y-6">
          <div className="w-16 h-16 bg-red-50 text-red-500 rounded-full flex items-center justify-center mx-auto">
            <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" x2="12.01" y1="16" y2="16"/><path d="M12 8v4"/></svg>
          </div>
          <div className="space-y-2">
            <p className="text-red-500 font-bold text-lg">{error}</p>
            <p className="text-stone-400">Hubo un problema técnico durante la generación.</p>
          </div>
          <button onClick={() => selectAndGenerate(state.selectedConceptIndex!)} className="bg-black text-white px-10 py-4 rounded-2xl font-bold shadow-xl active:scale-95 transition-all">Reintentar Generación</button>
        </div>
      ) : state.imageHistory[0] ? (
        <div className="space-y-8">
          <div className="rounded-[2.5rem] overflow-hidden border border-stone-100 shadow-2xl bg-white aspect-square relative group">
            <img src={state.imageHistory[0]} alt="Final Result" className="w-full h-full object-cover" />
            <div className="absolute inset-0 bg-black/0 group-hover:bg-black/10 transition-colors pointer-events-none" />
          </div>

          <div className="bg-stone-50 p-6 rounded-2xl border border-stone-100 italic text-stone-700 font-medium text-center">
             "{state.concepts[state.selectedConceptIndex!]}"
          </div>

          <div className="grid grid-cols-3 gap-3">
            <button onClick={() => selectAndGenerate(state.selectedConceptIndex!)} className={btnSecondary}>Regenerar</button>
            <button onClick={() => setState(p => ({ ...p, step: 5 }))} className={btnSecondary}>Alternativas</button>
            <button onClick={() => handleDownload(state.imageHistory[0])} className="py-4 rounded-xl bg-black text-white font-bold px-4 shadow-lg shadow-black/10 active:scale-95 hover:bg-stone-900">Descargar</button>
          </div>

          <div className="pt-8 border-t border-stone-100 space-y-6">
            <h4 className="text-sm font-black text-stone-900 uppercase tracking-widest text-center">Ajustes Rápidos de Post-Producción</h4>
            <div className="flex flex-wrap justify-center gap-2">
              {["Más contraste", "Iluminación cenital", "Estilo vintage", "Fondo dramático oscuro", "Aclarar etiqueta"].map(s => (
                <button key={s} onClick={() => handleAdjustment(s)} className="px-5 py-2.5 rounded-full border border-stone-200 text-xs font-bold text-stone-900 bg-white hover:border-black active:scale-90 transition-all shadow-sm">{s}</button>
              ))}
            </div>
          </div>
        </div>
      ) : (
        <div className="py-24 text-center">
            <p className="text-stone-400">No hay resultados disponibles. Comienza de nuevo.</p>
            <button onClick={() => setState(prev => ({...prev, step: 1}))} className="mt-4 font-bold underline">Reiniciar proceso</button>
        </div>
      )}
    </div>
  );

  return (
    <div className="max-w-xl mx-auto pb-20">
      {state.step === 1 && renderStep1()}
      {state.step === 2 && renderStep2()}
      {state.step === 3 && renderStep3()}
      {state.step === 4 && renderStep4()}
      {state.step === 5 && renderStep5()}
      {state.step === 6 && renderStep6()}
    </div>
  );
};

