import React, { useState, useEffect, useCallback } from 'react';
import { Wine, ImageType, FunnelState, AspectRatio, GalleryImage } from '../types';
import { generateVisualConcepts, generateFinalImage } from '../services/geminiService';

interface CreativeFunnelProps {
  wines: Wine[];
  onFinish: () => void;
  onSaveToGallery: (img: GalleryImage) => void;
  initialData?: {
    wine: Wine;
    concept: string;
    isAdjustment?: boolean;
  };
}

const CreativeFunnel: React.FC<CreativeFunnelProps> = ({ wines, onFinish, onSaveToGallery, initialData }) => {
  const [selectedWine, setSelectedWine] = useState<Wine>(initialData?.wine || wines[0]);
  const [state, setState] = useState<FunnelState>({
    type: null,
    step: initialData ? 5 : 1,
    selections: {},
    contextText: '',
    concepts: initialData ? [initialData.concept] : [],
    selectedConceptIndex: initialData ? 0 : null,
    editingConceptIndex: null,
    imageHistory: []
  });

  const [ratio, setRatio] = useState<AspectRatio>('1:1');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [customAdjustment, setCustomAdjustment] = useState('');

  // Handle auto-generation for gallery-initiated tasks
  useEffect(() => {
    if (initialData && !initialData.isAdjustment && state.step === 5 && state.imageHistory.length === 0) {
      selectAndGenerate(0);
    }
  }, []);

  const setType = (type: ImageType) => setState(prev => ({ ...prev, type, step: 2, selections: {} }));
  const handleSelection = (key: string, value: string) => setState(prev => ({ ...prev, selections: { ...prev.selections, [key]: value } }));
  const nextStep = () => setState(prev => ({ ...prev, step: prev.step + 1 }));
  const prevStep = () => setState(prev => ({ ...prev, step: prev.step === 5 ? 4 : Math.max(1, prev.step - 1) }));

  const startConceptGeneration = async () => {
    setLoading(true);
    setError(null);
    try {
      const concepts = await generateVisualConcepts(selectedWine, state);
      setState(prev => ({ ...prev, concepts, step: 4 }));
    } catch (e) {
      setError("No se pudieron generar conceptos. Inténtalo de nuevo.");
    } finally {
      setLoading(false);
    }
  };

  const selectAndGenerate = async (index: number, adjustment?: string) => {
    if (loading) return;

    setLoading(true);
    setError(null);

    // Move to step 5 immediately to show loading state
    setState(prev => ({ ...prev, selectedConceptIndex: index, step: 5 }));

    try {
      // Use the index provided to ensure we get the correct concept even if state is updating
      const conceptToUse = state.concepts[index] || initialData?.concept || '';
      const img = await generateFinalImage(selectedWine, conceptToUse, ratio, adjustment);

      if (img) {
        // Update local state first to ensure the UI stays in Step 5
        setState(prev => ({ 
          ...prev, 
          imageHistory: [img, ...prev.imageHistory],
          step: 5 
        }));

        // Fire side effect to save to gallery
        const galleryItem: GalleryImage = {
          id: Date.now().toString(),
          url: img,
          concept: conceptToUse,
          wineName: selectedWine.name,
          timestamp: Date.now()
        };
        onSaveToGallery(galleryItem);
      } else {
        setError("La IA no devolvió ninguna imagen.");
      }
    } catch (e) {
      setError("Error durante la generación. Por favor, reintenta.");
    } finally {
      setLoading(false);
    }
