              {ratios.map(r => (
                <button
                  key={r}
                  onClick={() => setRatio(r)}
                  className={`py-3 rounded-lg border text-sm font-medium transition-all ${
                    ratio === r 
                    ? 'bg-black text-white border-black shadow-md' 
                    : 'bg-white text-stone-600 border-stone-200 hover:border-stone-400'
