import React, { Component, ErrorInfo, ReactNode } from 'react';

interface Props {
  children: ReactNode;
}

interface State {
  hasError: boolean;
}

class ErrorBoundary extends Component<Props, State> {
  public state: State = {
    hasError: false
  };

  public static getDerivedStateFromError(_: Error): State {
    return { hasError: true };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught error:", error, errorInfo);
  }

  public render() {
    if (this.state.hasError) {
      return (
        <div className="min-h-[60vh] flex flex-col items-center justify-center p-8 text-center space-y-6">
          <div className="w-20 h-20 bg-stone-100 rounded-full flex items-center justify-center text-stone-400">
            <svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
          </div>
          <div className="space-y-2">
            <h2 className="text-2xl font-serif font-bold text-black">Algo no ha salido como esperábamos</h2>
            <p className="text-stone-500 max-w-xs mx-auto">Se ha producido un error inesperado en la mesa de trabajo.</p>
          </div>
          <button 
            onClick={() => window.location.reload()} 
            className="bg-black text-white px-8 py-4 rounded-2xl font-bold shadow-xl active:scale-95 transition-all"
          >
            Reiniciar aplicación
          </button>
        </div>
      );
    }

    return this.props.children;
  }
}

export default ErrorBoundary;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import WineList from './components/WineList';
import WineForm from './components/WineForm';
import CreativeFunnel from './components/CreativeFunnel';
import Gallery from './components/Gallery';
import ErrorBoundary from './components/ErrorBoundary';
import { Wine, AppScreen, GalleryImage } from './types';

const App: React.FC = () => {
  const [screen, setScreen] = useState<AppScreen>(AppScreen.HOME);
  const [funnelKey, setFunnelKey] = useState(0);
  const [wines, setWines] = useState<Wine[]>(() => {
    const saved = localStorage.getItem('kinglab_wines_v2');
    return saved ? JSON.parse(saved) : [];
  });
  const [gallery, setGallery] = useState<GalleryImage[]>(() => {
    const saved = localStorage.getItem('kinglab_gallery_v3');
    return saved ? JSON.parse(saved) : [];
  });
  const [selectedWineForEdit, setSelectedWineForEdit] = useState<Wine | null>(null);
  const [funnelConfig, setFunnelConfig] = useState<{
    wine: Wine;
    concept: string;
    isAdjustment?: boolean;
  } | undefined>(undefined);

  useEffect(() => { localStorage.setItem('kinglab_wines_v2', JSON.stringify(wines)); }, [wines]);
  useEffect(() => { localStorage.setItem('kinglab_gallery_v3', JSON.stringify(gallery)); }, [gallery]);

  const handleSaveWine = (wine: Wine) => {
    setWines(prev => {
      const exists = prev.find(w => w.id === wine.id);
      if (exists) return prev.map(w => w.id === wine.id ? wine : w);
      return [wine, ...prev];
    });
    setScreen(AppScreen.HOME);
    setSelectedWineForEdit(null);
  };

  const handleBack = () => {
    if (screen === AppScreen.FORM) setScreen(wines.length === 0 ? AppScreen.HOME : AppScreen.MANAGE);
    else setScreen(AppScreen.HOME);
    setSelectedWineForEdit(null);
    setFunnelConfig(undefined);
  };

  const startNewSession = () => {
    setFunnelConfig(undefined);
    setFunnelKey(prev => prev + 1);
    setScreen(AppScreen.FUNNEL);
  };

  const startFromGallery = (img: GalleryImage, isAdjustment: boolean) => {
    const wine = wines.find(w => w.name === img.wineName);
    if (wine) {
      setFunnelConfig({ wine, concept: img.concept, isAdjustment });
      setFunnelKey(prev => prev + 1);
      setScreen(AppScreen.FUNNEL);
    }
  };

  const getTitle = () => {
    if (screen === AppScreen.HOME) return 'Kinglab Bodegas 202';
    if (screen === AppScreen.FUNNEL) return 'Nueva Idea Creativa';
    if (screen === AppScreen.MANAGE) return 'Gestionar Vinos';
    if (screen === AppScreen.GALLERY) return 'Galería';
    if (screen === AppScreen.FORM) return selectedWineForEdit ? 'Editar Vino' : 'Añadir Vino';
    return screen;
  };

  return (
    <ErrorBoundary>
      <Layout 
        title={getTitle()} 
        onBack={screen !== AppScreen.HOME ? handleBack : undefined}
        onGear={() => setScreen(AppScreen.MANAGE)}
        onGallery={() => setScreen(AppScreen.GALLERY)}
        showGear={wines.length > 0}
        showGallery={gallery.length > 0}
      >
        {screen === AppScreen.HOME && (
          wines.length === 0 ? (
            <div className="flex flex-col items-center justify-center h-full py-24 text-center space-y-10 animate-in fade-in duration-700">
              <div className="space-y-3 px-8">
                <h2 className="text-5xl font-serif font-bold text-black">Kinglab</h2>
                <p className="text-stone-400 font-medium italic text-lg leading-relaxed">Asistente de dirección de arte profesional para el sector vinícola.</p>
              </div>
              <button onClick={() => setScreen(AppScreen.FORM)} className="bg-black text-white px-12 py-6 rounded-full font-bold shadow-2xl active:scale-90 transition-all text-xl">
                Dar de alta un vino
              </button>
            </div>
          ) : (
            <div className="space-y-12 py-10">
              <div className="bg-white p-12 rounded-[2.5rem] border-2 border-stone-100 text-center space-y-8 shadow-sm">
                <div className="w-16 h-16 bg-stone-50 rounded-full flex items-center justify-center mx-auto text-black border border-stone-100">
                  <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2v20"/><path d="M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/></svg>
                </div>
                <div className="space-y-3">
                  <h3 className="text-3xl font-serif font-bold">Mesa de Trabajo</h3>
                  <p className="text-stone-400 font-medium text-lg">Inicia una sesión de dirección creativa para tus productos.</p>
                </div>
                <button onClick={startNewSession} className="w-full bg-black text-white px-8 py-6 rounded-3xl font-bold shadow-2xl active:scale-95 transition-all text-xl">
                  Comenzar proceso
                </button>
              </div>
              {gallery.length > 0 && (
                <div className="space-y-6">
                  <div className="flex justify-between items-end px-4">
                    <h4 className="font-serif font-bold text-2xl text-black">Recientes</h4>
                    <button onClick={() => setScreen(AppScreen.GALLERY)} className="text-black font-black text-[10px] uppercase tracking-widest border-b-2 border-black pb-1 active:opacity-50">Explorar todo</button>
                  </div>
                  <div className="grid grid-cols-2 gap-4">
                    {gallery.slice(0, 4).map(img => (
                      <div key={img.id} onClick={() => setScreen(AppScreen.GALLERY)} className="aspect-square rounded-3xl overflow-hidden border border-stone-100 shadow-sm cursor-pointer active:scale-95 transition-all">
                        <img src={img.url} className="w-full h-full object-cover" alt={img.wineName} />
                      </div>
                    ))}
                  </div>
                </div>
              )}
            </div>
          )
        )}

        {screen === AppScreen.FUNNEL && wines.length > 0 && (
          <CreativeFunnel 
            key={funnelKey}
            wines={wines} 
            onFinish={() => setScreen(AppScreen.HOME)} 
            onSaveToGallery={(img) => setGallery(prev => [img, ...prev])} 
            initialData={funnelConfig} 
          />
        )}

        {screen === AppScreen.GALLERY && (
          <Gallery images={gallery} onBack={() => setScreen(AppScreen.HOME)} onRegenerate={(img) => startFromGallery(img, false)} onAdjust={(img) => startFromGallery(img, true)} />
        )}

        {screen === AppScreen.MANAGE && (
          <WineList wines={wines} onEdit={(w) => { setSelectedWineForEdit(w); setScreen(AppScreen.FORM); }} onAdd={() => { setSelectedWineForEdit(null); setScreen(AppScreen.FORM); }} />
        )}

        {screen === AppScreen.FORM && (
          <WineForm initialWine={selectedWineForEdit || undefined} onSave={handleSaveWine} />
        )}
      </Layout>
    </ErrorBoundary>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { Wine, ImageType, FunnelState, AspectRatio, GalleryImage } from '../types';
import { generateVisualConcepts, generateFinalImage } from '../services/geminiService';

interface CreativeFunnelProps {
  wines: Wine[];
  onFinish: () => void;
  onSaveToGallery: (img: GalleryImage) => void;
  initialData?: {
    wine: Wine;
    concept: string;
    isAdjustment?: boolean;
  };
}

const CreativeFunnel: React.FC<CreativeFunnelProps> = ({ wines, onFinish, onSaveToGallery, initialData }) => {
  const [selectedWine, setSelectedWine] = useState<Wine>(initialData?.wine || wines[0]);

  const [state, setState] = useState<FunnelState>({
    type: null,
    step: initialData ? 5 : 1,
    selections: {},
    contextText: '',
    concepts: initialData ? [initialData.concept] : [],
    selectedConceptIndex: initialData ? 0 : null,
    editingConceptIndex: null,
    imageHistory: [],
    isLoading: false,
    error: null
  });

  const [ratio, setRatio] = useState<AspectRatio>('1:1');
  const [customAdjustment, setCustomAdjustment] = useState('');
  const [editValue, setEditValue] = useState('');

  // Top-level hooks strictly at the top level to avoid hook violations (Error #310)
  const conceptText = useMemo(() => {
    if (state.selectedConceptIndex !== null && state.concepts[state.selectedConceptIndex]) {
      return state.concepts[state.selectedConceptIndex];
    }
    return initialData?.concept || state.concepts[0] || "Captura publicitaria profesional.";
  }, [state.selectedConceptIndex, state.concepts, initialData]);

  // Auto-trigger generation if coming from gallery (not for adjustments)
  useEffect(() => {
    if (initialData && !initialData.isAdjustment && state.step === 5 && state.imageHistory.length === 0 && !state.isLoading) {
      selectAndGenerate(0);
    }
  }, []);

  const setType = (type: ImageType) => setState(prev => ({ ...prev, type, step: 2, selections: {} }));

  const handleSelection = (key: string, value: string) => 
    setState(prev => ({ ...prev, selections: { ...prev.selections, [key]: value } }));

  const nextStep = () => setState(prev => ({ ...prev, step: prev.step + 1 }));

  const prevStep = () => setState(prev => ({ 
    ...prev, 
    error: null,
    step: prev.step === 5 ? 4 : Math.max(1, prev.step - 1) 
  }));

  const startConceptGeneration = async () => {
    setState(prev => ({ ...prev, isLoading: true, error: null }));
    try {
      const concepts = await generateVisualConcepts(selectedWine, state);
      setState(prev => ({ 
        ...prev, 
        concepts: (Array.isArray(concepts) && concepts.length > 0) ? concepts : prev.concepts, 
        step: 4, 
        editingConceptIndex: null,
        isLoading: false
      }));
    } catch (e) {
      setState(prev => ({ ...prev, error: "No se pudieron generar conceptos.", isLoading: false }));
    }
  };

  const selectAndGenerate = async (index: number, adjustment?: string) => {
    if (state.isLoading) return;

    // Set loading and step atomically
    setState(prev => ({ ...prev, isLoading: true, error: null, selectedConceptIndex: index, step: 5 }));

    try {
      const conceptToUse = state.concepts[index] || (index === 0 ? initialData?.concept : '') || '';
      const img = await generateFinalImage(selectedWine, String(conceptToUse), ratio, adjustment);

      if (img) {
        setState(prev => ({ 
          ...prev, 
          imageHistory: [img, ...prev.imageHistory],
          isLoading: false,
          error: null
        }));

        const galleryItem: GalleryImage = {
          id: Date.now().toString(),
          url: img,
          concept: String(conceptToUse),
          wineName: selectedWine.name,
          timestamp: Date.now()
        };
        onSaveToGallery(galleryItem);
      } else {
        setState(prev => ({ ...prev, error: "La IA no devolvió ninguna imagen.", isLoading: false }));
      }
    } catch (e) {
      console.error("Funnel Generation Error:", e);
      setState(prev => ({ ...prev, error: "Error crítico durante la generación.", isLoading: false }));
    }
  };

  const startEdit = (idx: number, concept: string) => {
    setEditValue(concept);
    setState(prev => ({ ...prev, editingConceptIndex: idx }));
  };

  const handleSaveEdit = () => {
    if (state.editingConceptIndex !== null) {
      const newConcepts = [...state.concepts];
      newConcepts[state.editingConceptIndex] = editValue;
      setState(prev => ({ ...prev, concepts: newConcepts, editingConceptIndex: null }));
      setEditValue('');
    }
  };

  const handleAdjustment = (adj: string) => {
    if (state.selectedConceptIndex !== null) {
      selectAndGenerate(state.selectedConceptIndex, adj);
    }
  };

  const handleDownload = (imgUrl: string) => {
    const link = document.createElement('a');
    link.href = imgUrl;
    link.download = `kinglab_${selectedWine.name.toLowerCase().replace(/\s/g, '_')}_${Date.now()}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const btnSecondary = "py-4 rounded-xl border border-stone-300 bg-white text-stone-900 font-bold hover:border-black active:bg-stone-50 transition-all text-center px-4";
  const btnPrimary = "w-full py-5 bg-black text-white rounded-2xl font-bold shadow-xl shadow-black/10 active:scale-95 transition-all text-lg flex items-center justify-center gap-3";

  const renderStep1 = () => (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4">
      <div className="space-y-3">
        <label className="text-sm font-bold text-stone-800 uppercase tracking-wide">Seleccionar vino</label>
        <select 
