import { GoogleGenAI, Type } from "@google/genai";
import { Wine, ImageType, FunnelState, AnalysisResult } from "../types";

const MODEL_TEXT = 'gemini-3-flash-preview';
const MODEL_IMAGE = 'gemini-2.5-flash-image';

export const analyzePublicPerception = async (wineName: string): Promise<AnalysisResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Analiza la percepción pública actual en internet del vino o bodega "${wineName}". 
  Busca en redes sociales, foros, prensa especializada y reseñas de usuarios. 
  IMPORTANTE: No utilices información del sitio web oficial de la bodega ni de sus canales propios. 
  Queremos saber qué dice el público "fuera de casa".

  Devuelve el resultado en JSON con:
  1. "summary": Un resumen de exactamente dos párrafos (aprox 100 palabras en total) en español.
  2. "fullReport": Un informe detallado y extenso que incluya tendencias, críticas recurrentes y elogios comunes.`;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_TEXT,
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            summary: { type: Type.STRING },
            fullReport: { type: Type.STRING }
          },
          required: ["summary", "fullReport"]
        }
      }
    });

    const data = JSON.parse(response.text || '{}');
    return {
      summary: data.summary || "No se encontró suficiente información externa relevante para este vino.",
      fullReport: data.fullReport || "Informe detallado no disponible."
    };
  } catch (error) {
    console.error("Error analyzing perception:", error);
    return {
      summary: "Error al conectar con las fuentes de datos externas.",
      fullReport: "No se pudo generar el informe."
    };
  }
};

export const generateVisualConcepts = async (state: FunnelState): Promise<string[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `
    Eres un Director Creativo experto para Kinglab Bodegas 202.
    Genera 3 conceptos visuales distintos basándote en esta conversación creativa:

    - Vino: ${state.wineName}
    - Público: ${state.audience}
    - Especial: ${state.specialFeatures}
    - Análisis de Mercado: ${state.useAnalysis ? state.analysis?.summary : 'No utilizado'}
    - Tipo de Imagen: ${state.type}
    - Estilo: ${state.style} (${state.styleDetail})
    - Lugar: ${state.location}
    - Momento/Tiempo: ${state.timeContext}

    REGLAS:
    - Conceptos en ESPAÑOL.
    - Cada uno debe ser un párrafo de 30-40 palabras.
    - Lenguaje editorial, elegante y descriptivo.
    - Deben ser realistas para fotografía publicitaria.
  `;

  try {
    const response = await ai.models.generateContent({
      model: MODEL_TEXT,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            concepts: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          },
          required: ["concepts"]
        }
      }
    });

    const data = JSON.parse(response.text || '{}');
    return data.concepts || [];
  } catch (error) {
    console.error("Error generating concepts:", error);
    return ["Concepto clásico de alta gama", "Composición moderna minimalista", "Escena natural y cálida"];
  }
};

export const generateFinalImage = async (
  wineImage: string | null,
  state: FunnelState,
  concept: string,
  ratio: string
): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  let parts: any[] = [];

  if (wineImage) {
    const base64Data = wineImage.split(',')[1];
    const mimeType = wineImage.split(';')[0].split(':')[1];
    parts.push({ inlineData: { data: base64Data, mimeType } });
  }

  if (state.locationImage) {
    const base64Loc = state.locationImage.split(',')[1];
    const mimeLoc = state.locationImage.split(';')[0].split(':')[1];
    parts.push({ inlineData: { data: base64Loc, mimeType: mimeLoc } });
  }

  const prompt = `
    Fotografía publicitaria profesional de alta gama.
    PRODUCTO: ${state.wineName}
    CONCEPTO: ${concept}
    ESTILO VISUAL: ${state.style}, ${state.styleDetail}.
    CONTEXTO: ${state.timeContext} en ${state.location}.

    Si se proporciona una imagen de producto, mantén la botella y la etiqueta reconocibles.
    Si se proporciona una imagen de lugar, úsala como referencia de ambiente.
    La imagen final debe ser cohesiva, elegante y lista para una revista de lujo.
  `;

  parts.push({ text: prompt });

  try {
    const response = await ai.models.generateContent({
      model: MODEL_IMAGE,
      contents: { parts },
      config: {
        imageConfig: {
          aspectRatio: ratio as any
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Error generating image:", error);
    throw error;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Wine, ImageType, FunnelState, AspectRatio, GalleryImage } from '../types';
import { analyzePublicPerception, generateVisualConcepts, generateFinalImage } from '../services/geminiService';

interface CreativeFunnelProps {
  wines: Wine[];
  onFinish: () => void;
  onSaveToGallery: (img: GalleryImage) => void;
}

const CreativeFunnel: React.FC<CreativeFunnelProps> = ({ wines, onFinish, onSaveToGallery }) => {
  const [state, setState] = useState<FunnelState>({
    step: 1,
    wineName: '',
    audience: '',
    specialFeatures: '',
    useAnalysis: null,
    analysis: null,
    type: null,
    style: '',
    styleDetail: '',
    location: '',
    locationImage: null,
    timeContext: '',
    concepts: [],
    selectedConceptIndex: null,
    imageHistory: [],
    isLoading: false,
    error: null,
    feedback: null
  });

  const [input, setInput] = useState('');
  const locInputRef = useRef<HTMLInputElement>(null);

  const nextStep = () => setState(prev => ({ ...prev, step: prev.step + 1 }));
  const goToStep = (s: number) => setState(prev => ({ ...prev, step: s }));

  const handleInputSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    switch (state.step) {
      case 1: setState(prev => ({ ...prev, wineName: input, step: 2 })); break;
      case 2: setState(prev => ({ ...prev, audience: input, step: 3 })); break;
      case 3: setState(prev => ({ ...prev, specialFeatures: input, step: 4 })); break;
      case 7: setState(prev => ({ ...prev, styleDetail: input, step: 8 })); break;
      case 9: setState(prev => ({ ...prev, location: input, step: 10 })); break;
      case 11: setState(prev => ({ ...prev, timeContext: input, step: 12 })); break;
    }
    setInput('');
  };

  const handleAnalysis = async (choice: boolean) => {
    if (choice) {
      setState(prev => ({ ...prev, isLoading: true }));
      const result = await analyzePublicPerception(state.wineName);
      setState(prev => ({ ...prev, analysis: result, isLoading: false, step: 5 }));
    } else {
      setState(prev => ({ ...prev, useAnalysis: false, step: 6 }));
    }
  };

  const handleAnalysisConfirmation = (confirm: boolean) => {
    setState(prev => ({ ...prev, useAnalysis: confirm, step: 6 }));
  };

  const downloadReport = () => {
    if (!state.analysis) return;
    const blob = new Blob([state.analysis.fullReport], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `Informe_Mercado_${state.wineName.replace(/\s/g, '_')}.txt`;
    a.click();
    URL.revokeObjectURL(url);
  };

  const handleLocationImage = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setState(prev => ({ ...prev, locationImage: reader.result as string, step: 11 }));
      reader.readAsDataURL(file);
    }
  };

  const generateConcepts = async () => {
    setState(prev => ({ ...prev, isLoading: true, error: null }));
    const concepts = await generateVisualConcepts(state);
    setState(prev => ({ ...prev, concepts, step: 13, isLoading: false }));
  };

  const generateImage = async (index: number) => {
    setState(prev => ({ ...prev, isLoading: true, selectedConceptIndex: index, step: 14 }));
    try {
      // Find reference wine image if it exists in local storage list
      const refWine = wines.find(w => w.name.toLowerCase() === state.wineName.toLowerCase());
      const result = await generateFinalImage(refWine?.image || null, state, state.concepts[index], '1:1');
      if (result) {
        setState(prev => ({ ...prev, imageHistory: [result, ...prev.imageHistory], isLoading: false }));
        onSaveToGallery({
          id: Date.now().toString(),
          url: result,
          concept: state.concepts[index],
          wineName: state.wineName,
          timestamp: Date.now()
        });
      } else {
        setState(prev => ({ ...prev, error: "No se pudo generar la imagen.", isLoading: false }));
      }
    } catch (e) {
      setState(prev => ({ ...prev, error: "Error de conexión con el motor de arte.", isLoading: false }));
    }
  };

  const handleFeedback = (type: 'like' | 'dislike') => {
    setState(prev => ({ ...prev, feedback: type }));
    // In a real app, we would save this to a backend for training
  };

  const renderBubble = (text: string, isUser = false) => (
    <div className={`flex ${isUser ? 'justify-end' : 'justify-start'} animate-in fade-in slide-in-from-${isUser ? 'right' : 'left'}-4 duration-500`}>
      <div className={`max-w-[85%] p-4 rounded-2xl ${isUser ? 'bg-black text-white rounded-tr-none' : 'bg-stone-100 text-stone-800 rounded-tl-none'} text-lg font-medium shadow-sm`}>
        {text}
      </div>
    </div>
  );

  const renderCurrentStep = () => {
    if (state.isLoading) {
      return (
        <div className="flex flex-col items-center justify-center py-20 space-y-6 animate-pulse">
          <div className="w-12 h-12 border-4 border-stone-200 border-t-black rounded-full animate-spin" />
          <p className="text-stone-500 font-serif text-xl italic">Kinglab está pensando...</p>
        </div>
      );
    }

    switch (state.step) {
      case 1: return (
        <div className="space-y-6">
          {renderBubble("¡Hola! Soy tu asistente creativo. Para empezar, ¿en qué vino o bodega quieres trabajar hoy?")}
          <form onSubmit={handleInputSubmit} className="flex gap-2">
            <input autoFocus value={input} onChange={e => setInput(e.target.value)} placeholder="Nombre del vino..." className="flex-1 p-4 rounded-xl border-2 border-stone-100 focus:border-black outline-none transition-all" />
            <button type="submit" className="p-4 bg-black text-white rounded-xl active:scale-95 transition-all"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m5 12 7-7 7 7"/><path d="M12 19V5"/></svg></button>
          </form>
        </div>
      );
      case 2: return (
        <div className="space-y-6">
          {renderBubble(state.wineName, true)}
          {renderBubble("Perfecto. ¿Para quién va dirigido este vino? (Háblame de su público ideal)")}
          <form onSubmit={handleInputSubmit} className="flex gap-2">
            <input autoFocus value={input} onChange={e => setInput(e.target.value)} placeholder="Ej: Jóvenes urbanos, coleccionistas..." className="flex-1 p-4 rounded-xl border-2 border-stone-100 focus:border-black outline-none transition-all" />
            <button type="submit" className="p-4 bg-black text-white rounded-xl"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m5 12 7-7 7 7"/><path d="M12 19V5"/></svg></button>
          </form>
        </div>
      );
      case 3: return (
        <div className="space-y-6">
          {renderBubble(state.audience, true)}
          {renderBubble("Entendido. ¿Qué hace especial a este vino? ¿Alguna nota de cata o rasgo artesanal?")}
          <form onSubmit={handleInputSubmit} className="flex gap-2">
            <input autoFocus value={input} onChange={e => setInput(e.target.value)} placeholder="Notas, crianza, suelo..." className="flex-1 p-4 rounded-xl border-2 border-stone-100 focus:border-black outline-none transition-all" />
            <button type="submit" className="p-4 bg-black text-white rounded-xl"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m5 12 7-7 7 7"/><path d="M12 19V5"/></svg></button>
          </form>
        </div>
      );
      case 4: return (
        <div className="space-y-6">
          {renderBubble(state.specialFeatures, true)}
          {renderBubble("¿Quieres que analicemos la percepción pública de este vino en internet antes de seguir?")}
          <div className="grid grid-cols-2 gap-3">
            <button onClick={() => handleAnalysis(true)} className="p-4 bg-black text-white rounded-xl font-bold active:scale-95 transition-all shadow-lg">Analizar mercado</button>
            <button onClick={() => handleAnalysis(false)} className="p-4 bg-white border-2 border-stone-100 text-stone-600 rounded-xl font-bold active:scale-95 transition-all">No, gracias</button>
          </div>
        </div>
      );
      case 5: return (
        <div className="space-y-6">
          {renderBubble("He analizado lo que se dice fuera de tus canales oficiales:")}
          <div className="bg-stone-50 p-6 rounded-2xl border border-stone-100 space-y-4 shadow-sm animate-in zoom-in-95">
            <p className="text-stone-800 leading-relaxed italic">{state.analysis?.summary}</p>
            <div className="flex flex-col gap-2">
              <button onClick={downloadReport} className="text-black text-xs font-black uppercase tracking-widest flex items-center gap-2 hover:opacity-70">
                <svg xmlns="http://www.w3.org/2000/svg" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M21 15v4a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2v-4"/><polyline points="7 10 12 15 17 10"/><line x1="12" x2="12" y1="15" y2="3"/></svg>
                Descargar Informe Completo (.txt)
              </button>
            </div>
          </div>
          {renderBubble("¿Quieres que tengamos en cuenta este análisis para la dirección creativa?")}
          <div className="grid grid-cols-2 gap-3">
            <button onClick={() => handleAnalysisConfirmation(true)} className="p-4 bg-black text-white rounded-xl font-bold">Tenerlo en cuenta</button>
            <button onClick={() => handleAnalysisConfirmation(false)} className="p-4 bg-white border-2 border-stone-100 text-stone-600 rounded-xl font-bold">Descartarlo</button>
          </div>
        </div>
      );
      case 6: return (
        <div className="space-y-6">
          {renderBubble(state.useAnalysis ? "Usaremos el análisis." : "Continuamos sin el análisis.", true)}
          {renderBubble("¿Qué tipo de imagen tienes en mente?")}
          <div className="grid grid-cols-1 gap-2">
            {Object.values(ImageType).map(t => (
              <button key={t} onClick={() => setState(prev => ({ ...prev, type: t, step: 7 }))} className="p-5 text-left bg-white border-2 border-stone-100 rounded-2xl font-bold hover:border-black transition-all flex justify-between items-center group">
                {t}
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round" className="opacity-0 group-hover:opacity-100 transition-opacity"><path d="m9 18 6-6-6-6"/></svg>
              </button>
            ))}
          </div>
        </div>
      );
      case 7: return (
        <div className="space-y-6">
          {renderBubble(state.type || '', true)}
          {renderBubble("¿Qué estilo visual prefieres?")}
          <div className="grid grid-cols-2 gap-2">
            {["Minimalista", "Editorial", "Natural", "Lujoso", "Cotidiano"].map(s => (
              <button key={s} onClick={() => {
                if (s === 'Minimalista') goToStep(9);
                else setState(prev => ({ ...prev, style: s, step: 8 }));
              }} className="p-4 bg-white border-2 border-stone-100 rounded-xl font-bold hover:border-black transition-all">
                {s}
              </button>
            ))}
          </div>
        </div>
      );
      case 8: return (
        <div className="space-y-6">
          {renderBubble(state.style, true)}
          {renderBubble("¿Algún detalle específico sobre el estilo? (Luz, sombras, elementos)")}
          <form onSubmit={handleInputSubmit} className="flex gap-2">
            <input autoFocus value={input} onChange={e => setInput(e.target.value)} placeholder="Ej: Luz suave de atardecer..." className="flex-1 p-4 rounded-xl border-2 border-stone-100 focus:border-black outline-none transition-all" />
            <button type="submit" className="p-4 bg-black text-white rounded-xl"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m5 12 7-7 7 7"/><path d="M12 19V5"/></svg></button>
          </form>
        </div>
      );
      case 9: return (
        <div className="space-y-6">
          {renderBubble("¿Muy minimalista o con algunos elementos?")}
          <div className="grid grid-cols-2 gap-3">
            <button onClick={() => setState(prev => ({ ...prev, style: 'Minimalista', styleDetail: 'Extremo, sin elementos extra', step: 10 }))} className="p-4 bg-black text-white rounded-xl font-bold">Muy minimal</button>
            <button onClick={() => setState(prev => ({ ...prev, style: 'Minimalista', styleDetail: 'Con elementos de apoyo sutiles', step: 8 }))} className="p-4 bg-white border-2 border-stone-100 text-stone-600 rounded-xl font-bold">Con elementos</button>
          </div>
        </div>
      );
      case 10: return (
        <div className="space-y-6">
          {renderBubble("¿Dónde ocurre la escena?")}
          <div className="grid grid-cols-2 gap-2">
            {["Viñedo", "Bodega", "Restaurante", "Casa", "Estudio"].map(loc => (
              <button key={loc} onClick={() => setState(prev => ({ ...prev, location: loc, step: 11 }))} className="p-4 bg-white border-2 border-stone-100 rounded-xl font-bold hover:border-black">
                {loc}
              </button>
            ))}
          </div>
          <p className="text-center text-stone-400 text-xs font-bold uppercase tracking-widest pt-4">O escribe tu propia ubicación</p>
          <form onSubmit={handleInputSubmit} className="flex gap-2">
            <input value={input} onChange={e => setInput(e.target.value)} placeholder="Otra ubicación..." className="flex-1 p-4 rounded-xl border-2 border-stone-100 focus:border-black outline-none transition-all" />
            <button type="submit" className="p-4 bg-black text-white rounded-xl"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m5 12 7-7 7 7"/><path d="M12 19V5"/></svg></button>
          </form>
        </div>
      );
      case 11: return (
        <div className="space-y-6">
          {renderBubble(state.location, true)}
          {renderBubble("¿Quieres subir una imagen de referencia para la ubicación? (Opcional)")}
          <div className="flex flex-col gap-3">
            {state.locationImage && <img src={state.locationImage} className="w-full h-40 object-cover rounded-2xl border" />}
            <input type="file" className="hidden" ref={locInputRef} onChange={handleLocationImage} accept="image/*" />
            <div className="grid grid-cols-2 gap-3">
              <button onClick={() => locInputRef.current?.click()} className="p-4 bg-stone-100 text-stone-800 rounded-xl font-bold flex items-center justify-center gap-2">
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect width="18" height="18" x="3" y="3" rx="2" ry="2"/><circle cx="9" cy="9" r="2"/><path d="m21 15-3.086-3.086a2 2 0 0 0-2.828 0L6 21"/></svg>
                Subir referencia
              </button>
              <button onClick={() => goToStep(12)} className="p-4 bg-black text-white rounded-xl font-bold">Omitir</button>
            </div>
          </div>
        </div>
      );
      case 12: return (
        <div className="space-y-6">
          {renderBubble("Por último, ¿cuándo ocurre la escena? Sugerencias:")}
          <div className="flex flex-wrap gap-2">
            {["Vendimia", "Cena con amigos", "Atardecer de verano", "Regalo de navidad", "San Valentín"].map(t => (
              <button key={t} onClick={() => setState(prev => ({ ...prev, timeContext: t, step: 13 }))} className="px-4 py-2 bg-stone-50 border border-stone-200 rounded-full text-sm font-bold text-stone-600 hover:border-black">
                {t}
              </button>
            ))}
          </div>
          <form onSubmit={handleInputSubmit} className="flex gap-2 pt-4">
            <input autoFocus value={input} onChange={e => setInput(e.target.value)} placeholder="Cualquier otro momento..." className="flex-1 p-4 rounded-xl border-2 border-stone-100 focus:border-black outline-none transition-all" />
            <button type="submit" className="p-4 bg-black text-white rounded-xl"><svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m5 12 7-7 7 7"/><path d="M12 19V5"/></svg></button>
          </form>
          <div className="pt-8">
            <button onClick={generateConcepts} className="w-full py-5 bg-black text-white rounded-2xl font-bold shadow-2xl shadow-black/20 flex items-center justify-center gap-3 animate-bounce">
              <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m12 3-1.912 5.813a2 2 0 0 1-1.275 1.275L3 12l5.813 1.912a2 2 0 0 1 1.275 1.275L12 21l1.912-5.813a2 2 0 0 1 1.275-1.275L21 12l-5.813-1.912a2 2 0 0 1-1.275-1.275L12 3Z"/></svg>
              Finalizar Dirección Creativa
            </button>
          </div>
        </div>
      );
      case 13: return (
        <div className="space-y-8 animate-in zoom-in-95 duration-500">
          <h2 className="text-2xl font-serif font-bold text-black text-center">Propuestas de Dirección</h2>
          <div className="space-y-4">
            {state.concepts.map((concept, idx) => (
              <button key={idx} onClick={() => generateImage(idx)} className="w-full text-left bg-white border-2 border-stone-100 p-6 rounded-3xl hover:border-black transition-all shadow-sm active:scale-95">
                <p className="text-stone-900 font-medium italic text-lg leading-relaxed">"{concept}"</p>
                <div className="mt-4 text-xs font-black uppercase tracking-widest text-stone-400">Seleccionar este concepto</div>
              </button>
            ))}
            <button onClick={generateConcepts} className="w-full py-4 border-2 border-dashed border-stone-200 text-stone-400 font-bold rounded-2xl hover:text-black hover:border-black">Generar otras ideas</button>
          </div>
        </div>
      );
      case 14: return (
        <div className="space-y-8 animate-in fade-in duration-700 pb-20">
          <div className="relative group overflow-hidden rounded-[2.5rem] border border-stone-200 shadow-2xl bg-white aspect-square">
            <img src={state.imageHistory[0]} alt="Result" className="w-full h-full object-cover" />
          </div>

          <div className="bg-stone-50 p-6 rounded-3xl border border-stone-100 italic text-stone-700 font-medium text-center shadow-inner">
            "{state.concepts[state.selectedConceptIndex || 0]}"
          </div>

          <div className="flex flex-col gap-4">
            <div className="flex items-center justify-center gap-6">
               <button onClick={() => handleFeedback('like')} className={`p-4 rounded-full transition-all ${state.feedback === 'like' ? 'bg-green-100 text-green-600 scale-110' : 'bg-stone-100 text-stone-400'}`}>
                 <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M7 10v12"/><path d="M15 5.88 14 10h5.83a2 2 0 0 1 1.92 2.56l-2.33 8A2 2 0 0 1 17.5 22H4a2 2 0 0 1-2-2v-8a2 2 0 0 1 2-2h2.76a2 2 0 0 0 1.79-1.11L12 2h0a3.13 3.13 0 0 1 3 3.88Z"/></svg>
               </button>
               <button onClick={() => handleFeedback('dislike')} className={`p-4 rounded-full transition-all ${state.feedback === 'dislike' ? 'bg-red-100 text-red-600 scale-110' : 'bg-stone-100 text-stone-400'}`}>
                 <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M17 14V2"/><path d="M9 18.12 10 14H4.17a2 2 0 0 1-1.92-2.56l2.33-8A2 2 0 0 1 6.5 2H20a2 2 0 0 1 2 2v8a2 2 0 0 1-2 2h-2.76a2 2 0 0 0-1.79 1.11L12 22h0a3.13 3.13 0 0 1-3-3.88Z"/></svg>
               </button>
            </div>

            <button onClick={onFinish} className="w-full py-5 bg-black text-white rounded-2xl font-bold shadow-xl shadow-black/10 active:scale-95 transition-all">Finalizar y Guardar</button>
            <button onClick={() => goToStep(13)} className="w-full py-4 text-stone-400 font-bold hover:text-black">Volver a propuestas</button>
          </div>
        </div>
      );
      default: return null;
    }
  };

  return (
    <div className="max-w-xl mx-auto pb-10">
      {renderCurrentStep()}
      {state.error && (
        <div className="mt-6 p-4 bg-red-50 text-red-600 rounded-xl font-bold text-center border border-red-100">
          {state.error}
        </div>
      )}
    </div>
  );
};

export default CreativeFunnel;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import WineList from './components/WineList';
import WineForm from './components/WineForm';
import CreativeFunnel from './components/CreativeFunnel';
import Gallery from './components/Gallery';
import ErrorBoundary from './components/ErrorBoundary';
import { Wine, AppScreen, GalleryImage } from './types';

const App: React.FC = () => {
  const [screen, setScreen] = useState<AppScreen>(AppScreen.HOME);
  const [funnelKey, setFunnelKey] = useState(0);
  const [wines, setWines] = useState<Wine[]>(() => {
    const saved = localStorage.getItem('kinglab_wines_v3');
    return saved ? JSON.parse(saved) : [];
  });
  const [gallery, setGallery] = useState<GalleryImage[]>(() => {
    const saved = localStorage.getItem('kinglab_gallery_v4');
    return saved ? JSON.parse(saved) : [];
  });
  const [selectedWineForEdit, setSelectedWineForEdit] = useState<Wine | null>(null);

  useEffect(() => { localStorage.setItem('kinglab_wines_v3', JSON.stringify(wines)); }, [wines]);
  useEffect(() => { localStorage.setItem('kinglab_gallery_v4', JSON.stringify(gallery)); }, [gallery]);

  const handleSaveWine = (wine: Wine) => {
    setWines(prev => {
      const exists = prev.find(w => w.id === wine.id);
      if (exists) return prev.map(w => w.id === wine.id ? wine : w);
      return [wine, ...prev];
    });
    setScreen(AppScreen.HOME);
    setSelectedWineForEdit(null);
  };

  const handleBack = () => {
    if (screen === AppScreen.FORM) setScreen(wines.length === 0 ? AppScreen.HOME : AppScreen.MANAGE);
    else setScreen(AppScreen.HOME);
  };

  const startNewSession = () => {
    setFunnelKey(prev => prev + 1);
    setScreen(AppScreen.FUNNEL);
  };

  const getTitle = () => {
    if (screen === AppScreen.HOME) return 'Kinglab Bodegas 202';
    if (screen === AppScreen.FUNNEL) return 'Dirección Creativa';
    if (screen === AppScreen.MANAGE) return 'Mis Vinos';
    if (screen === AppScreen.GALLERY) return 'Galería de Arte';
    if (screen === AppScreen.FORM) return selectedWineForEdit ? 'Editar Vino' : 'Registrar Vino';
    return screen;
  };

  return (
    <ErrorBoundary>
      <Layout 
        title={getTitle()} 
        onBack={screen !== AppScreen.HOME ? handleBack : undefined}
        onGear={() => setScreen(AppScreen.MANAGE)}
        onGallery={() => setScreen(AppScreen.GALLERY)}
        showGear={screen === AppScreen.HOME}
        showGallery={gallery.length > 0 && screen === AppScreen.HOME}
      >
        {screen === AppScreen.HOME && (
          <div className="flex flex-col h-full py-10 space-y-12 animate-in fade-in duration-700">
            <div className="text-center space-y-4">
              <h2 className="text-5xl font-serif font-bold text-black">Kinglab</h2>
              <p className="text-stone-400 font-medium italic text-lg leading-relaxed max-w-sm mx-auto">Tu mesa de trabajo inteligente para la dirección de arte vinícola.</p>
            </div>

            <div className="grid gap-6">
              <div className="bg-white p-10 rounded-[2.5rem] border-2 border-stone-100 text-center space-y-8 shadow-sm">
                <div className="w-16 h-16 bg-stone-50 rounded-full flex items-center justify-center mx-auto text-black border border-stone-100">
                  <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2v20"/><path d="M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/></svg>
                </div>
                <div className="space-y-2">
                  <h3 className="text-2xl font-serif font-bold">Nueva Sesión</h3>
                  <p className="text-stone-400 font-medium">Inicia el proceso creativo conversacional.</p>
                </div>
                <button onClick={startNewSession} className="w-full bg-black text-white px-8 py-5 rounded-2xl font-bold shadow-2xl active:scale-95 transition-all text-lg">
                  Comenzar
                </button>
              </div>

              {wines.length === 0 && (
                <div className="bg-stone-50 p-6 rounded-3xl border border-dashed border-stone-200 text-center space-y-3">
                  <p className="text-stone-500 text-sm font-medium">¿Aún no has registrado tus vinos? Hazlo para usarlos como referencia visual.</p>
                  <button onClick={() => setScreen(AppScreen.FORM)} className="text-black font-black text-xs uppercase tracking-widest border-b-2 border-black pb-1">Añadir primer vino</button>
                </div>
              )}
            </div>

            {gallery.length > 0 && (
              <div className="space-y-6">
                <div className="flex justify-between items-end px-4">
                  <h4 className="font-serif font-bold text-2xl text-black">Arte Reciente</h4>
                  <button onClick={() => setScreen(AppScreen.GALLERY)} className="text-black font-black text-[10px] uppercase tracking-widest border-b-2 border-black pb-1 active:opacity-50">Ver todo</button>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  {gallery.slice(0, 4).map(img => (
                    <div key={img.id} onClick={() => setScreen(AppScreen.GALLERY)} className="aspect-square rounded-3xl overflow-hidden border border-stone-100 shadow-sm cursor-pointer active:scale-95 transition-all">
                      <img src={img.url} className="w-full h-full object-cover" alt={img.wineName} />
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {screen === AppScreen.FUNNEL && (
          <CreativeFunnel 
            key={funnelKey}
            wines={wines} 
            onFinish={() => setScreen(AppScreen.HOME)} 
            onSaveToGallery={(img) => setGallery(prev => [img, ...prev])} 
          />
        )}

        {screen === AppScreen.GALLERY && (
          <Gallery images={gallery} onBack={() => setScreen(AppScreen.HOME)} onRegenerate={() => {}} onAdjust={() => {}} />
        )}

        {screen === AppScreen.MANAGE && (
          <WineList wines={wines} onEdit={(w) => { setSelectedWineForEdit(w); setScreen(AppScreen.FORM); }} onAdd={() => { setSelectedWineForEdit(null); setScreen(AppScreen.FORM); }} />
        )}

        {screen === AppScreen.FORM && (
          <WineForm initialWine={selectedWineForEdit || undefined} onSave={handleSaveWine} />
        )}
      </Layout>
    </ErrorBoundary>
  );
};

