               <button onClick={() => handleFeedback('like')} className={`p-4 rounded-full transition-all ${state.feedback === 'like' ? 'bg-green-100 text-green-600 scale-110' : 'bg-stone-100 text-stone-400'}`}>
                 <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M7 10v12"/><path d="M15 5.88 14 10h5.83a2 2 0 0 1 1.92 2.56l-2.33 8A2 2 0 0 1 17.5 22H4a2 2 0 0 1-2-2v-8a2 2 0 0 1 2-2h2.76a2 2 0 0 0 1.79-1.11L12 2h0a3.13 3.13 0 0 1 3 3.88Z"/></svg>
               </button>
               <button onClick={() => handleFeedback('dislike')} className={`p-4 rounded-full transition-all ${state.feedback === 'dislike' ? 'bg-red-100 text-red-600 scale-110' : 'bg-stone-100 text-stone-400'}`}>
                 <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M17 14V2"/><path d="M9 18.12 10 14H4.17a2 2 0 0 1-1.92-2.56l2.33-8A2 2 0 0 1 6.5 2H20a2 2 0 0 1 2 2v8a2 2 0 0 1-2 2h-2.76a2 2 0 0 0-1.79 1.11L12 22h0a3.13 3.13 0 0 1-3-3.88Z"/></svg>
               </button>
            </div>

            <button onClick={onFinish} className="w-full py-5 bg-black text-white rounded-2xl font-bold shadow-xl shadow-black/10 active:scale-95 transition-all">Finalizar y Guardar</button>
            <button onClick={() => goToStep(13)} className="w-full py-4 text-stone-400 font-bold hover:text-black">Volver a propuestas</button>
          </div>
        </div>
      );
      default: return null;
    }
  };

  return (
    <div className="max-w-xl mx-auto pb-10">
      {renderCurrentStep()}
      {state.error && (
        <div className="mt-6 p-4 bg-red-50 text-red-600 rounded-xl font-bold text-center border border-red-100">
          {state.error}
        </div>
      )}
    </div>
  );
};

