import { GoogleGenAI, Type } from "@google/genai";
import { Wine, ImageType, FunnelState, AnalysisResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

export const analyzePublicPerception = async (wineName: string): Promise<AnalysisResult> => {
  const prompt = `Analiza la percepción pública actual en internet del vino o bodega "${wineName}". 
  Busca en redes sociales, foros, prensa especializada y reseñas de usuarios. 
  IMPORTANTE: No utilices información del sitio web oficial de la bodega ni de sus canales propios. 

  Devuelve la respuesta en este formato exacto:
  RESUMEN: (Dos párrafos de texto natural en español analizando la marca)
  INFORME: (Un informe detallado con puntos clave, críticas y elogios)`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }]
      }
    });

    const text = response.text || '';
    const summaryMatch = text.match(/RESUMEN:([\s\S]*?)INFORME:/i);
    const reportMatch = text.match(/INFORME:([\s\S]*)$/i);

    const urls = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((c: any) => c.web?.uri)
      .filter(Boolean) || [];

    return {
      summary: summaryMatch ? summaryMatch[1].trim() : "No se pudo extraer el resumen.",
      fullReport: reportMatch ? reportMatch[1].trim() : text,
      urls: Array.from(new Set(urls))
    };
  } catch (error) {
    console.error("Error analyzing perception:", error);
    throw error;
  }
};

export const generateVisualConcepts = async (state: FunnelState): Promise<string[]> => {
  const prompt = `
    Eres un Director Creativo experto para Kinglab Bodegas 202.
    Genera 3 conceptos visuales distintos basándote en esta conversación creativa:

    VINO: ${state.wineName}
    PÚBLICO: ${state.audience}
    DIFERENCIADOR: ${state.specialFeatures}
    ANÁLISIS MERCADO: ${state.useAnalysis ? state.analysisResult?.summary : 'Ignorado'}
    TIPO IMAGEN: ${state.imageType}
    ESTILO: ${state.visualStyle} (${state.styleDetail})
    LUGAR: ${state.location}
    CUANDO: ${state.timeContext}

    REGLAS:
    - Conceptos en ESPAÑOL.
    - Cada uno debe ser un párrafo de 30-40 palabras.
    - Lenguaje editorial, elegante y descriptivo.
    - Estructura la respuesta como JSON con una lista llamada "concepts".
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            concepts: {
              type: Type.ARRAY,
              items: { type: Type.STRING }
            }
          },
          required: ["concepts"]
        }
      }
    });

    const data = JSON.parse(response.text || '{}');
    return data.concepts || [];
  } catch (error) {
    console.error("Error generating concepts:", error);
    return ["Concepto minimalista", "Concepto rústico", "Concepto editorial"];
  }
};

export const generateFinalImage = async (
  wineImage: string | null,
  state: FunnelState,
  concept: string,
  ratio: string
): Promise<string | null> => {
  let parts: any[] = [];

  if (wineImage) {
    const base64Data = wineImage.split(',')[1];
    const mimeType = wineImage.split(';')[0].split(':')[1];
    parts.push({ inlineData: { data: base64Data, mimeType } });
  }

  if (state.locationImage) {
    const base64Loc = state.locationImage.split(',')[1];
    const mimeLoc = state.locationImage.split(';')[0].split(':')[1];
    parts.push({ inlineData: { data: base64Loc, mimeType: mimeLoc } });
  }

  const promptText = `
    Fotografía publicitaria de alta gama.
    PRODUCTO: ${state.wineName}
    CONCEPTO: ${concept}
    ESTILO: ${state.visualStyle}, ${state.styleDetail}.
    AMBIENTE: ${state.location} en ${state.timeContext}.

    Si hay una imagen de botella, mantén la etiqueta reconocible.
    Si hay una imagen de lugar, úsala de referencia.
    Resultado elegante, listo para editorial.
  `;

  parts.push({ text: promptText });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts },
      config: {
        imageConfig: {
          aspectRatio: ratio as any
        }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Error generating image:", error);
    throw error;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Wine, ImageType, FunnelState, AspectRatio, GalleryImage, AnalysisResult } from '../types';
import { analyzePublicPerception, generateVisualConcepts, generateFinalImage } from '../services/geminiService';

interface CreativeFunnelProps {
  wines: Wine[];
  onFinish: () => void;
  onSaveToGallery: (img: GalleryImage) => void;
}

const CreativeFunnel: React.FC<CreativeFunnelProps> = ({ wines, onFinish, onSaveToGallery }) => {
  const [state, setState] = useState<FunnelState>({
    step: 1,
    wineName: '',
    audience: '',
    specialFeatures: '',
    analysisChoice: null,
    analysisResult: null,
    useAnalysis: null,
    imageType: null,
    visualStyle: '',
    styleDetail: '',
    location: '',
    locationImage: null,
    timeContext: '',
    concepts: [],
    selectedConceptIndex: null,
    imageHistory: [],
    isLoading: false,
    error: null,
    feedback: null
  });

  const [input, setInput] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [state.step, state.isLoading]);

  const handleTextSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!input.trim()) return;

    const val = input.trim();
    setInput('');

    switch (state.step) {
      case 1: setState(s => ({ ...s, wineName: val, step: 2 })); break;
      case 2: setState(s => ({ ...s, audience: val, step: 3 })); break;
      case 3: setState(s => ({ ...s, specialFeatures: val, step: 4 })); break;
      case 8: setState(s => ({ ...s, styleDetail: val, step: 10 })); break;
      case 10: setState(s => ({ ...s, location: val, step: 11 })); break;
      case 12: setState(s => ({ ...s, timeContext: val, step: 13 })); break;
    }
  };

  const startAnalysis = async () => {
    setState(s => ({ ...s, isLoading: true, error: null }));
    try {
      const result = await analyzePublicPerception(state.wineName);
      setState(s => ({ ...s, analysisResult: result, step: 5, isLoading: false }));
    } catch (e) {
      setState(s => ({ ...s, error: "No pudimos completar el análisis de mercado.", isLoading: false, step: 6 }));
    }
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => setState(s => ({ ...s, locationImage: reader.result as string, step: 12 }));
      reader.readAsDataURL(file);
    }
  };

  const generateConcepts = async () => {
    setState(s => ({ ...s, isLoading: true, error: null }));
    try {
      const concepts = await generateVisualConcepts(state);
      setState(s => ({ ...s, concepts, step: 14, isLoading: false }));
    } catch (e) {
      setState(s => ({ ...s, error: "Error al generar conceptos creativos.", isLoading: false }));
    }
  };

  const createFinalImage = async (index: number) => {
    setState(s => ({ ...s, isLoading: true, selectedConceptIndex: index, step: 15 }));
    try {
      const wineRef = wines.find(w => w.name.toLowerCase() === state.wineName.toLowerCase()) || null;
      const url = await generateFinalImage(wineRef?.image || null, state, state.concepts[index], '1:1');
      if (url) {
        setState(s => ({ ...s, imageHistory: [url], isLoading: false }));
        onSaveToGallery({
          id: Date.now().toString(),
          url,
          concept: state.concepts[index],
          wineName: state.wineName,
          timestamp: Date.now()
        });
      }
    } catch (e) {
      setState(s => ({ ...s, error: "Fallo en la generación de imagen.", isLoading: false }));
    }
  };

  const getTimeSuggestions = () => {
    const month = new Date().getMonth();
    const seasonSuggestions = month >= 2 && month <= 4 ? ["Primavera", "Tarde soleada"] :
                        month >= 5 && month <= 7 ? ["Verano", "Atardecer cálido", "Cena terraza"] :
                        month >= 8 && month <= 10 ? ["Vendimia", "Otoño", "Luz dorada"] :
                        ["Invierno", "Noche de amigos", "Navidad"];
    return [...seasonSuggestions, "San Valentín", "Momento relax"];
  };

  const renderBubble = (text: string, isAssistant = true) => (
    <div className={`flex ${isAssistant ? 'justify-start' : 'justify-end'} mb-4 animate-in fade-in slide-in-from-${isAssistant ? 'left' : 'right'}-4 duration-500`}>
      <div className={`max-w-[85%] p-4 rounded-2xl ${isAssistant ? 'bg-stone-100 text-stone-800 rounded-tl-none' : 'bg-black text-white rounded-tr-none shadow-lg'} font-medium leading-relaxed`}>
        {text}
      </div>
    </div>
  );

  const renderInput = (placeholder: string) => (
    <form onSubmit={handleTextSubmit} className="flex gap-2 sticky bottom-4 z-10 bg-white/80 backdrop-blur-sm p-2 rounded-2xl border border-stone-200 shadow-xl">
      <input
        autoFocus
        value={input}
        onChange={e => setInput(e.target.value)}
        placeholder={placeholder}
        className="flex-1 px-4 py-3 bg-transparent outline-none text-black font-medium"
      />
      <button type="submit" className="bg-black text-white p-3 rounded-xl active:scale-95 transition-all">
        <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="m5 12 7-7 7 7"/><path d="M12 19V5"/></svg>
      </button>
    </form>
  );

  return (
    <div className="flex flex-col min-h-full max-w-lg mx-auto pb-20">
      {/* Mensajes previos */}
      {state.step > 1 && renderBubble("¿En qué vino o bodega quieres trabajar hoy?")}
      {state.wineName && renderBubble(state.wineName, false)}

      {state.step > 2 && renderBubble("¿Para quién va dirigido este vino?")}
      {state.audience && renderBubble(state.audience, false)}

      {state.step > 3 && renderBubble("¿Qué hace especial a este vino?")}
      {state.specialFeatures && renderBubble(state.specialFeatures, false)}

      {/* Paso actual */}
      {state.isLoading ? (
        <div className="flex flex-col items-center py-10 space-y-4 animate-pulse">
          <div className="w-10 h-10 border-4 border-stone-100 border-t-black rounded-full animate-spin" />
          <p className="text-stone-400 font-serif italic">Diseñando...</p>
        </div>
      ) : (
        <>
          {state.step === 1 && (
            <div className="space-y-4">
              {renderBubble("¡Hola! Soy tu asistente de dirección creativa. ¿Sobre qué vino trabajaremos hoy?")}
              {renderInput("Nombre del vino o bodega...")}
            </div>
          )}

          {state.step === 2 && (
            <div className="space-y-4">
              {renderBubble("Entendido. ¿Para quién va dirigido este vino?")}
              {renderInput("Háblame de su público...")}
            </div>
          )}

          {state.step === 3 && (
            <div className="space-y-4">
              {renderBubble("¿Qué hace especial a este vino?")}
              {renderInput("Notas de cata, historia, origen...")}
            </div>
          )}

          {state.step === 4 && (
            <div className="space-y-4">
              {renderBubble("¿Quieres que analicemos la percepción pública de este vino en internet antes de seguir?")}
              <div className="flex gap-2">
                <button onClick={startAnalysis} className="flex-1 bg-black text-white py-4 rounded-xl font-bold shadow-lg active:scale-95 transition-all">Analizar percepción</button>
                <button onClick={() => setState(s => ({ ...s, step: 6, useAnalysis: false }))} className="flex-1 bg-stone-100 text-stone-600 py-4 rounded-xl font-bold active:scale-95 transition-all">Continuar directo</button>
              </div>
            </div>
          )}

          {state.step === 5 && state.analysisResult && (
            <div className="space-y-6">
              {renderBubble("He analizado las redes, foros y prensa especializada:")}
              <div className="bg-stone-50 p-6 rounded-3xl border border-stone-200 space-y-4 animate-in zoom-in-95">
                <p className="text-stone-700 italic leading-relaxed">{state.analysisResult.summary}</p>
                <button 
                  onClick={() => {
                    const blob = new Blob([state.analysisResult?.fullReport || ''], { type: 'text/plain' });
                    const url = URL.createObjectURL(blob);
                    const a = document.createElement('a');
                    a.href = url;
                    a.download = `Analisis_${state.wineName}.txt`;
                    a.click();
                  }}
                  className="text-xs font-black uppercase tracking-widest text-black border-b-2 border-black pb-1"
                >
                  Descargar informe completo
                </button>
                {state.analysisResult.urls.length > 0 && (
                  <div className="pt-2">
                    <p className="text-[10px] font-black uppercase text-stone-400 mb-2">Fuentes consultadas:</p>
                    <div className="flex flex-wrap gap-2">
                      {state.analysisResult.urls.slice(0,3).map((u, i) => (
                        <a key={i} href={u} target="_blank" className="text-[9px] bg-white px-2 py-1 rounded border border-stone-100 truncate max-w-[100px]">{new URL(u).hostname}</a>
                      ))}
                    </div>
                  </div>
                )}
              </div>
              {renderBubble("¿Quieres que usemos esta información para los conceptos?")}
              <div className="flex gap-2">
                <button onClick={() => setState(s => ({ ...s, useAnalysis: true, step: 6 }))} className="flex-1 bg-black text-white py-4 rounded-xl font-bold">Tenerlo en cuenta</button>
                <button onClick={() => setState(s => ({ ...s, useAnalysis: false, step: 6 }))} className="flex-1 bg-stone-100 text-stone-600 py-4 rounded-xl font-bold">Descartarlo</button>
              </div>
            </div>
          )}

          {state.step === 6 && (
            <div className="space-y-4">
              {renderBubble("¿Qué tipo de imagen quieres crear?")}
              <div className="grid grid-cols-1 gap-2">
                {Object.values(ImageType).map(t => (
                  <button key={t} onClick={() => setState(s => ({ ...s, imageType: t, step: 7 }))} className="w-full py-4 px-6 bg-white border-2 border-stone-100 rounded-2xl font-bold text-left hover:border-black transition-all flex justify-between items-center group shadow-sm">
                    {t}
                    <svg xmlns="http://www.w3.org/2000/svg" width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className="opacity-0 group-hover:opacity-100 transition-opacity"><path d="m9 18 6-6-6-6"/></svg>
                  </button>
                ))}
              </div>
            </div>
          )}

          {state.step === 7 && (
            <div className="space-y-4">
              {renderBubble("¿Qué estilo visual tienes en mente?")}
              <div className="grid grid-cols-2 gap-2">
                {["Minimalista", "Editorial", "Natural", "Lujoso", "Cotidiano"].map(style => (
                  <button key={style} onClick={() => {
                    if (style === "Minimalista") setState(s => ({ ...s, visualStyle: style, step: 9 }));
                    else setState(s => ({ ...s, visualStyle: style, step: 8 }));
                  }} className="py-4 bg-white border-2 border-stone-100 rounded-xl font-bold hover:border-black transition-all">{style}</button>
                ))}
              </div>
            </div>
          )}

          {state.step === 8 && (
            <div className="space-y-4">
              {renderBubble(`Me gusta el estilo ${state.visualStyle}. ¿Algún detalle sobre la composición o elementos?`)}
              {renderInput("Ej: Copas de cristal, uvas frescas, mesa de madera...")}
            </div>
          )}

          {state.step === 9 && (
            <div className="space-y-4">
              {renderBubble("¿Prefieres un minimalismo extremo o con algunos elementos sutiles?")}
              <div className="flex gap-2">
                <button onClick={() => setState(s => ({ ...s, styleDetail: "Muy minimal, sin objetos extra", step: 10 }))} className="flex-1 bg-black text-white py-4 rounded-xl font-bold">Muy minimal</button>
                <button onClick={() => setState(s => ({ ...s, styleDetail: "Minimalista con elementos sutiles", step: 8 }))} className="flex-1 bg-stone-100 text-stone-600 py-4 rounded-xl font-bold">Con elementos</button>
              </div>
            </div>
          )}

          {state.step === 10 && (
            <div className="space-y-4">
              {renderBubble("¿Dónde ocurre la escena?")}
              <div className="grid grid-cols-2 gap-2">
                {["Viñedo", "Bodega", "Restaurante", "Casa"].map(loc => (
                  <button key={loc} onClick={() => setState(s => ({ ...s, location: loc, step: 11 }))} className="py-4 bg-white border-2 border-stone-100 rounded-xl font-bold hover:border-black">{loc}</button>
                ))}
              </div>
              <p className="text-center text-[10px] font-black uppercase text-stone-400 py-2">O escribe otra opción</p>
              {renderInput("Ej: Puerto de mar, biblioteca...")}
            </div>
          )}

          {state.step === 11 && (
            <div className="space-y-4">
              {renderBubble(`Entendido, en ${state.location}. ¿Quieres subir una imagen de referencia del lugar?`)}
              <div className="flex flex-col gap-3">
                <button onClick={() => fileInputRef.current?.click()} className="w-full py-4 border-2 border-dashed border-stone-200 rounded-xl text-stone-500 font-bold flex items-center justify-center gap-2 hover:border-black hover:text-black transition-all">
                  <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><rect width="18" height="18" x="3" y="3" rx="2" ry="2"/><circle cx="9" cy="9" r="2"/><path d="m21 15-3.086-3.086a2 2 0 0 0-2.828 0L6 21"/></svg>
                  Subir referencia
                </button>
                <input type="file" ref={fileInputRef} onChange={handleImageUpload} className="hidden" accept="image/*" />
                <button onClick={() => setState(s => ({ ...s, step: 12 }))} className="w-full bg-black text-white py-4 rounded-xl font-bold">Omitir paso</button>
              </div>
            </div>
          )}

          {state.step === 12 && (
            <div className="space-y-4">
              {renderBubble("¿Cuándo ocurre la escena? Algunas sugerencias:")}
              <div className="flex flex-wrap gap-2">
                {getTimeSuggestions().map(t => (
                  <button key={t} onClick={() => setState(s => ({ ...s, timeContext: t, step: 13 }))} className="px-4 py-2 bg-stone-50 border border-stone-200 rounded-full text-sm font-bold text-stone-600 hover:border-black">{t}</button>
                ))}
              </div>
              {renderInput("Cualquier otro momento...")}
            </div>
          )}

          {state.step === 13 && (
            <div className="space-y-6 pt-10">
              {renderBubble("Tengo todo lo necesario. ¿Preparamos los conceptos de dirección?")}
              <button onClick={generateConcepts} className="w-full bg-black text-white py-6 rounded-[2rem] font-bold shadow-2xl shadow-black/20 flex items-center justify-center gap-4 text-xl animate-bounce">
                <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m12 3-1.912 5.813a2 2 0 0 1-1.275 1.275L3 12l5.813 1.912a2 2 0 0 1 1.275 1.275L12 21l1.912-5.813a2 2 0 0 1 1.275-1.275L21 12l-5.813-1.912a2 2 0 0 1-1.275-1.275L12 3Z"/></svg>
                Generar Conceptos
              </button>
            </div>
          )}

          {state.step === 14 && (
            <div className="space-y-6 animate-in zoom-in-95">
              {renderBubble("Aquí tienes mis propuestas:")}
              <div className="space-y-4">
                {state.concepts.map((c, i) => (
                  <button key={i} onClick={() => createFinalImage(i)} className="w-full p-6 bg-white border-2 border-stone-100 rounded-3xl text-left hover:border-black transition-all shadow-sm">
                    <p className="text-stone-800 font-medium italic leading-relaxed">"{c}"</p>
                    <div className="mt-4 text-[10px] font-black uppercase tracking-widest text-stone-400">Seleccionar este concepto</div>
                  </button>
                ))}
              </div>
            </div>
          )}

          {state.step === 15 && state.imageHistory.length > 0 && (
            <div className="space-y-6 animate-in fade-in duration-700">
              <div className="rounded-[2.5rem] overflow-hidden border border-stone-200 shadow-2xl aspect-square relative bg-white">
                <img src={state.imageHistory[0]} alt="Resultado" className="w-full h-full object-cover" />
              </div>
              <div className="bg-stone-50 p-6 rounded-2xl italic text-stone-600 text-center font-medium shadow-inner">
                "{state.concepts[state.selectedConceptIndex || 0]}"
              </div>
              <div className="flex flex-col gap-4">
                <div className="flex gap-4 justify-center">
                  <button 
                    onClick={() => setState(s => ({ ...s, feedback: 'like' }))}
                    className={`p-4 rounded-full transition-all ${state.feedback === 'like' ? 'bg-green-100 text-green-600 scale-110' : 'bg-stone-100 text-stone-400'}`}
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M7 10v12"/><path d="M15 5.88 14 10h5.83a2 2 0 0 1 1.92 2.56l-2.33 8A2 2 0 0 1 17.5 22H4a2 2 0 0 1-2-2v-8a2 2 0 0 1 2-2h2.76a2 2 0 0 0 1.79-1.11L12 2h0a3.13 3.13 0 0 1 3 3.88Z"/></svg>
                  </button>
                  <button 
                    onClick={() => setState(s => ({ ...s, feedback: 'dislike' }))}
                    className={`p-4 rounded-full transition-all ${state.feedback === 'dislike' ? 'bg-red-100 text-red-600 scale-110' : 'bg-stone-100 text-stone-400'}`}
                  >
                    <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M17 14V2"/><path d="M9 18.12 10 14H4.17a2 2 0 0 1-1.92-2.56l2.33-8A2 2 0 0 1 6.5 2H20a2 2 0 0 1 2 2v8a2 2 0 0 1-2 2h-2.76a2 2 0 0 0-1.79 1.11L12 22h0a3.13 3.13 0 0 1-3-3.88Z"/></svg>
                  </button>
                </div>
                <button onClick={onFinish} className="w-full bg-black text-white py-5 rounded-2xl font-bold shadow-xl active:scale-95 transition-all text-lg">Finalizar Sesión</button>
                <button onClick={() => setState(s => ({ ...s, step: 14 }))} className="text-stone-400 font-bold hover:text-black transition-colors">Volver a propuestas</button>
              </div>
            </div>
          )}
        </>
      )}

      {state.error && (
        <div className="mt-8 p-4 bg-red-50 text-red-600 rounded-xl font-bold text-center border border-red-100">
          {state.error}
          <button onClick={() => window.location.reload()} className="block mx-auto mt-2 underline">Recargar</button>
        </div>
      )}

      <div ref={scrollRef} className="h-4 w-full" />
    </div>
  );
};

export default CreativeFunnel;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import WineList from './components/WineList';
import WineForm from './components/WineForm';
import CreativeFunnel from './components/CreativeFunnel';
import Gallery from './components/Gallery';
import ErrorBoundary from './components/ErrorBoundary';
import { Wine, AppScreen, GalleryImage } from './types';

const App: React.FC = () => {
  const [screen, setScreen] = useState<AppScreen>(AppScreen.HOME);
  const [funnelKey, setFunnelKey] = useState(0);
  const [wines, setWines] = useState<Wine[]>(() => {
    const saved = localStorage.getItem('kinglab_wines_v2');
    return saved ? JSON.parse(saved) : [];
  });
  const [gallery, setGallery] = useState<GalleryImage[]>(() => {
    const saved = localStorage.getItem('kinglab_gallery_v3');
    return saved ? JSON.parse(saved) : [];
  });
  const [selectedWineForEdit, setSelectedWineForEdit] = useState<Wine | null>(null);

  useEffect(() => { localStorage.setItem('kinglab_wines_v2', JSON.stringify(wines)); }, [wines]);
  useEffect(() => { localStorage.setItem('kinglab_gallery_v3', JSON.stringify(gallery)); }, [gallery]);

  const handleSaveWine = (wine: Wine) => {
    setWines(prev => {
      const exists = prev.find(w => w.id === wine.id);
      if (exists) return prev.map(w => w.id === wine.id ? wine : w);
      return [wine, ...prev];
    });
    setScreen(AppScreen.HOME);
    setSelectedWineForEdit(null);
  };

  const handleBack = () => {
    if (screen === AppScreen.FORM) setScreen(wines.length === 0 ? AppScreen.HOME : AppScreen.MANAGE);
    else setScreen(AppScreen.HOME);
    setSelectedWineForEdit(null);
  };

  const startNewSession = () => {
    setFunnelKey(prev => prev + 1);
    setScreen(AppScreen.FUNNEL);
  };

  const getTitle = () => {
    if (screen === AppScreen.HOME) return 'Kinglab Bodegas 202';
    if (screen === AppScreen.FUNNEL) return 'Sesión Creativa';
    if (screen === AppScreen.MANAGE) return 'Gestionar Vinos';
    if (screen === AppScreen.GALLERY) return 'Galería de Arte';
    if (screen === AppScreen.FORM) return selectedWineForEdit ? 'Editar Vino' : 'Añadir Vino';
    return screen;
  };

  return (
    <ErrorBoundary>
      <Layout 
        title={getTitle()} 
        onBack={screen !== AppScreen.HOME ? handleBack : undefined}
        onGear={() => setScreen(AppScreen.MANAGE)}
        onGallery={() => setScreen(AppScreen.GALLERY)}
        showGear={screen === AppScreen.HOME}
        showGallery={gallery.length > 0 && screen === AppScreen.HOME}
      >
        {screen === AppScreen.HOME && (
          <div className="space-y-12 py-6 animate-in fade-in duration-700">
            <div className="text-center space-y-4 px-6">
              <h2 className="text-5xl font-serif font-bold text-black">Kinglab</h2>
              <p className="text-stone-400 font-medium italic text-lg leading-relaxed">Tu mesa de trabajo inteligente para la dirección de arte vinícola.</p>
            </div>

            <div className="bg-white p-12 rounded-[2.5rem] border-2 border-stone-100 text-center space-y-8 shadow-sm max-w-lg mx-auto">
              <div className="w-16 h-16 bg-stone-50 rounded-full flex items-center justify-center mx-auto text-black border border-stone-100">
                <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2v20"/><path d="M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/></svg>
              </div>
              <div className="space-y-3">
                <h3 className="text-2xl font-serif font-bold">Nueva Dirección</h3>
                <p className="text-stone-400 font-medium">Inicia una sesión conversacional para crear arte publicitario.</p>
              </div>
              <button onClick={startNewSession} className="w-full bg-black text-white px-8 py-5 rounded-2xl font-bold shadow-2xl active:scale-95 transition-all text-lg">
                Comenzar Sesión
              </button>
            </div>

            {wines.length === 0 && (
              <div className="text-center px-10">
                <button onClick={() => setScreen(AppScreen.FORM)} className="text-stone-400 font-black text-[10px] uppercase tracking-widest border-b-2 border-stone-200 pb-1 hover:text-black hover:border-black transition-all">
                  Registrar mi primer vino
                </button>
              </div>
            )}

            {gallery.length > 0 && (
              <div className="space-y-6">
                <div className="flex justify-between items-end px-4">
                  <h4 className="font-serif font-bold text-2xl text-black">Explorar Galería</h4>
                  <button onClick={() => setScreen(AppScreen.GALLERY)} className="text-black font-black text-[10px] uppercase tracking-widest border-b-2 border-black pb-1 active:opacity-50">Ver todo</button>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  {gallery.slice(0, 4).map(img => (
                    <div key={img.id} onClick={() => setScreen(AppScreen.GALLERY)} className="aspect-square rounded-3xl overflow-hidden border border-stone-100 shadow-sm cursor-pointer active:scale-95 transition-all">
                      <img src={img.url} className="w-full h-full object-cover" alt={img.wineName} />
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {screen === AppScreen.FUNNEL && (
          <CreativeFunnel 
            key={funnelKey}
            wines={wines} 
            onFinish={() => setScreen(AppScreen.HOME)} 
            onSaveToGallery={(img) => setGallery(prev => [img, ...prev])} 
          />
        )}

        {screen === AppScreen.GALLERY && (
          <Gallery images={gallery} onBack={() => setScreen(AppScreen.HOME)} onRegenerate={() => {}} onAdjust={() => {}} />
        )}

        {screen === AppScreen.MANAGE && (
          <WineList wines={wines} onEdit={(w) => { setSelectedWineForEdit(w); setScreen(AppScreen.FORM); }} onAdd={() => { setSelectedWineForEdit(null); setScreen(AppScreen.FORM); }} />
        )}

        {screen === AppScreen.FORM && (
          <WineForm initialWine={selectedWineForEdit || undefined} onSave={handleSaveWine} />
        )}
      </Layout>
    </ErrorBoundary>
  );
};

export default App;

import React, { useState } from 'react';
import { Wine, ImageType, AspectRatio, FunnelState } from '../types';
// Fixed: Using generateFinalImage as generateWineImage does not exist in geminiService.ts
import { generateFinalImage } from '../services/geminiService';

interface ImageGeneratorProps {
  wines: Wine[];
  initialSelectedWine?: Wine;
}

const ImageGenerator: React.FC<ImageGeneratorProps> = ({ wines, initialSelectedWine }) => {
  const [selectedWine, setSelectedWine] = useState<Wine | null>(initialSelectedWine || wines[0] || null);
  const [ratio, setRatio] = useState<AspectRatio>('1:1');
  const [type, setType] = useState<ImageType>(ImageType.BODEGON);
  const [context, setContext] = useState('');
  const [loading, setLoading] = useState(false);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);

  const handleGenerate = async () => {
    if (!selectedWine) return;
    setLoading(true);
    try {
      // Fixed: Constructing a proper concept and matching the 4-argument signature of generateFinalImage.
      // We also now pass the image string (base64) instead of the whole wine object.
      const concept = context.trim() || `Fotografía publicitaria profesional de ${selectedWine.name}, estilo ${type}.`;

      // Creating a mock FunnelState to satisfy the service requirements (it uses state properties for prompt construction).
      const mockState: Partial<FunnelState> = {
        wineName: selectedWine.name,
        visualStyle: type,
        styleDetail: context || 'Estilo publicitario editorial',
        location: 'Estudio fotográfico',
        timeContext: 'Iluminación de estudio',
        locationImage: null
      };

      const result = await generateFinalImage(
        selectedWine.image, 
        mockState as FunnelState, 
        concept, 
        ratio
      );
      setGeneratedImage(result);
    } catch (error) {
      console.error("Generation error:", error);
      alert("Error al generar la imagen. Verifica tu conexión o API Key.");
    } finally {
      setLoading(false);
    }
  };

  // Fix: changed '4:5' to '3:4' to match AspectRatio type definition in types.ts (allowed values: '1:1' | '3:4' | '4:3' | '9:16' | '16:9')
  const ratios: AspectRatio[] = ['1:1', '3:4', '9:16', '16:9'];
  const types = Object.values(ImageType);

  const labelClasses = "block text-sm font-semibold text-stone-700 mb-2";

  return (
    <div className="space-y-8 pb-10">
      {!generatedImage ? (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-300">
          {/* WINE SELECTOR */}
          <div>
            <label className={labelClasses}>Seleccionar vino</label>
            <select
              className="w-full px-4 py-3 rounded-lg border border-stone-200 focus:ring-2 focus:ring-black outline-none bg-white text-black"
              value={selectedWine?.id || ''}
              onChange={(e) => setSelectedWine(wines.find(w => w.id === e.target.value) || null)}
            >
              {wines.map(w => (
                <option key={w.id} value={w.id}>{w.name}</option>
              ))}
            </select>
          </div>

          {/* RATIO BUTTONS */}
          <div className="space-y-3">
            <label className={labelClasses}>Formato de imagen</label>
            <div className="grid grid-cols-4 gap-2">
              {ratios.map(r => (
                <button
                  key={r}
                  onClick={() => setRatio(r)}
                  className={`py-3 rounded-lg border text-sm font-medium transition-all ${
                    ratio === r 
                    ? 'bg-black text-white border-black shadow-md' 
                    : 'bg-white text-stone-600 border-stone-200 hover:border-stone-400'
                  }`}
                >
                  {r}
                </button>
              ))}
            </div>
          </div>

          {/* TYPE BUTTONS */}
          <div className="space-y-3">
            <label className={labelClasses}>Tipo de imagen</label>
            <div className="grid grid-cols-1 gap-2">
              {types.map(t => (
                <button
                  key={t}
                  onClick={() => setType(t)}
