import { GoogleGenAI, Type } from "@google/genai";
import { Wine, ImageType, FunnelState, AnalysisResult } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

/**
 * Realiza un análisis de percepción digital excluyendo el sitio oficial.
 */
export const analyzePublicPerception = async (wineName: string): Promise<AnalysisResult> => {
  const prompt = `Realiza un análisis profesional de la percepción pública actual en internet para el vino o bodega "${wineName}". 
  Busca en redes sociales, foros, prensa digital y reseñas de usuarios. 
  REGLA CRÍTICA: Excluye explícitamente cualquier información que provenga del sitio web oficial de la bodega o sus canales propios. 
  Queremos la visión externa del mercado.

  Formato de respuesta requerido (ESPAÑOL):
  RESUMEN: exacto de dos párrafos con la percepción general.
  INFORME: un informe detallado con puntos de vista, tendencias y críticas.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }]
      }
    });

    const text = response.text || '';
    const summaryMatch = text.match(/RESUMEN:([\s\S]*?)INFORME:/i);
    const reportMatch = text.match(/INFORME:([\s\S]*)$/i);

    const urls = response.candidates?.[0]?.groundingMetadata?.groundingChunks
      ?.map((c: any) => c.web?.uri)
      .filter(Boolean) || [];

    return {
      summary: summaryMatch ? summaryMatch[1].trim() : "No se pudo extraer el resumen estructurado.",
      fullReport: reportMatch ? reportMatch[1].trim() : text,
      urls: Array.from(new Set(urls))
    };
  } catch (error) {
    console.error("Error en análisis de percepción:", error);
    throw error;
  }
};

/**
 * Genera conceptos creativos basados en la conversación acumulada.
 */
export const generateVisualConcepts = async (state: FunnelState): Promise<string[]> => {
  if (!state.selectedWine) return [];

  const prompt = `
    Como Director Creativo Senior, genera 3 conceptos visuales únicos para el vino "${state.selectedWine.name}".
    Contexto acumulado:
    - Posicionamiento: ${state.selectedWine.priceLevel}
    - Público: ${state.selectedWine.targetAudience}
    - Especial: ${state.selectedWine.specialFeatures}
    - Análisis de Mercado: ${state.useAnalysis ? state.analysisResult?.summary : 'No utilizado'}
    - Tipo de Imagen: ${state.imageType}
    - Estilo Visual: ${state.visualStyle} (${state.styleSubDetail || ''})
    - Elementos: ${state.elements.join(', ')}
    - Ubicación: ${state.location}
    - Momento: ${state.timeContext}
    - Matices extra: ${state.nuances}

    REGLAS:
    - Idioma: Español.
    - Tono: Editorial, sofisticado.
    - Formato: JSON con lista "concepts" de strings. Cada string debe ser un párrafo descriptivo de 40 palabras.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            concepts: { type: Type.ARRAY, items: { type: Type.STRING } }
          },
          required: ["concepts"]
        }
      }
    });

    const data = JSON.parse(response.text || '{}');
    return data.concepts || [];
  } catch (error) {
    console.error("Error generando conceptos:", error);
    return ["Escena clásica de bodega con luz natural", "Bodegón minimalista sobre piedra", "Momento social elegante en terraza"];
  }
};

/**
 * Genera la imagen final utilizando las referencias de botella y lugar.
 */
export const generateFinalImage = async (
  wine: Wine,
  state: FunnelState,
  concept: string,
  ratio: string
): Promise<string | null> => {
  let parts: any[] = [];

  // Referencia de la botella (Obligatoria según Phase 1)
  const bottleBase64 = wine.image.split(',')[1];
  const bottleMime = wine.image.split(';')[0].split(':')[1];
  parts.push({ inlineData: { data: bottleBase64, mimeType: bottleMime } });

  // Referencia de lugar (Opcional según Phase 4)
  if (state.locationImage) {
    const locBase64 = state.locationImage.split(',')[1];
    const locMime = state.locationImage.split(';')[0].split(':')[1];
    parts.push({ inlineData: { data: locBase64, mimeType: locMime } });
  }

  const promptText = `
    FOTOGRAFÍA PUBLICITARIA DE ALTA CALIDAD.
    PRODUCTO: Botella de vino "${wine.name}".
    ESTILO: ${state.visualStyle}, ${state.styleSubDetail || ''}.
    CONCEPTO: ${concept}
    AMBIENTE: ${state.location} en ${state.timeContext}.
    DETALLES: ${state.elements.join(', ')}. ${state.nuances}

    INSTRUCCIONES:
    1. Mantén la botella y su etiqueta reconocibles de la imagen proporcionada.
    2. Usa la imagen de lugar como referencia de atmósfera si existe.
    3. Iluminación profesional acorde a un posicionamiento ${wine.priceLevel}.
    4. El resultado debe ser estético, nítido y editorial.
  `;

  parts.push({ text: promptText });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-pro-image-preview',
      contents: { parts },
      config: {
        imageConfig: { aspectRatio: ratio as any }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Error generando imagen final:", error);
    throw error;
  }
};

import React, { useState, useRef } from 'react';
