          </div>
        </div>

        <div>
          <label className={labelClasses}>¿Para quién va dirigido?</label>
          <input name="targetAudience" value={formData.targetAudience} onChange={handleTextChange} className={inputClasses} placeholder="Ej: Amantes del vino clásico, jóvenes..." />
        </div>

        <div>
          <label className={labelClasses}>Posicionamiento</label>
          <div className="grid grid-cols-2 gap-2">
            {PRICE_LEVELS.map(level => (
              <button
