interface CreativeFunnelProps {
  wines: Wine[];
  onFinish: () => void;
  onSaveToGallery: (img: GalleryImage) => void;
}

const CreativeFunnel: React.FC<CreativeFunnelProps> = ({ wines, onFinish, onSaveToGallery }) => {
  const [state, setState] = useState<FunnelState>({
    step: 1,
    selectedWine: null,
    analysisChoice: null,
    analysisResult: null,
    useAnalysis: null,
    imageType: null,
    visualStyle: null,
    styleSubDetail: null,
    elements: [],
    location: null,
    locationImage: null,
    timeContext: '',
    nuances: '',
    concepts: [],
    selectedConceptIndex: null,
    imageHistory: [],
    isLoading: false,
    error: null,
    feedback: null
  });

  const [inputText, setInputText] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [state.step, state.isLoading]);

  const goToStep = (step: number) => setState(s => ({ ...s, step }));

  const handleAnalysisChoice = async (choice: boolean) => {
    if (choice) {
      setState(s => ({ ...s, isLoading: true, analysisChoice: true }));
      try {
        const result = await analyzePublicPerception(state.selectedWine!.name);
        setState(s => ({ ...s, analysisResult: result, step: 3, isLoading: false }));
      } catch (e) {
        setState(s => ({ ...s, error: "Error en el análisis digital. Continuando sin él.", step: 4, isLoading: false }));
      }
    } else {
      setState(s => ({ ...s, analysisChoice: false, step: 4 }));
    }
  };

  const getSeasonalSuggestions = () => {
    const month = new Date().getMonth(); // 0-11
    if (month >= 11 || month <= 1) return ["Invierno", "Cena de Navidad", "Noche de Reyes"];
    if (month >= 2 && month <= 4) return ["Primavera", "San Valentín", "Tarde de Sol"];
    if (month >= 5 && month <= 7) return ["Verano", "Atardecer en terraza", "Picnic"];
    if (month >= 8 && month <= 10) return ["Vendimia", "Otoño", "Luz dorada"];
    return ["Todo el año"];
  };

  const getElementsForPositioning = () => {
    const isPremium = state.selectedWine?.priceLevel === 'Lujo' || state.selectedWine?.priceLevel === 'Premium';
    const common = ["Copa", "Corcho", "Botella"];
    if (isPremium) return [...common, "Cristalería tallada", "Superficie de mármol", "Uvas seleccionadas", "Guantes de seda"];
    return [...common, "Mesa de madera", "Quesos", "Uvas frescas", "Cesta de mimbre"];
  };

  const handleTextSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;
    const val = inputText.trim();
    setInputText('');

    if (state.step === 8) setState(s => ({ ...s, timeContext: val, step: 9 }));
    else if (state.step === 9) setState(s => ({ ...s, nuances: val, step: 10 }));
  };

  const startGeneration = async () => {
    setState(s => ({ ...s, isLoading: true }));
    const concepts = await generateVisualConcepts(state);
    setState(s => ({ ...s, concepts, step: 11, isLoading: false }));
  };

  const finalizeImage = async (index: number) => {
    setState(s => ({ ...s, isLoading: true, selectedConceptIndex: index, step: 12 }));
    try {
      const img = await generateFinalImage(state.selectedWine!, state, state.concepts[index], '1:1');
