              <button key={t} onClick={() => setState(s => ({ ...s, imageType: t, step: 5 }))} className="p-5 text-left bg-white border-2 border-stone-100 rounded-2xl font-bold hover:border-black transition-all">
                {t}
              </button>
            ))}
          </div>
        </div>
      )}

      {state.step === 5 && (
        <div className="space-y-6">
          {renderBubble("¿Qué estilo visual prefieres?")}
          <div className="grid grid-cols-2 gap-2">
            {["Minimalista", "Editorial", "Natural", "Lujoso", "Cotidiano"].map(s => (
              <button key={s} onClick={() => setState(s => ({ ...s, visualStyle: s, step: s === "Minimalista" ? 6 : 7 }))} className="py-4 bg-white border-2 border-stone-100 rounded-xl font-bold hover:border-black transition-all">
                {s}
              </button>
            ))}
          </div>
        </div>
      )}

      {state.step === 6 && (
        <div className="space-y-6">
          {renderBubble("Para el estilo minimalista, ¿buscas algo puro o con algunos matices?")}
          <div className="flex gap-3">
            <button onClick={() => setState(s => ({ ...s, styleSubDetail: "Muy minimal", elements: [], step: 7 }))} className={buttonPrimary}>Muy minimal</button>
            <button onClick={() => setState(s => ({ ...s, styleSubDetail: "Con elementos", step: 7 }))} className={buttonSecondary}>Con elementos</button>
          </div>
        </div>
      )}

      {state.step === 7 && (
        <div className="space-y-6">
          {state.styleSubDetail === "Muy minimal" ? (
            <>
              {renderBubble("Entendido, minimalismo puro. Vamos a la localización. ¿Dónde ocurre la escena?")}
              <div className="grid grid-cols-2 gap-2">
                {["Viñedo", "Bodega", "Restaurante", "Casa", "Estudio"].map(loc => (
                  <button key={loc} onClick={() => setState(s => ({ ...s, location: loc, step: 8 }))} className="py-4 bg-white border-2 border-stone-100 rounded-xl font-bold hover:border-black">{loc}</button>
                ))}
              </div>
            </>
          ) : (
            <>
              {renderBubble("¿Qué elementos contextuales quieres incluir?")}
              <div className="grid grid-cols-2 gap-2">
                {getElementsForPositioning().map(el => (
                  <button 
                    key={el} 
                    onClick={() => {
                      const newElements = state.elements.includes(el) ? state.elements.filter(x => x !== el) : [...state.elements, el];
                      setState(s => ({ ...s, elements: newElements }));
                    }} 
                    className={`py-4 rounded-xl border-2 font-bold ${state.elements.includes(el) ? 'bg-black text-white border-black' : 'bg-white text-stone-800 border-stone-100'}`}
                  >
                    {el}
                  </button>
                ))}
              </div>
              <button disabled={state.elements.length === 0} onClick={() => goToStep(8)} className={buttonPrimary + " mt-4 w-full"}>Continuar a Localización</button>
            </>
          )}
        </div>
      )}

      {state.step === 8 && (
        <div className="space-y-6">
          {renderBubble("¿Cuándo ocurre la escena? Sugerencias basadas en el calendario actual:")}
          <div className="flex flex-wrap gap-2">
            {getSeasonalSuggestions().map(t => (
              <button key={t} onClick={() => setState(s => ({ ...s, timeContext: t, step: 9 }))} className="px-4 py-2 bg-stone-50 border border-stone-200 rounded-full text-sm font-bold text-stone-600 hover:border-black">{t}</button>
            ))}
          </div>
          <form onSubmit={handleTextSubmit} className="flex gap-2">
            <input value={inputText} onChange={e => setInputText(e.target.value)} placeholder="O escribe otro momento..." className="flex-1 px-4 py-3 rounded-xl border-2 border-stone-100 focus:border-black outline-none" />
            <button type="submit" className="p-3 bg-black text-white rounded-xl shadow-lg"><svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="m12 5 7 7-7 7"/></svg></button>
          </form>
        </div>
      )}

      {state.step === 9 && (
        <div className="space-y-6">
          {renderBubble("Para terminar de perfilar la dirección, ¿hay algún matiz extra? (Luz, atmósfera, mood...)")}
          <form onSubmit={handleTextSubmit} className="flex gap-2">
            <textarea value={inputText} onChange={e => setInputText(e.target.value)} rows={3} placeholder="Ej: Luz lateral cálida, sombras suaves..." className="flex-1 px-5 py-4 rounded-2xl border-2 border-stone-100 focus:border-black outline-none" />
          </form>
          <button onClick={() => setState(s => ({ ...s, nuances: inputText, step: 10 }))} className={buttonPrimary + " w-full"}>Definir Detalles</button>
        </div>
      )}

      {state.step === 10 && (
        <div className="space-y-6 pt-10">
          {renderBubble("Tengo todo listo. ¿Preparamos los conceptos de dirección creativa?")}
          <button onClick={startGeneration} className="w-full bg-black text-white py-8 rounded-[2.5rem] font-bold shadow-2xl flex items-center justify-center gap-4 text-2xl animate-bounce">
            <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m12 3-1.912 5.813a2 2 0 0 1-1.275 1.275L3 12l5.813 1.912a2 2 0 0 1 1.275 1.275L12 21l1.912-5.813a2 2 0 0 1 1.275-1.275L21 12l-5.813-1.912a2 2 0 0 1-1.275-1.275L12 3Z"/></svg>
            Crear Conceptos
          </button>
        </div>
      )}

      {state.step === 11 && (
        <div className="space-y-8 animate-in zoom-in-95 duration-500">
          {renderBubble("Aquí tienes mis propuestas de dirección:")}
          <div className="space-y-4">
            {state.concepts.map((c, i) => (
              <button key={i} onClick={() => finalizeImage(i)} className="w-full p-7 bg-white border-2 border-stone-100 rounded-[2rem] text-left hover:border-black transition-all shadow-sm active:scale-95">
                <p className="text-stone-800 font-medium italic text-lg leading-relaxed">"{c}"</p>
                <div className="mt-4 text-[10px] font-black uppercase tracking-widest text-stone-400">Seleccionar este concepto</div>
              </button>
            ))}
            <button onClick={startGeneration} className="w-full py-4 border-2 border-dashed border-stone-200 text-stone-400 font-bold rounded-2xl hover:text-black hover:border-black">Proponer otras ideas</button>
          </div>
        </div>
      )}

      {state.step === 12 && state.imageHistory.length > 0 && (
        <div className="space-y-8 animate-in fade-in duration-1000">
          <div className="rounded-[3rem] overflow-hidden border border-stone-100 shadow-2xl aspect-square relative bg-white">
            <img src={state.imageHistory[0]} alt="Arte Final" className="w-full h-full object-cover" />
          </div>
          <div className="bg-stone-50 p-7 rounded-[2rem] border border-stone-100 italic text-stone-600 text-center font-medium shadow-inner">
            "{state.concepts[state.selectedConceptIndex || 0]}"
          </div>
          <div className="flex flex-col gap-4">
            <div className="flex gap-4 justify-center">
              <button onClick={() => setState(s => ({ ...s, feedback: 'like' }))} className={`p-5 rounded-full transition-all ${state.feedback === 'like' ? 'bg-green-100 text-green-600 scale-110' : 'bg-stone-100 text-stone-400'}`}>
                <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M7 10v12"/><path d="M15 5.88 14 10h5.83a2 2 0 0 1 1.92 2.56l-2.33 8A2 2 0 0 1 17.5 22H4a2 2 0 0 1-2-2v-8a2 2 0 0 1 2-2h2.76a2 2 0 0 0 1.79-1.11L12 2h0a3.13 3.13 0 0 1 3 3.88Z"/></svg>
              </button>
              <button onClick={() => setState(s => ({ ...s, feedback: 'dislike' }))} className={`p-5 rounded-full transition-all ${state.feedback === 'dislike' ? 'bg-red-100 text-red-600 scale-110' : 'bg-stone-100 text-stone-400'}`}>
                <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M17 14V2"/><path d="M9 18.12 10 14H4.17a2 2 0 0 1-1.92-2.56l2.33-8A2 2 0 0 1 6.5 2H20a2 2 0 0 1 2 2v8a2 2 0 0 1-2 2h-2.76a2 2 0 0 0-1.79 1.11L12 22h0a3.13 3.13 0 0 1-3-3.88Z"/></svg>
              </button>
            </div>
            <button onClick={onFinish} className="w-full bg-black text-white py-6 rounded-[2rem] font-bold shadow-xl active:scale-95 transition-all text-xl">Finalizar Sesión</button>
          </div>
        </div>
      )}

      {state.error && (
        <div className="mt-8 p-6 bg-red-50 text-red-600 rounded-2xl font-bold text-center border border-red-100">
          {state.error}
          <button onClick={() => window.location.reload()} className="block mx-auto mt-2 underline">Reintentar</button>
        </div>
      )}

      <div ref={scrollRef} className="h-10 w-full" />
    </div>
  );
};

export default CreativeFunnel;

import React, { useState, useEffect } from 'react';
import Layout from './components/Layout';
import WineList from './components/WineList';
import WineForm from './components/WineForm';
import CreativeFunnel from './components/CreativeFunnel';
import Gallery from './components/Gallery';
import ErrorBoundary from './components/ErrorBoundary';
import { Wine, AppScreen, GalleryImage } from './types';

const App: React.FC = () => {
  const [screen, setScreen] = useState<AppScreen>(AppScreen.HOME);
  const [funnelKey, setFunnelKey] = useState(0);
  const [wines, setWines] = useState<Wine[]>(() => {
    const saved = localStorage.getItem('kinglab_wines_v4');
    return saved ? JSON.parse(saved) : [];
  });
  const [gallery, setGallery] = useState<GalleryImage[]>(() => {
    const saved = localStorage.getItem('kinglab_gallery_v5');
    return saved ? JSON.parse(saved) : [];
  });
  const [selectedWineForEdit, setSelectedWineForEdit] = useState<Wine | null>(null);

  useEffect(() => { localStorage.setItem('kinglab_wines_v4', JSON.stringify(wines)); }, [wines]);
  useEffect(() => { localStorage.setItem('kinglab_gallery_v5', JSON.stringify(gallery)); }, [gallery]);

  const handleSaveWine = (wine: Wine) => {
    setWines(prev => {
      const exists = prev.find(w => w.id === wine.id);
      if (exists) return prev.map(w => w.id === wine.id ? wine : w);
      return [wine, ...prev];
    });
    setScreen(AppScreen.HOME);
    setSelectedWineForEdit(null);
  };

  const handleBack = () => {
    if (screen === AppScreen.FORM) setScreen(wines.length === 0 ? AppScreen.HOME : AppScreen.MANAGE);
    else setScreen(AppScreen.HOME);
    setSelectedWineForEdit(null);
  };

  const startNewSession = () => {
    setFunnelKey(prev => prev + 1);
    setScreen(AppScreen.FUNNEL);
  };

  const getTitle = () => {
    if (screen === AppScreen.HOME) return 'Kinglab Bodegas 202';
    if (screen === AppScreen.FUNNEL) return 'Dirección Creativa';
    if (screen === AppScreen.MANAGE) return 'Mis Productos';
    if (screen === AppScreen.GALLERY) return 'Galería Editorial';
    if (screen === AppScreen.FORM) return selectedWineForEdit ? 'Editar Producto' : 'Dar de alta un vino';
    return screen;
  };

  return (
    <ErrorBoundary>
      <Layout 
        title={getTitle()} 
        onBack={screen !== AppScreen.HOME ? handleBack : undefined}
        onGear={() => setScreen(AppScreen.MANAGE)}
        onGallery={() => setScreen(AppScreen.GALLERY)}
        showGear={screen === AppScreen.HOME}
        showGallery={gallery.length > 0 && screen === AppScreen.HOME}
      >
        {screen === AppScreen.HOME && (
          <div className="space-y-12 py-6 animate-in fade-in duration-700">
            <div className="text-center space-y-4 px-6">
              <h2 className="text-6xl font-serif font-bold text-black tracking-tight">Kinglab</h2>
              <p className="text-stone-400 font-medium italic text-lg leading-relaxed max-w-sm mx-auto">Excelencia en dirección de arte para el sector vinícola.</p>
            </div>

            <div className="bg-white p-12 rounded-[3rem] border-2 border-stone-100 text-center space-y-8 shadow-sm max-w-lg mx-auto">
              <div className="w-16 h-16 bg-stone-50 rounded-full flex items-center justify-center mx-auto text-black border border-stone-100">
                <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><path d="M12 2v20"/><path d="M17 5H9.5a3.5 3.5 0 0 0 0 7h5a3.5 3.5 0 0 1 0 7H6"/></svg>
              </div>
              <div className="space-y-3">
                <h3 className="text-2xl font-serif font-bold">Mesa de Trabajo</h3>
                <p className="text-stone-400 font-medium leading-snug">Inicia una nueva sesión de dirección creativa profesional.</p>
              </div>
              <button 
                onClick={() => wines.length > 0 ? startNewSession() : setScreen(AppScreen.FORM)} 
                className="w-full bg-black text-white px-8 py-6 rounded-3xl font-bold shadow-2xl active:scale-95 transition-all text-xl"
              >
                {wines.length > 0 ? "Comenzar Sesión" : "Dar de alta un vino"}
              </button>
            </div>

            {wines.length > 0 && (
              <div className="text-center">
                <button onClick={() => setScreen(AppScreen.FORM)} className="text-stone-400 font-black text-[10px] uppercase tracking-widest border-b-2 border-stone-200 pb-1 hover:text-black hover:border-black transition-all">
                  Registrar otro producto
                </button>
              </div>
            )}

            {gallery.length > 0 && (
              <div className="space-y-8 px-2">
                <div className="flex justify-between items-end px-4">
                  <h4 className="font-serif font-bold text-3xl text-black">Explorar Galería</h4>
                  <button onClick={() => setScreen(AppScreen.GALLERY)} className="text-black font-black text-[10px] uppercase tracking-widest border-b-2 border-black pb-1 active:opacity-50">Ver todo</button>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  {gallery.slice(0, 4).map(img => (
                    <div key={img.id} onClick={() => setScreen(AppScreen.GALLERY)} className="aspect-square rounded-[2rem] overflow-hidden border border-stone-100 shadow-sm cursor-pointer active:scale-95 transition-all">
                      <img src={img.url} className="w-full h-full object-cover" alt={img.wineName} />
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        )}

        {screen === AppScreen.FUNNEL && (
          <CreativeFunnel 
            key={funnelKey}
            wines={wines} 
            onFinish={() => setScreen(AppScreen.HOME)} 
            onSaveToGallery={(img) => setGallery(prev => [img, ...prev])} 
          />
        )}

        {screen === AppScreen.GALLERY && (
          <Gallery images={gallery} onBack={() => setScreen(AppScreen.HOME)} onRegenerate={() => {}} onAdjust={() => {}} />
        )}

        {screen === AppScreen.MANAGE && (
          <WineList wines={wines} onEdit={(w) => { setSelectedWineForEdit(w); setScreen(AppScreen.FORM); }} onAdd={() => { setSelectedWineForEdit(null); setScreen(AppScreen.FORM); }} />
        )}

        {screen === AppScreen.FORM && (
          <WineForm initialWine={selectedWineForEdit || undefined} onSave={handleSaveWine} onCancel={handleBack} />
        )}
      </Layout>
    </ErrorBoundary>
  );
};

export default App;

import React, { useState } from 'react';
import { Wine, ImageType, AspectRatio, FunnelState } from '../types';
// Fixed: Using generateFinalImage as generateWineImage does not exist in geminiService.ts
import { generateFinalImage } from '../services/geminiService';

interface ImageGeneratorProps {
  wines: Wine[];
  initialSelectedWine?: Wine;
}

const ImageGenerator: React.FC<ImageGeneratorProps> = ({ wines, initialSelectedWine }) => {
  const [selectedWine, setSelectedWine] = useState<Wine | null>(initialSelectedWine || wines[0] || null);
  const [ratio, setRatio] = useState<AspectRatio>('1:1');
  const [type, setType] = useState<ImageType>(ImageType.BODEGON);
  const [context, setContext] = useState('');
  const [loading, setLoading] = useState(false);
  const [generatedImage, setGeneratedImage] = useState<string | null>(null);

  const handleGenerate = async () => {
    if (!selectedWine) return;
    setLoading(true);
    try {
      // Fixed: Constructing a proper concept and matching the 4-argument signature of generateFinalImage.
      const concept = context.trim() || `Fotografía publicitaria profesional de ${selectedWine.name}, estilo ${type}.`;

      // Creating a mock FunnelState to satisfy the service requirements.
      // Removed 'wineName' and fixed property names and required arrays/strings.
      const mockState: Partial<FunnelState> = {
        visualStyle: type,
        styleSubDetail: context || 'Estilo publicitario editorial',
        elements: [],
        nuances: '',
        location: 'Estudio fotográfico',
        timeContext: 'Iluminación de estudio',
        locationImage: null
      };

      // Fixed: Passing the whole selectedWine object as required by generateFinalImage signature.
      const result = await generateFinalImage(
        selectedWine, 
        mockState as FunnelState, 
        concept, 
        ratio
      );
      setGeneratedImage(result);
    } catch (error) {
      console.error("Generation error:", error);
      alert("Error al generar la imagen. Verifica tu conexión o API Key.");
    } finally {
      setLoading(false);
    }
  };

  // Fix: changed '4:5' to '3:4' to match AspectRatio type definition in types.ts (allowed values: '1:1' | '3:4' | '4:3' | '9:16' | '16:9')
  const ratios: AspectRatio[] = ['1:1', '3:4', '9:16', '16:9'];
  const types = Object.values(ImageType);

  const labelClasses = "block text-sm font-semibold text-stone-700 mb-2";

  return (
    <div className="space-y-8 pb-10">
      {!generatedImage ? (
        <div className="space-y-8 animate-in fade-in slide-in-from-bottom-2 duration-300">
          {/* WINE SELECTOR */}
          <div>
            <label className={labelClasses}>Seleccionar vino</label>
            <select
              className="w-full px-4 py-3 rounded-lg border border-stone-200 focus:ring-2 focus:ring-black outline-none bg-white text-black"
              value={selectedWine?.id || ''}
              onChange={(e) => setSelectedWine(wines.find(w => w.id === e.target.value) || null)}
            >
              {wines.map(w => (
                <option key={w.id} value={w.id}>{w.name}</option>
              ))}
            </select>
          </div>

          {/* RATIO BUTTONS */}
          <div className="space-y-3">
            <label className={labelClasses}>Formato de imagen</label>
            <div className="grid grid-cols-4 gap-2">
              {ratios.map(r => (
                <button
                  key={r}
                  onClick={() => setRatio(r)}
                  className={`py-3 rounded-lg border text-sm font-medium transition-all ${
                    ratio === r 
                    ? 'bg-black text-white border-black shadow-md' 
                    : 'bg-white text-stone-600 border-stone-200 hover:border-stone-400'
                  }`}
                >
                  {r}
                </button>
              ))}
            </div>
          </div>

          {/* TYPE BUTTONS */}
          <div className="space-y-3">
            <label className={labelClasses}>Tipo de imagen</label>
            <div className="grid grid-cols-1 gap-2">
              {types.map(t => (
                <button
                  key={t}
                  onClick={() => setType(t)}
                  className={`py-4 rounded-xl border text-left px-5 font-semibold transition-all ${
                    type === t 
                    ? 'bg-black text-white border-black shadow-md' 
                    : 'bg-white text-stone-600 border-stone-200 hover:border-stone-400'
                  }`}
                >
                  {t}
                </button>
              ))}
            </div>
          </div>

          {/* OPTIONAL CONTEXT */}
          <div className="space-y-2">
            <label className={labelClasses}>Idea o contexto (opcional)</label>
            <textarea
              value={context}
              onChange={(e) => setContext(e.target.value)}
              className="w-full px-4 py-3 rounded-lg border border-stone-200 focus:ring-2 focus:ring-black outline-none bg-white text-black placeholder-stone-400 transition-all"
              placeholder="Ej: Bodega antigua con barricas al fondo..."
              rows={3}
            />
          </div>

          <button
            onClick={handleGenerate}
            disabled={loading || !selectedWine}
            className={`w-full py-5 rounded-2xl font-bold text-white shadow-xl flex items-center justify-center gap-3 transition-all ${
              loading ? 'bg-stone-400 cursor-not-allowed' : 'bg-black shadow-black/10 active:scale-[0.98]'
            }`}
          >
            {loading ? (
              <>
                <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                Generando arte...
              </>
            ) : (
              <>
                <svg xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m12 3-1.912 5.813a2 2 0 0 1-1.275 1.275L3 12l5.813 1.912a2 2 0 0 1 1.275 1.275L12 21l1.912-5.813a2 2 0 0 1 1.275-1.275L21 12l-5.813-1.912a2 2 0 0 1-1.275-1.275L12 3Z"/></svg>
                Generar imagen
              </>
            )}
          </button>
        </div>
      ) : (
        <div className="space-y-6 animate-in zoom-in-95 duration-500">
          <div className="relative group overflow-hidden rounded-2xl border border-stone-200 shadow-2xl bg-white">
            <img src={generatedImage} alt="Generated result" className="w-full h-auto" />
          </div>
          <div className="flex gap-4">
            <button
              onClick={() => setGeneratedImage(null)}
              className="flex-1 bg-stone-100 text-stone-700 py-4 rounded-xl font-bold hover:bg-stone-200 transition-all"
            >
              Volver
            </button>
            <a
              href={generatedImage}
              download={`kinglab-${selectedWine?.name || 'vin'}-${Date.now()}.png`}
              className="flex-1 bg-black text-white py-4 rounded-xl font-bold text-center shadow-lg shadow-black/10 hover:bg-stone-900 transition-all"
            >
              Descargar
            </a>
          </div>
        </div>
      )}
    </div>
  );
};

export default ImageGenerator;

import React, { useState, useEffect, useRef } from 'react';
import { Wine, ImageType, FunnelState, GalleryImage, AnalysisResult } from '../types';
import { analyzePublicPerception, generateVisualConcepts, generateFinalImage } from '../services/geminiService';

interface CreativeFunnelProps {
  wines: Wine[];
  onFinish: () => void;
  onSaveToGallery: (img: GalleryImage) => void;
}

const CreativeFunnel: React.FC<CreativeFunnelProps> = ({ wines, onFinish, onSaveToGallery }) => {
  const [state, setState] = useState<FunnelState>({
    step: 1,
    selectedWine: null,
    analysisChoice: null,
    analysisResult: null,
    useAnalysis: null,
    imageType: null,
    visualStyle: null,
    styleSubDetail: null,
    elements: [],
    location: null,
    locationImage: null,
    timeContext: '',
    nuances: '',
    concepts: [],
    selectedConceptIndex: null,
    imageHistory: [],
    isLoading: false,
    error: null,
    feedback: null
  });

  const [inputText, setInputText] = useState('');
  const fileInputRef = useRef<HTMLInputElement>(null);
  const scrollRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    scrollRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [state.step, state.isLoading]);

  const goToStep = (step: number) => setState(s => ({ ...s, step }));

  const handleAnalysisChoice = async (choice: boolean) => {
    if (choice) {
      setState(s => ({ ...s, isLoading: true, analysisChoice: true }));
      try {
        const result = await analyzePublicPerception(state.selectedWine!.name);
        setState(s => ({ ...s, analysisResult: result, step: 3, isLoading: false }));
      } catch (e) {
        setState(s => ({ ...s, error: "Error en el análisis digital. Continuando sin él.", step: 4, isLoading: false }));
      }
    } else {
      setState(s => ({ ...s, analysisChoice: false, step: 4 }));
    }
  };

  const getSeasonalSuggestions = () => {
    const month = new Date().getMonth(); // 0-11
    if (month >= 11 || month <= 1) return ["Invierno", "Cena de Navidad", "Noche de Reyes"];
    if (month >= 2 && month <= 4) return ["Primavera", "San Valentín", "Tarde de Sol"];
    if (month >= 5 && month <= 7) return ["Verano", "Atardecer en terraza", "Picnic"];
    if (month >= 8 && month <= 10) return ["Vendimia", "Otoño", "Luz dorada"];
    return ["Todo el año"];
  };

  const getElementsForPositioning = () => {
    const isPremium = state.selectedWine?.priceLevel === 'Lujo' || state.selectedWine?.priceLevel === 'Premium';
    const common = ["Copa", "Corcho", "Botella"];
    if (isPremium) return [...common, "Cristalería tallada", "Superficie de mármol", "Uvas seleccionadas", "Guantes de seda"];
    return [...common, "Mesa de madera", "Quesos", "Uvas frescas", "Cesta de mimbre"];
  };

  const handleTextSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!inputText.trim()) return;
    const val = inputText.trim();
    setInputText('');

    if (state.step === 8) setState(s => ({ ...s, timeContext: val, step: 9 }));
    else if (state.step === 9) setState(s => ({ ...s, nuances: val, step: 10 }));
  };

  const startGeneration = async () => {
    setState(s => ({ ...s, isLoading: true }));
    const concepts = await generateVisualConcepts(state);
    setState(s => ({ ...s, concepts, step: 11, isLoading: false }));
  };

  const finalizeImage = async (index: number) => {
    setState(s => ({ ...s, isLoading: true, selectedConceptIndex: index, step: 12 }));
    try {
      const img = await generateFinalImage(state.selectedWine!, state, state.concepts[index], '1:1');
      if (img) {
        setState(s => ({ ...s, imageHistory: [img], isLoading: false }));
        onSaveToGallery({
          id: Date.now().toString(),
          url: img,
          concept: state.concepts[index],
          wineName: state.selectedWine!.name,
          timestamp: Date.now()
        });
      }
    } catch (e) {
      setState(s => ({ ...s, error: "Fallo en la generación visual. Reintenta.", isLoading: false }));
    }
  };

  const renderBubble = (text: string, isAssistant = true) => (
    <div className={`flex ${isAssistant ? 'justify-start' : 'justify-end'} mb-6 animate-in fade-in slide-in-from-${isAssistant ? 'left' : 'right'}-4`}>
      <div className={`max-w-[85%] p-5 rounded-3xl ${isAssistant ? 'bg-stone-100 text-stone-800 rounded-tl-none' : 'bg-black text-white rounded-tr-none shadow-xl'} font-medium`}>
        {text}
      </div>
    </div>
  );

  const buttonPrimary = "flex-1 py-5 bg-black text-white rounded-2xl font-bold shadow-xl active:scale-95 transition-all text-center";
  const buttonSecondary = "flex-1 py-5 bg-white border-2 border-stone-100 text-stone-800 rounded-2xl font-bold active:scale-95 transition-all text-center hover:border-black";

  if (state.isLoading) {
    return (
      <div className="flex flex-col items-center justify-center py-32 space-y-8">
        <div className="w-12 h-12 border-4 border-stone-100 border-t-black rounded-full animate-spin" />
        <div className="text-center">
          <h3 className="text-2xl font-serif font-bold text-black italic">Kinglab está diseñando...</h3>
          <p className="text-stone-400 font-medium">Capturando la esencia de tu vino.</p>
        </div>
      </div>
    );
  }

  return (
    <div className="flex flex-col max-w-lg mx-auto pb-20">
      {/* PHASE 1 (Wine Selection if multiple, or auto-pick) */}
      {state.step === 1 && (
        <div className="space-y-6">
          {renderBubble("¡Hola! Soy tu Director Creativo. ¿Sobre qué vino registrado quieres que trabajemos hoy?")}
          <div className="grid gap-3">
            {wines.map(w => (
              <button key={w.id} onClick={() => setState(s => ({ ...s, selectedWine: w, step: 2 }))} className="p-5 bg-white border-2 border-stone-100 rounded-2xl text-left font-bold flex items-center gap-4 hover:border-black transition-all group">
                <img src={w.image} className="w-12 h-12 object-contain" alt={w.name} />
                <div className="flex-1">
                  <p className="text-lg">{w.name}</p>
                  <p className="text-xs text-stone-400 uppercase tracking-widest">{w.priceLevel}</p>
                </div>
                <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className="opacity-0 group-hover:opacity-100"><path d="m9 18 6-6-6-6"/></svg>
              </button>
            ))}
          </div>
        </div>
      )}

      {/* PHASE 2: Analysis Choice */}
      {state.step === 2 && (
        <div className="space-y-6">
          {renderBubble(`Excelente elección: ${state.selectedWine?.name}.`)}
          {renderBubble("¿Quieres que analicemos cómo se percibe este vino en el entorno digital antes de empezar la dirección creativa?")}
          <div className="flex gap-3">
            <button onClick={() => handleAnalysisChoice(true)} className={buttonPrimary}>Analizar mercado</button>
            <button onClick={() => handleAnalysisChoice(false)} className={buttonSecondary}>Saltar análisis</button>
          </div>
        </div>
      )}

      {/* STEP 3: Analysis Results */}
      {state.step === 3 && state.analysisResult && (
        <div className="space-y-6">
          {renderBubble("He analizado la percepción digital fuera de tus canales oficiales:")}
          <div className="bg-stone-50 p-7 rounded-[2rem] border border-stone-200 space-y-6 animate-in zoom-in-95">
            <p className="text-stone-700 italic leading-relaxed text-lg">{state.analysisResult.summary}</p>
            <div className="flex flex-col gap-2">
              <button 
                onClick={() => {
                  const blob = new Blob([state.analysisResult?.fullReport || ''], { type: 'text/plain' });
                  const url = URL.createObjectURL(blob);
                  const a = document.createElement('a'); a.href = url; a.download = `Analisis_${state.selectedWine?.name}.txt`; a.click();
                }}
                className="text-xs font-black uppercase tracking-widest text-black border-b-2 border-black inline-block pb-1 w-fit"
              >
                Descargar informe completo
              </button>
            </div>
          </div>
          {renderBubble("¿Quieres que tengamos en cuenta este análisis para los conceptos visuales?")}
          <div className="flex gap-3">
            <button onClick={() => setState(s => ({ ...s, useAnalysis: true, step: 4 }))} className={buttonPrimary}>Tenerlo en cuenta</button>
            <button onClick={() => setState(s => ({ ...s, useAnalysis: false, step: 4 }))} className={buttonSecondary}>Descartarlo</button>
          </div>
        </div>
      )}

      {/* PHASE 3: Creative Direction (Conditional) */}
      {state.step === 4 && (
        <div className="space-y-6">
          {renderBubble("Comencemos con la dirección creativa. ¿Qué tipo de imagen quieres crear?")}
          <div className="grid gap-2">
            {Object.values(ImageType).map(t => (
              <button key={t} onClick={() => setState(s => ({ ...s, imageType: t, step: 5 }))} className="p-5 text-left bg-white border-2 border-stone-100 rounded-2xl font-bold hover:border-black transition-all">
                {t}
              </button>
            ))}
          </div>
        </div>
      )}

      {state.step === 5 && (
        <div className="space-y-6">
          {renderBubble("¿Qué estilo visual prefieres?")}
          <div className="grid grid-cols-2 gap-2">
            {/* Fixed: Renamed map iterator to 'style' to avoid shadowing state 's' */}
            {["Minimalista", "Editorial", "Natural", "Lujoso", "Cotidiano"].map(style => (
              <button 
                key={style} 
                onClick={() => setState(prev => ({ ...prev, visualStyle: style, step: style === "Minimalista" ? 6 : 7 }))} 
                className="py-4 bg-white border-2 border-stone-100 rounded-xl font-bold hover:border-black transition-all"
              >
                {style}
              </button>
            ))}
          </div>
        </div>
      )}

      {state.step === 6 && (
        <div className="space-y-6">
          {renderBubble("Para el estilo minimalista, ¿buscas algo puro o con algunos matices?")}
          <div className="flex gap-3">
            <button onClick={() => setState(s => ({ ...s, styleSubDetail: "Muy minimal", elements: [], step: 7 }))} className={buttonPrimary}>Muy minimal</button>
            <button onClick={() => setState(s => ({ ...s, styleSubDetail: "Con elementos", step: 7 }))} className={buttonSecondary}>Con elementos</button>
          </div>
        </div>
      )}

      {state.step === 7 && (
        <div className="space-y-6">
          {state.styleSubDetail === "Muy minimal" ? (
            <>
              {renderBubble("Entendido, minimalismo puro. Vamos a la localización. ¿Dónde ocurre la escena?")}
              <div className="grid grid-cols-2 gap-2">
                {["Viñedo", "Bodega", "Restaurante", "Casa", "Estudio"].map(loc => (
                  <button key={loc} onClick={() => setState(s => ({ ...s, location: loc, step: 8 }))} className="py-4 bg-white border-2 border-stone-100 rounded-xl font-bold hover:border-black">{loc}</button>
                ))}
              </div>
            </>
          ) : (
            <>
              {renderBubble("¿Qué elementos contextuales quieres incluir?")}
              <div className="grid grid-cols-2 gap-2">
                {getElementsForPositioning().map(el => (
                  <button 
                    key={el} 
                    onClick={() => {
                      const newElements = state.elements.includes(el) ? state.elements.filter(x => x !== el) : [...state.elements, el];
                      setState(s => ({ ...s, elements: newElements }));
                    }} 
                    className={`py-4 rounded-xl border-2 font-bold ${state.elements.includes(el) ? 'bg-black text-white border-black' : 'bg-white text-stone-800 border-stone-100'}`}
                  >
                    {el}
                  </button>
                ))}
              </div>
              <button disabled={state.elements.length === 0} onClick={() => goToStep(8)} className={buttonPrimary + " mt-4 w-full"}>Continuar a Localización</button>
            </>
          )}
        </div>
      )}

      {state.step === 8 && (
        <div className="space-y-6">
          {renderBubble("¿Cuándo ocurre la escena? Sugerencias basadas en el calendario actual:")}
          <div className="flex flex-wrap gap-2">
            {getSeasonalSuggestions().map(t => (
              <button key={t} onClick={() => setState(s => ({ ...s, timeContext: t, step: 9 }))} className="px-4 py-2 bg-stone-50 border border-stone-200 rounded-full text-sm font-bold text-stone-600 hover:border-black">{t}</button>
            ))}
          </div>
          <form onSubmit={handleTextSubmit} className="flex gap-2">
            <input value={inputText} onChange={e => setInputText(e.target.value)} placeholder="O escribe otro momento..." className="flex-1 px-4 py-3 rounded-xl border-2 border-stone-100 focus:border-black outline-none" />
            <button type="submit" className="p-3 bg-black text-white rounded-xl shadow-lg"><svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14"/><path d="m12 5 7 7-7 7"/></svg></button>
          </form>
        </div>
      )}

      {state.step === 9 && (
        <div className="space-y-6">
          {renderBubble("Para terminar de perfilar la dirección, ¿hay algún matiz extra? (Luz, atmósfera, mood...)")}
          <form onSubmit={handleTextSubmit} className="flex gap-2">
            <textarea value={inputText} onChange={e => setInputText(e.target.value)} rows={3} placeholder="Ej: Luz lateral cálida, sombras suaves..." className="flex-1 px-5 py-4 rounded-2xl border-2 border-stone-100 focus:border-black outline-none" />
          </form>
          <button onClick={() => setState(s => ({ ...s, nuances: inputText, step: 10 }))} className={buttonPrimary + " w-full"}>Definir Detalles</button>
        </div>
      )}

      {state.step === 10 && (
        <div className="space-y-6 pt-10">
          {renderBubble("Tengo todo listo. ¿Preparamos los conceptos de dirección creativa?")}
          <button onClick={startGeneration} className="w-full bg-black text-white py-8 rounded-[2.5rem] font-bold shadow-2xl flex items-center justify-center gap-4 text-2xl animate-bounce">
            <svg xmlns="http://www.w3.org/2000/svg" width="32" height="32" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="m12 3-1.912 5.813a2 2 0 0 1-1.275 1.275L3 12l5.813 1.912a2 2 0 0 1 1.275 1.275L12 21l1.912-5.813a2 2 0 0 1 1.275-1.275L21 12l-5.813-1.912a2 2 0 0 1-1.275-1.275L12 3Z"/></svg>
            Crear Conceptos
          </button>
        </div>
      )}

      {state.step === 11 && (
        <div className="space-y-8 animate-in zoom-in-95 duration-500">
          {renderBubble("Aquí tienes mis propuestas de dirección:")}
          <div className="space-y-4">
            {state.concepts.map((c, i) => (
              <button key={i} onClick={() => finalizeImage(i)} className="w-full p-7 bg-white border-2 border-stone-100 rounded-[2rem] text-left hover:border-black transition-all shadow-sm active:scale-95">
                <p className="text-stone-800 font-medium italic text-lg leading-relaxed">"{c}"</p>
                <div className="mt-4 text-[10px] font-black uppercase tracking-widest text-stone-400">Seleccionar este concepto</div>
              </button>
            ))}
            <button onClick={startGeneration} className="w-full py-4 border-2 border-dashed border-stone-200 text-stone-400 font-bold rounded-2xl hover:text-black hover:border-black">Proponer otras ideas</button>
          </div>
        </div>
      )}

      {state.step === 12 && state.imageHistory.length > 0 && (
        <div className="space-y-8 animate-in fade-in duration-1000">
          <div className="rounded-[3rem] overflow-hidden border border-stone-100 shadow-2xl aspect-square relative bg-white">
            <img src={state.imageHistory[0]} alt="Arte Final" className="w-full h-full object-cover" />
          </div>
          <div className="bg-stone-50 p-7 rounded-[2rem] border border-stone-100 italic text-stone-600 text-center font-medium shadow-inner">
            "{state.concepts[state.selectedConceptIndex || 0]}"
          </div>
          <div className="flex flex-col gap-4">
            <div className="flex gap-4 justify-center">
              <button onClick={() => setState(s => ({ ...s, feedback: 'like' }))} className={`p-5 rounded-full transition-all ${state.feedback === 'like' ? 'bg-green-100 text-green-600 scale-110' : 'bg-stone-100 text-stone-400'}`}>
                <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M7 10v12"/><path d="M15 5.88 14 10h5.83a2 2 0 0 1 1.92 2.56l-2.33 8A2 2 0 0 1 17.5 22H4a2 2 0 0 1-2-2v-8a2 2 0 0 1 2-2h2.76a2 2 0 0 0 1.79-1.11L12 2h0a3.13 3.13 0 0 1 3 3.88Z"/></svg>
              </button>
              <button onClick={() => setState(s => ({ ...s, feedback: 'dislike' }))} className={`p-5 rounded-full transition-all ${state.feedback === 'dislike' ? 'bg-red-100 text-red-600 scale-110' : 'bg-stone-100 text-stone-400'}`}>
                <svg xmlns="http://www.w3.org/2000/svg" width="28" height="28" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M17 14V2"/><path d="M9 18.12 10 14H4.17a2 2 0 0 1-1.92-2.56l2.33-8A2 2 0 0 1 6.5 2H20a2 2 0 0 1 2 2v8a2 2 0 0 1-2 2h-2.76a2 2 0 0 0-1.79 1.11L12 22h0a3.13 3.13 0 0 1-3-3.88Z"/></svg>
              </button>
            </div>
            <button onClick={onFinish} className="w-full bg-black text-white py-6 rounded-[2rem] font-bold shadow-xl active:scale-95 transition-all text-xl">Finalizar Sesión</button>
          </div>
        </div>
      )}

      {state.error && (
        <div className="mt-8 p-6 bg-red-50 text-red-600 rounded-2xl font-bold text-center border border-red-100">
          {state.error}
          <button onClick={() => window.location.reload()} className="block mx-auto mt-2 underline">Reintentar</button>
        </div>
      )}

      <div ref={scrollRef} className="h-10 w-full" />
    </div>
  );
};

