            <p className="text-red-600 font-bold px-8">{state.error}</p>
            {latestImage && (
               <div className="max-w-[150px] mx-auto opacity-50 mb-4">
                 <img src={latestImage} alt="Last valid" className="rounded-xl border" />
               </div>
