import React, { Component, ErrorInfo, ReactNode } from 'react';

interface Props {
  children: ReactNode;
}

interface State {
  hasError: boolean;
}

// Fixed: Explicitly defining the component class with props and state types to resolve property access issues.
class ErrorBoundary extends Component<Props, State> {
  public state: State = {
    hasError: false
  };

  public static getDerivedStateFromError(_: Error): State {
    return { hasError: true };
  }

  public componentDidCatch(error: Error, errorInfo: ErrorInfo) {
    console.error("Uncaught error:", error, errorInfo);
  }

  public render() {
    if (this.state.hasError) {
      return (
        <div className="min-h-[60vh] flex flex-col items-center justify-center p-8 text-center space-y-6">
          <div className="w-20 h-20 bg-stone-100 rounded-full flex items-center justify-center text-stone-400">
            <svg xmlns="http://www.w3.org/2000/svg" width="40" height="40" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5" strokeLinecap="round" strokeLinejoin="round"><circle cx="12" cy="12" r="10"/><line x1="12" y1="8" x2="12" y2="12"/><line x1="12" y1="16" x2="12.01" y2="16"/></svg>
          </div>
          <div className="space-y-2">
            <h2 className="text-2xl font-serif font-bold text-black">Algo no ha salido como esperábamos</h2>
            <p className="text-stone-500 max-w-xs mx-auto">Se ha producido un error inesperado en la mesa de trabajo.</p>
          </div>
          <button 
            onClick={() => window.location.reload()} 
            className="bg-black text-white px-8 py-4 rounded-2xl font-bold shadow-xl active:scale-95 transition-all"
          >
            Reiniciar aplicación
          </button>
        </div>
      );
    }

    // Fixed: Wrapping children in a fragment to ensure a valid return type and clear property context.
    return <>{this.props.children}</>;
  }
}

export default ErrorBoundary;

import { GoogleGenAI, Type } from "@google/genai";
import { Wine, ImageType, FunnelState } from "../types";

// Fixed: Updated analyzePerception to extract groundingChunks and append URLs to the result as mandated by the guidelines for Search Grounding.
export const analyzePerception = async (wineName: string): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const prompt = `Analiza la percepción pública y de expertos del vino o bodega "${wineName}" en entornos digitales (redes sociales, foros, reseñas, prensa especializada). 
  REGLA CRÍTICA: NO incluyas información del sitio web oficial de la bodega ni de sus propios canales de redes sociales. 
  Queremos saber qué dice el público "fuera de casa".

  Devuelve un resumen de EXACTAMENTE DOS PÁRRAFOS en español.`;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        tools: [{ googleSearch: {} }],
      }
    });

    let text = response.text || "No se pudo obtener información externa suficiente para realizar el análisis.";

    // Extracting and listing website URLs from groundingChunks as required.
    const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    if (groundingChunks) {
      const urls = groundingChunks
        .map((chunk: any) => chunk.web?.uri)
        .filter((uri: string | undefined): uri is string => !!uri);

      if (urls.length > 0) {
        const uniqueUrls = Array.from(new Set(urls));
        text += "\n\nFuentes consultadas:\n" + uniqueUrls.join("\n");
      }
    }

    return text;
  } catch (error) {
    console.error("Error analyzing perception:", error);
    return "Ocurrió un error al intentar acceder a los datos de percepción digital.";
  }
};

export const generateVisualConcepts = async (wine: Wine, state: FunnelState): Promise<string[]> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const isMuyMinimal = state.type === ImageType.BODEGON && state.selections['limpieza'] === 'Muy minimal';

  const prompt = `
    Eres un Director Creativo experto en fotografía de vinos para Kinglab Bodegas 202.
    Tu tarea es generar 3 conceptos visuales que reflejen la esencia de este producto específico.

    PRODUCTO (CONTEXTO ACTIVO - Prioriza estos valores en el estilo):
    - Nombre: ${wine.name}
    - Carácter: ${wine.description}
    - Público Objetivo: ${wine.targetAudience}
    - Cualidades Especiales: ${wine.specialFeatures}
    ${wine.useAnalysisInCreative ? `\n- PERCEPCIÓN DIGITAL EXTERNA: ${wine.analysisResult}` : ''}

    TIPO DE IMAGEN: ${state.type}
    ${isMuyMinimal ? 'ESTILO ESPECÍFICO: SIMPLICIDAD EXTREMA. Bodegón "Muy minimal". Elimina cualquier elemento decorativo. Enfócate exclusivamente en la pureza de la iluminación, la composición geométrica impecable y la elegancia del vacío.' : ''}
    DETALLES ELEGIDOS: ${JSON.stringify(state.selections)}
    LUGAR: ${state.selections['donde'] || 'N/A'} ${state.locationImage ? '(Referencia visual subida)' : ''}
    CUÁNDO: ${state.timeContext || 'N/A'}
    ATMÓSFERA: ${state.contextText || 'N/A'}

    REGLAS DE SALIDA:
    - Genera 3 propuestas creativas en ESPAÑOL.
    - Cada propuesta debe ser un párrafo de 30-40 palabras.
    - Usa un lenguaje evocador, profesional y alineado con el perfil del vino (si es premium, lenguaje lujoso; si es social, lenguaje vibrante).
    - No repitas conceptos.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.OBJECT,
          properties: {
            concepts: {
              type: Type.ARRAY,
              items: { type: Type.STRING },
              description: "Tres conceptos visuales creativos."
            }
          },
          required: ["concepts"]
        }
      }
    });

    const data = JSON.parse(response.text || '{}');
    return data.concepts || [];
  } catch (error) {
    console.error("Error generating concepts:", error);
    return [
      "Una composición de alta gama enfocada en la silueta de la botella con iluminación de contorno dramática.",
      "Un entorno natural y orgánico que resalta la conexión de la etiqueta con su origen artesanal.",
      "Foco selectivo en el cristal y el color del vino, usando texturas ricas en el fondo para crear profundidad."
    ];
  }
};

export const generateFinalImage = async (
  wine: Wine, 
  concept: string, 
  ratio: string, 
  adjustment?: string,
  locationImage?: string
): Promise<string | null> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const wineBase64 = wine.image.split(',')[1];
  const wineMimeType = wine.image.split(';')[0].split(':')[1];

  const contents: any[] = [
    { inlineData: { data: wineBase64, mimeType: wineMimeType } }
  ];

  let prompt = `
    Genera una imagen publicitaria de alta calidad basada ESTRICTAMENTE en este concepto creativo:
    "${concept}"

    DETALLES TÉCNICOS:
    - Producto: ${wine.name}
    - Objetivo: Mantener la forma exacta de la botella y la legibilidad de la etiqueta de la imagen de referencia.
    - Estilo: Fotografía publicitaria profesional de alta gama.
  `;

  if (locationImage) {
    const locBase64 = locationImage.split(',')[1];
    const locMimeType = locationImage.split(';')[0].split(':')[1];
    contents.push({ inlineData: { data: locBase64, mimeType: locMimeType } });
    prompt += `\n\nREFERENCIA DE ENTORNO: La segunda imagen es una referencia arquitectónica/espacial. Evoca este mismo lugar en el fondo de la composición.`;
  }

  if (adjustment) {
    prompt += `\n\nAJUSTE DE POST-PRODUCCIÓN: "${adjustment}". Aplícalo respetando la composición original.`;
  }

  contents.push({ text: prompt });

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: contents },
      config: {
        imageConfig: {
          aspectRatio: ratio as any
        }
      }
    });

    // Correctly iterating through parts to find the image part as mandated for nano banana series models.
    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    return null;
  } catch (error) {
    console.error("Error generating final image:", error);
    throw error;
  }
};

import React, { useState, useEffect, useMemo, useRef } from 'react';
import { Wine, ImageType, FunnelState, AspectRatio, GalleryImage } from '../types';
import { generateVisualConcepts, generateFinalImage } from '../services/geminiService';

interface CreativeFunnelProps {
  wines: Wine[];
  onFinish: () => void;
  onSaveToGallery: (img: GalleryImage) => void;
  initialData?: {
    wine: Wine;
    concept: string;
    isAdjustment?: boolean;
  };
}

const CreativeFunnel: React.FC<CreativeFunnelProps> = ({ wines, onFinish, onSaveToGallery, initialData }) => {
  const [selectedWine, setSelectedWine] = useState<Wine>(initialData?.wine || wines[0]);
  const locationFileRef = useRef<HTMLInputElement>(null);

  const [state, setState] = useState<FunnelState>({
    type: null,
    step: initialData ? 6 : 1,
    selections: {},
    contextText: '',
    timeContext: '',
    locationImage: undefined,
    concepts: initialData ? [initialData.concept] : [],
    selectedConceptIndex: initialData ? 0 : null,
    editingConceptIndex: null,
    imageHistory: [],
    isLoading: false,
    error: null
  });

  const [ratio, setRatio] = useState<AspectRatio>('1:1');
  const [customAdjustment, setCustomAdjustment] = useState('');
  const [editValue, setEditValue] = useState('');
  const [showMoreActions, setShowMoreActions] = useState(false);

  // Active Context Analysis
  const isPremium = useMemo(() => {
    const text = (selectedWine.description + selectedWine.specialFeatures + selectedWine.name).toLowerCase();
    return /premium|exclusivo|reserva|limitada|lujo|alta gama|noble|sofisticado|añejo|crianza/.test(text);
  }, [selectedWine]);

  const isSocial = useMemo(() => {
    const text = (selectedWine.description + selectedWine.specialFeatures + selectedWine.targetAudience).toLowerCase();
    return /social|amigos|fiesta|diario|fresco|joven|compartir|picnic|terraza|informal/.test(text);
  }, [selectedWine]);

  const currentConceptText = useMemo(() => {
    if (state.selectedConceptIndex !== null && state.concepts[state.selectedConceptIndex]) {
      return state.concepts[state.selectedConceptIndex];
    }
    return state.concepts[0] || initialData?.concept || "Captura publicitaria profesional.";
  }, [state.selectedConceptIndex, state.concepts, initialData]);

  const seasonalSuggestions = useMemo(() => {
    const now = new Date();
    const month = now.getMonth();
    let suggestions: string[] = [];
    if (month === 11 || month <= 1) suggestions.push("Invierno");
    else if (month >= 2 && month <= 4) suggestions.push("Primavera");
    else if (month >= 5 && month <= 7) suggestions.push("Verano");
    else if (month >= 8 && month <= 10) suggestions.push("Otoño");
    if (month === 0) suggestions.push("San Valentín", "Escena acogedora");
    else if (month === 1) suggestions.push("San Valentín", "Luz de chimenea");
    else if (month >= 5 && month <= 7) suggestions.push("Atardecer en terraza", "Picnic");
    else if (month >= 8 && month <= 10) suggestions.push("Vendimia", "Luz dorada");
    return Array.from(new Set(suggestions)).slice(0, 4);
  }, []);

  useEffect(() => {
    if (initialData && !initialData.isAdjustment && state.step === 6 && state.imageHistory.length === 0 && !state.isLoading) {
      selectAndGenerate(0);
    }
  }, []);

  const setType = (type: ImageType) => {
    setState(prev => ({ ...prev, type, step: 2, selections: {} }));
    setShowMoreActions(false);
  };

  const handleSelection = (key: string, value: string) => {
    if (key === 'accion' && value === 'Más opciones') {
      setShowMoreActions(true);
      return;
    }
    setState(prev => ({ ...prev, selections: { ...prev.selections, [key]: value } }));
  };

  const handleLocationImageChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setState(prev => ({ ...prev, locationImage: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const startConceptGeneration = async () => {
    setState(prev => ({ ...prev, isLoading: true, error: null }));
    try {
      const concepts = await generateVisualConcepts(selectedWine, state);
      setState(prev => ({ 
        ...prev, 
        concepts: (Array.isArray(concepts) && concepts.length > 0) ? concepts : prev.concepts, 
        step: 5, 
        editingConceptIndex: null,
        isLoading: false
      }));
    } catch (e) {
      setState(prev => ({ ...prev, error: "No se pudieron generar conceptos.", isLoading: false }));
    }
  };

  const shouldSkipAtmosphere = () => {
    if (state.type !== ImageType.BODEGON) return false;
    if (state.selections['limpieza'] === 'Muy minimal') return true;
    if (state.selections['fondo'] === 'Neutro') return true;
    return false;
  };

  const nextStep = () => {
    if (state.step === 3) {
      if (shouldSkipAtmosphere()) {
        startConceptGeneration();
      } else {
        setState(prev => ({ ...prev, step: 4 }));
      }
    } else {
      setState(prev => ({ ...prev, step: prev.step + 1 }));
    }
  };

  const prevStep = () => setState(prev => {
    let targetStep = prev.step - 1;
    if (prev.step === 5) {
      if (shouldSkipAtmosphere()) targetStep = 3;
      else targetStep = 4;
    }
    if (prev.step === 6) targetStep = 5;
    return { ...prev, error: null, step: Math.max(1, targetStep) };
  });

  const selectAndGenerate = async (index: number, adjustment?: string) => {
    if (state.isLoading) return;
    setState(prev => ({ ...prev, isLoading: true, error: null, selectedConceptIndex: index, step: 6 }));
    try {
      const conceptToUse = state.concepts[index] || (index === 0 ? initialData?.concept : '') || '';
      const img = await generateFinalImage(selectedWine, String(conceptToUse), ratio, adjustment, state.locationImage);
      if (img) {
        const galleryItem: GalleryImage = {
          id: Date.now().toString(),
          url: img,
          concept: String(conceptToUse),
          wineName: selectedWine.name,
          timestamp: Date.now()
        };
        setState(prev => ({ 
          ...prev, 
          imageHistory: [img, ...prev.imageHistory],
          isLoading: false,
          error: null
        }));
        onSaveToGallery(galleryItem);
      } else {
        setState(prev => ({ ...prev, error: "La IA no devolvió ninguna imagen válida.", isLoading: false }));
      }
    } catch (e) {
      setState(prev => ({ ...prev, error: "Ocurrió un error inesperado durante la generación.", isLoading: false }));
    }
  };

  const startEdit = (idx: number, concept: string) => {
    setEditValue(concept);
    setState(prev => ({ ...prev, editingConceptIndex: idx }));
  };

  const handleSaveEdit = () => {
    if (state.editingConceptIndex !== null) {
      const newConcepts = [...state.concepts];
      newConcepts[state.editingConceptIndex] = editValue;
      setState(prev => ({ ...prev, concepts: newConcepts, editingConceptIndex: null }));
      setEditValue('');
    }
  };

  const handleAdjustment = (adj: string) => {
    if (state.isLoading) return;
    const index = state.selectedConceptIndex !== null ? state.selectedConceptIndex : 0;
    selectAndGenerate(index, adj);
  };

  const handleDownload = (imgUrl: string) => {
    const link = document.createElement('a');
    link.href = imgUrl;
    link.download = `kinglab_${selectedWine.name.toLowerCase().replace(/\s/g, '_')}_${Date.now()}.png`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  const btnSecondary = "py-4 rounded-xl border border-stone-300 bg-white text-stone-900 font-bold hover:border-black active:bg-stone-50 transition-all text-center px-4";
  const btnPrimary = "w-full py-5 bg-black text-white rounded-2xl font-bold shadow-xl shadow-black/10 active:scale-95 transition-all text-lg flex items-center justify-center gap-3";

  const renderStep1 = () => (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4">
      <div className="space-y-3">
        <label className="text-sm font-bold text-stone-800 uppercase tracking-wide">Producto Actual</label>
        <div className="flex items-center gap-4 bg-white p-4 rounded-2xl border border-stone-100 shadow-sm">
          <img src={selectedWine.image} alt={selectedWine.name} className="w-16 h-16 object-contain bg-stone-50 rounded-lg p-1" />
          <div>
            <h4 className="font-bold text-black">{selectedWine.name}</h4>
            <p className="text-xs text-stone-400 line-clamp-1">{selectedWine.description}</p>
          </div>
        </div>
      </div>
      <div className="space-y-4">
        <h2 className="text-2xl font-bold text-black font-serif">Tipo de Producción</h2>
        <div className="grid gap-3">
          {Object.values(ImageType).map(t => (
            <button key={t} onClick={() => setType(t)} className="w-full py-6 rounded-2xl border-2 border-stone-100 bg-white text-stone-900 font-bold text-left px-8 hover:border-black transition-all shadow-sm active:bg-stone-50 flex justify-between items-center group">
              {t}
              <svg xmlns="http://www.w3.org/2000/svg" width="20" height="20" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round" className="opacity-0 group-hover:opacity-100 transition-opacity"><path d="m9 18 6-6-6-6"/></svg>
            </button>
          ))}
        </div>
      </div>
    </div>
  );

  const renderStep2 = () => {
    const questions: Record<ImageType, any[]> = {
      [ImageType.BODEGON]: [
        { label: "Tipo de superficie", key: "superficie", options: ["Madera", "Piedra", "Mármol", "Minimalista"] },
        { label: "Nivel de limpieza visual", key: "limpieza", options: ["Muy minimal", "Con elementos"] },
        { label: "Apoyo", key: "apoyo", options: ["Ninguno", "Copas", "Uvas", "Corchos"] },
        { label: "Fondo", key: "fondo", options: ["Neutro", "Con contexto"] }
      ],
      [ImageType.EN_USO]: [
        { label: "Tipo de presencia", key: "mano", options: ["Mano sola", "Persona parcial", "Persona completa"] },
        { 
          label: "Valor de plano", 
          key: "valor_plano", 
          options: (selections: any) => {
            if (selections['mano'] === "Mano sola") return ["Macro", "Primer plano", "Plano medio"];
            if (selections['mano'] === "Persona parcial") return ["Primer plano", "Plano medio", "Plano americano"];
            if (selections['mano'] === "Persona completa") return ["Plano medio", "Plano general"];
            return [];
          }
        },
        { 
          label: "Acción", 
          key: "accion", 
          options: showMoreActions 
            ? ["Sostener", "Servir", "Brindar", "Beber", "Descorchar", "Girar la copa", "Oler"] 
            : ["Sostener", "Servir", "Brindar", "Beber", "Más opciones"] 
        },
        { label: "Intensidad Humana", key: "protagonismo", options: ["Baja", "Moderada", "Alta"] }
      ],
      [ImageType.MOMENTO_SOCIAL]: [
        { label: "Personas", key: "personas", options: ["2 personas", "3 personas", "Grupo"] },
        { label: "Situación", key: "situacion", options: ["Íntima", "Celebración", "Informal"] },
